import React, { useState } from 'react';
import { PrayerRequest } from '../types';

interface PrayersProps {
  prayers: PrayerRequest[];
  setPrayers: React.Dispatch<React.SetStateAction<PrayerRequest[]>>;
}

const PrayersView: React.FC<PrayersProps> = ({ prayers, setPrayers }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('Todos');

  const categories = ['Todos', ...Array.from(new Set(prayers.map(p => p.category)))];

  const filteredPrayers = prayers.filter(p => {
    const matchesSearch = p.title.toLowerCase().includes(searchTerm.toLowerCase()) || p.description.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesCategory = selectedCategory === 'Todos' || p.category === selectedCategory;
    return matchesSearch && matchesCategory;
  });

  const togglePrayed = (id: number) => {
    setPrayers(prev => {
      const updated = prev.map(p => p.id === id ? { ...p, isPrayed: !p.isPrayed } : p);
      // Check for completion of the 105 cycle
      if (updated.every(p => p.isPrayed)) {
        alert("Glória a Deus! Você completou o ciclo de 105 orações. Um novo ciclo se inicia!");
        return updated.map(p => ({ ...p, isPrayed: false }));
      }
      return updated;
    });
  };

  const toggleFavorite = (id: number) => {
    setPrayers(prev => prev.map(p => p.id === id ? { ...p, isFavorite: !p.isFavorite } : p));
  };

  const handleNoteChange = (id: number, note: string) => {
    setPrayers(prev => prev.map(p => p.id === id ? { ...p, personalNotes: note } : p));
  };

  const handleShare = (p: PrayerRequest) => {
    const text = `Motivo de Oração Despertar de Débora:\n\n*${p.title}*\n${p.description}\n\n📖 _${p.verse}_`;
    const url = `https://wa.me/?text=${encodeURIComponent(text)}`;
    window.open(url, '_blank');
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col gap-4">
        <h2 className="serif-font text-2xl font-bold text-brand-deepPink">Pedidos de Oração</h2>

        {/* Search & Filter */}
        <div className="space-y-3">
          <div className="relative">
            <i className="fa-solid fa-search absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"></i>
            <input 
              type="text" 
              placeholder="Buscar pedido..." 
              className="w-full bg-white border border-brand-pink rounded-full py-3 pl-11 pr-4 text-sm focus:outline-none focus:ring-2 focus:ring-brand-rose/20 transition-shadow"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex gap-2 overflow-x-auto no-scrollbar pb-2">
            {categories.map(cat => (
              <button
                key={cat}
                onClick={() => setSelectedCategory(cat)}
                className={`px-4 py-1.5 rounded-full text-xs font-medium whitespace-nowrap transition-colors ${selectedCategory === cat ? 'bg-brand-rose text-white' : 'bg-white text-brand-rose border border-brand-pink'}`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>
      </div>

      <div className="space-y-4">
        {filteredPrayers.length > 0 ? (
          filteredPrayers.map(p => (
            <div key={p.id} className={`bg-white rounded-2xl p-5 border shadow-sm transition-all ${p.isPrayed ? 'opacity-70 grayscale-[0.5]' : 'border-brand-pink'}`}>
              <div className="flex items-start justify-between mb-3">
                <div className="space-y-1">
                  <span className="text-[10px] font-bold text-brand-rose uppercase bg-brand-pink px-2 py-0.5 rounded-full">{p.category}</span>
                  <h3 className="font-bold text-brand-deepPink text-lg">{p.title}</h3>
                </div>
                <div className="flex gap-3">
                  <button onClick={() => toggleFavorite(p.id)} className={`transition-colors ${p.isFavorite ? 'text-brand-rose' : 'text-gray-300'}`}>
                    <i className={`fa-${p.isFavorite ? 'solid' : 'regular'} fa-star`}></i>
                  </button>
                  <button onClick={() => handleShare(p)} className="text-gray-300 hover:text-brand-rose">
                    <i className="fa-solid fa-share-nodes"></i>
                  </button>
                </div>
              </div>

              <p className="text-sm text-gray-600 mb-4">{p.description}</p>

              <div className="bg-brand-cream border-l-4 border-brand-rose p-3 rounded-r-xl mb-4 italic text-sm text-gray-700">
                "{p.verse}"
              </div>

              <div className="space-y-4">
                <textarea 
                  placeholder="Sua oração pessoal (privado)..."
                  className="w-full bg-gray-50 border border-gray-100 rounded-xl p-3 text-xs focus:outline-none h-20 resize-none"
                  value={p.personalNotes || ''}
                  onChange={(e) => handleNoteChange(p.id, e.target.value)}
                />

                <button 
                  onClick={() => togglePrayed(p.id)}
                  className={`w-full py-3 rounded-full text-sm font-bold flex items-center justify-center gap-2 transition-all ${p.isPrayed ? 'bg-gray-100 text-gray-400' : 'gradient-brand text-white shadow-md active:scale-[0.98]'}`}
                >
                  <i className={`fa-solid ${p.isPrayed ? 'fa-check-circle' : 'fa-circle-check'}`}></i>
                  {p.isPrayed ? 'Orado' : 'Marcar como Orado'}
                </button>
              </div>
            </div>
          ))
        ) : (
          <div className="text-center py-12 text-gray-400">
            <i className="fa-solid fa-feather-pointed text-4xl mb-3 block"></i>
            <p className="text-sm">Nenhum pedido encontrado.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default PrayersView;

import React, { useState } from 'react';
import { ChildOfPrayer } from '../types';

interface FilhosProps {
  children: ChildOfPrayer[];
  setChildren: React.Dispatch<React.SetStateAction<ChildOfPrayer[]>>;
}

const FilhosView: React.FC<FilhosProps> = ({ children, setChildren }) => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [selectedChild, setSelectedChild] = useState<ChildOfPrayer | null>(null);

  const calculateAge = (birthDate: string) => {
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) age--;
    return age;
  };

  const getSelo = (type: string) => {
    switch (type) {
      case 'geracao_compromisso': return 'bg-yellow-100 text-yellow-700 border-yellow-200';
      case 'biologico': return 'bg-blue-100 text-blue-700 border-blue-200';
      case 'espiritual': return 'bg-purple-100 text-purple-700 border-purple-200';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  const getLabel = (type: string) => {
    switch (type) {
      case 'geracao_compromisso': return 'Geração Compromisso';
      case 'biologico': return 'Filho Biológico';
      case 'espiritual': return 'Filho Espiritual';
      case 'adotivo': return 'Filho Adotivo';
      default: return type;
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="serif-font text-2xl font-bold text-brand-deepPink">Filhos de Oração</h2>
        <button 
          onClick={() => setShowAddModal(true)}
          className="bg-brand-rose text-white w-10 h-10 rounded-full flex items-center justify-center shadow-lg active:scale-90 transition-transform"
        >
          <i className="fa-solid fa-plus"></i>
        </button>
      </div>

      <p className="text-sm text-gray-500 leading-relaxed bg-brand-pink/30 p-4 rounded-2xl border border-brand-pink italic">
        "Aqui você acompanha os filhos que Deus confiou a você para interceder, crendo que, por meio da oração, Ele está formando uma Geração Compromisso."
      </p>

      {/* Children List */}
      <div className="grid grid-cols-1 gap-4 pb-12">
        {children.length > 0 ? (
          children.map(child => (
            <div 
              key={child.id} 
              onClick={() => setSelectedChild(child)}
              className="bg-white rounded-3xl p-4 border border-brand-pink shadow-sm flex gap-4 cursor-pointer hover:shadow-md transition-shadow active:scale-[0.99]"
            >
              <div className="w-20 h-20 rounded-2xl overflow-hidden flex-shrink-0 bg-brand-lavender">
                <img 
                    src={child.photo || `https://picsum.photos/seed/${child.id}/200`} 
                    alt={child.name} 
                    className="w-full h-full object-cover" 
                />
              </div>
              <div className="flex-1 space-y-2">
                <div className="flex justify-between items-start">
                  <h3 className="font-bold text-brand-deepPink">{child.name}</h3>
                  <span className={`text-[9px] uppercase font-bold px-2 py-0.5 rounded-full border ${getSelo(child.type)}`}>
                    {getLabel(child.type)}
                  </span>
