import React, { useState, useEffect, useCallback } from 'react';
import { UserStats } from '../types';

interface TimerProps {
  stats: UserStats;
  setStats: React.Dispatch<React.SetStateAction<UserStats>>;
  onFinish: () => void;
}

const TimerView: React.FC<TimerProps> = ({ stats, setStats, onFinish }) => {
  const [seconds, setSeconds] = useState(15 * 60); // 15 minutes
  const [isActive, setIsActive] = useState(false);

  useEffect(() => {
    let interval: any = null;
    if (isActive && seconds > 0) {
      interval = setInterval(() => {
        setSeconds(s => s - 1);
      }, 1000);
    } else if (seconds === 0) {
      handleComplete();
    }
    return () => clearInterval(interval);
  }, [isActive, seconds]);

  const handleComplete = useCallback(() => {
    setIsActive(false);
    setStats(prev => ({
      ...prev,
      totalMinutes: prev.totalMinutes + 15,
      hasDailyTrophy: true
    }));
    alert("Parabéns! Você concluiu seus 15 minutos de oração diária. Troféu liberado!");
    onFinish();
  }, [setStats, onFinish]);

  const formatTime = (totalSeconds: number) => {
    const mins = Math.floor(totalSeconds / 60);
    const secs = totalSeconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const progress = ((15 * 60 - seconds) / (15 * 60)) * 100;

  return (
    <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-12 animate-fadeIn">
      <div className="text-center space-y-2">
        <h2 className="serif-font text-3xl font-bold text-brand-deepPink">Momento com Deus</h2>
        <p className="text-sm text-gray-500">15 minutos para transformar vidas através da intercessão.</p>
      </div>

      {/* Timer Circle */}
      <div className="relative w-64 h-64 flex items-center justify-center">
        <svg className="absolute w-full h-full -rotate-90">
          <circle 
            cx="128" cy="128" r="120" 
            className="stroke-brand-lavender fill-none" 
            strokeWidth="8" 
          />
          <circle 
            cx="128" cy="128" r="120" 
            className="stroke-brand-rose fill-none transition-all duration-1000" 
            strokeWidth="8" 
            strokeDasharray={754} 
            strokeDashoffset={754 - (754 * progress) / 100}
            strokeLinecap="round"
          />
        </svg>
        <div className="text-center z-10">
          <p className="text-5xl font-bold text-brand-deepPink font-mono">{formatTime(seconds)}</p>
          <p className="text-[10px] uppercase font-bold text-brand-rose mt-1">Tempo Restante</p>
        </div>
      </div>

      <div className="flex gap-4 w-full">
        <button 
          onClick={() => setIsActive(!isActive)}
          className={`flex-1 py-4 rounded-full text-white font-bold shadow-lg transition-all active:scale-95 flex items-center justify-center gap-2 ${isActive ? 'bg-orange-400' : 'gradient-brand'}`}
        >
          <i className={`fa-solid ${isActive ? 'fa-pause' : 'fa-play'}`}></i>
          {isActive ? 'Pausar' : 'Iniciar Oração'}
        </button>
        {seconds < 15 * 60 && (
          <button 
            onClick={() => {
              if (window.confirm("Deseja encerrar agora? O tempo não será registrado.")) {
                onFinish();
              }
            }}
            className="px-6 py-4 rounded-full bg-gray-100 text-gray-500 font-bold active:scale-95"
          >
            Sair
          </button>
        )}
      </div>

      <p className="text-xs text-gray-400 italic text-center max-w-xs">
        "Vocês, porém, amados, edifiquem-se na vossa santíssima fé e orem no Espírito Santo." - Judas 1:20
      </p>
    </div>
  );
};

export default TimerView;

