              <div className="flex-1 space-y-2">
                <div className="flex justify-between items-start">
                  <h3 className="font-bold text-brand-deepPink">{child.name}</h3>
                  <span className={`text-[9px] uppercase font-bold px-2 py-0.5 rounded-full border ${getSelo(child.type)}`}>
                    {getLabel(child.type)}
                  </span>
                </div>
                <p className="text-xs text-gray-500">
                  <i className="fa-solid fa-cake-candles mr-1"></i> {calculateAge(child.birthDate)} anos • 
