                <div className="flex items-center justify-around bg-brand-lavender/30 p-5 rounded-3xl border border-brand-pink/30">
                  <div className="text-center">
                    <p className="text-2xl font-black text-brand-deepPink">{selectedChild.prayerMinutes}</p>
                    <p className="text-[9px] uppercase font-black text-gray-400 tracking-tighter">Minutos</p>
                  </div>
                  <div className="h-10 w-[1px] bg-brand-pink"></div>
                  <div className="text-center">
                    <p className="text-2xl font-black text-brand-deepPink">
                      {selectedChild.individualRequests.filter(r => r.status === 'respondido').length}
                    </p>
                    <p className="text-[9px] uppercase font-black text-gray-400 tracking-tighter">Vitórias</p>
                  </div>
                  <div className="h-10 w-[1px] bg-brand-pink"></div>
                  <div className="text-center">
                    <p className="text-2xl font-black text-brand-deepPink">
                      {selectedChild.individualRequests.length}
                    </p>
                    <p className="text-[9px] uppercase font-black text-gray-400 tracking-tighter">Total</p>
                  </div>
                </div>
              </section>

              <button className="w-full gradient-brand py-5 rounded-full text-white font-black uppercase tracking-widest shadow-xl shadow-brand-rose/30 active:scale-[0.97] transition-all flex items-center justify-center gap-3">
                <i className="fa-solid fa-hands-praying"></i>
                Orar por {selectedChild.name.split(' ')[0]}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Add Request Modal */}
      {showAddRequestModal && (
        <div className="fixed inset-0 bg-black/70 z-[70] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-sm rounded-[2rem] p-8 space-y-6 animate-fadeIn shadow-2xl">
            <div className="text-center">
              <h3 className="serif-font text-2xl font-bold text-brand-deepPink">Nova Intercessão</h3>
              <p className="text-xs text-gray-400 mt-1">Coloque o clamor específico no altar do Senhor.</p>
            </div>

            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-brand-rose uppercase ml-2 tracking-widest">Qual o motivo?</label>
                <textarea 
                  placeholder="Ex: Sabedoria nos estudos, proteção no caminho..." 
                  value={newReqText}
                  onChange={(e) => setNewReqText(e.target.value)}
                  className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-pink h-28 resize-none shadow-inner" 
                />
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black text-brand-rose uppercase ml-2 tracking-widest">Versículo da Promessa</label>
                <input 
                  type="text" 
                  placeholder="Ex: Filipenses 4:13" 
                  value={newReqVerse}
                  onChange={(e) => setNewReqVerse(e.target.value)}
                  className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-pink shadow-inner" 
                />
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black text-brand-rose uppercase ml-2 tracking-widest">Status Inicial</label>
                <div className="flex gap-3">
                  <button 
                    onClick={() => setNewReqStatus('em_oracao')}
                    className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase border-2 transition-all ${newReqStatus === 'em_oracao' ? 'bg-orange-50 border-orange-200 text-orange-700 shadow-sm' : 'bg-white border-gray-100 text-gray-400'}`}
                  >
                    Em Oração
                  </button>
                  <button 
                    onClick={() => setNewReqStatus('respondido')}
                    className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase border-2 transition-all ${newReqStatus === 'respondido' ? 'bg-green-50 border-green-200 text-green-700 shadow-sm' : 'bg-white border-gray-100 text-gray-400'}`}
                  >
                    Respondido
                  </button>
                </div>
              </div>
            </div>

            <div className="flex gap-4 pt-2">
              <button 
                onClick={() => { setShowAddRequestModal(false); resetRequestForm(); }} 
                className="flex-1 py-4 bg-gray-100 text-gray-500 rounded-full text-xs font-black uppercase tracking-widest"
              >
                Cancelar
              </button>
              <button 
                onClick={handleAddRequest} 
                className="flex-1 py-4 gradient-brand text-white rounded-full text-xs font-black uppercase tracking-widest shadow-lg shadow-brand-rose/20 active:scale-95"
              >
                Adicionar
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Add Child Modal */}
      {showAddModal && (
        <div className="fixed inset-0 bg-black/70 z-[60] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 space-y-6 animate-fadeIn overflow-y-auto max-h-[90vh] no-scrollbar shadow-2xl">
            <div className="text-center">
              <h3 className="serif-font text-2xl font-bold text-brand-deepPink">Novo Filho de Oração</h3>
              <p className="text-xs text-gray-400 mt-1">Inicie uma cobertura espiritual sobre um jovem.</p>
            </div>

            <div className="flex flex-col items-center space-y-3">
              <div 
                className="relative group cursor-pointer"
                onClick={() => fileInputRef.current?.click()}
              >
                <div className="w-28 h-28 rounded-[2rem] bg-brand-pink border-2 border-dashed border-brand-rose flex items-center justify-center overflow-hidden shadow-inner group-hover:border-solid transition-all">
                  {newPhoto ? (
                    <img src={newPhoto} className="w-full h-full object-cover" alt="Preview" />
                  ) : (
                    <div className="text-center text-brand-rose">
                      <i className="fa-solid fa-camera-retro text-2xl mb-1"></i>
                      <p className="text-[8px] font-black mt-1 uppercase tracking-tighter">Escolher Foto</p>
                    </div>
                  )}
                </div>
                {newPhoto && (
                  <button 
                    onClick={(e) => { e.stopPropagation(); setNewPhoto(undefined); }}
                    className="absolute -top-2 -right-2 w-7 h-7 bg-white border border-brand-pink text-brand-rose rounded-full flex items-center justify-center shadow-lg active:scale-90"
                  >
                    <i className="fa-solid fa-xmark text-xs"></i>
                  </button>
                )}
                <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity rounded-[2rem]">
                  <i className="fa-solid fa-camera text-white"></i>
                </div>
              </div>
              <p className="text-[9px] text-gray-400 font-bold uppercase tracking-widest">Câmera ou Galeria</p>
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handlePhotoUpload} 
                className="hidden" 
                accept="image/*"
              />
            </div>

            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-brand-rose uppercase ml-2 tracking-widest">Nome Completo</label>
                <input 
                  type="text" 
                  placeholder="Nome do jovem" 
                  value={newName}
                  onChange={(e) => setNewName(e.target.value)}
                  className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-pink shadow-inner" 
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-brand-rose uppercase ml-2 tracking-widest">Vínculo</label>
                  <select 
                    value={newType}
                    onChange={(e) => setNewType(e.target.value as any)}
                    className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-pink shadow-inner appearance-none bg-[url('data:image/svg+xml;charset=US-ASCII,%3Csvg%20xmlns%3D%22http%3A//www.w3.org/2000/svg%22%20width%3D%22292.4%22%20height%3D%22292.4%22%3E%3Cpath%20fill%3D%22%23E91E63%22%20d%3D%22M287%2069.4a17.6%2017.6%200%200%200-13-5.4H18.4c-5%200-9.3%201.8-12.9%205.4A17.6%2017.6%200%200%200%200%2082.2c0%205%201.8%209.3%205.4%2012.9l128%20127.9c3.6%203.6%207.8%205.4%2012.8%205.4s9.2-1.8%2012.8-5.4L287%2095c3.5-3.5%205.4-7.8%205.4-12.8%200-5-1.9-9.2-5.5-12.8z%22/%3E%3C/svg%3E')] bg-[length:12px] bg-[right_1rem_center] bg-no-repeat"
                  >
                    <option value="biologico">Biológico</option>
                    <option value="espiritual">Espiritual</option>
                    <option value="adotivo">Adotivo</option>
                    <option value="geracao_compromisso">Geração Compromisso</option>
                  </select>
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-brand-rose uppercase ml-2 tracking-widest">Nascimento</label>
                  <input 
                    type="date" 
                    value={newBirthDate}
                    onChange={(e) => setNewBirthDate(e.target.value)}
                    className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-pink shadow-inner" 
                  />
                </div>
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black text-brand-rose uppercase ml-2 tracking-widest">Cidade/Estado</label>
                <input 
                  type="text" 
                  placeholder="Ex: Curitiba, PR" 
                  value={newLocation}
                  onChange={(e) => setNewLocation(e.target.value)}
                  className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-pink shadow-inner" 
                />
              </div>
            </div>

            <div className="flex gap-4 pt-4">
              <button 
                onClick={() => { setShowAddModal(false); resetChildForm(); }} 
                className="flex-1 py-4 bg-gray-100 text-gray-500 rounded-full text-xs font-black uppercase tracking-widest transition-all"
              >
                Cancelar
              </button>
              <button 
                onClick={handleSaveChild} 
                className="flex-1 py-4 gradient-brand text-white rounded-full text-xs font-black uppercase tracking-widest shadow-xl shadow-brand-rose/20 active:scale-95 transition-all"
              >
                Salvar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default FilhosView;

import React, { useState, useRef } from 'react';
import { ChildOfPrayer, ChildPrayerRequest } from '../types';

interface FilhosProps {
  children: ChildOfPrayer[];
  setChildren: React.Dispatch<React.SetStateAction<ChildOfPrayer[]>>;
}

const FilhosView: React.FC<FilhosProps> = ({ children, setChildren }) => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [showAddRequestModal, setShowAddRequestModal] = useState(false);
  const [selectedChild, setSelectedChild] = useState<ChildOfPrayer | null>(null);

  // Form State for Child
  const [newName, setNewName] = useState('');
  const [newType, setNewType] = useState<ChildOfPrayer['type']>('biologico');
  const [newBirthDate, setNewBirthDate] = useState('');
  const [newLocation, setNewLocation] = useState('');
  const [newPhoto, setNewPhoto] = useState<string | undefined>(undefined);

  // Form State for Request
  const [newReqText, setNewReqText] = useState('');
  const [newReqVerse, setNewReqVerse] = useState('');
  const [newReqStatus, setNewReqStatus] = useState<'em_oracao' | 'respondido'>('em_oracao');

  const fileInputRef = useRef<HTMLInputElement>(null);

  const calculateAge = (birthDate: string) => {
    if (!birthDate) return 0;
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) age--;
    return age;
  };

  const getSelo = (type: string) => {
    switch (type) {
      case 'geracao_compromisso': return 'bg-yellow-100 text-yellow-700 border-yellow-200';
      case 'biologico': return 'bg-blue-100 text-blue-700 border-blue-200';
      case 'espiritual': return 'bg-purple-100 text-purple-700 border-purple-200';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  const getLabel = (type: string) => {
    switch (type) {
      case 'geracao_compromisso': return 'Geração Compromisso';
      case 'biologico': return 'Filho Biológico';
      case 'espiritual': return 'Filho Espiritual';
      case 'adotivo': return 'Filho Adotivo';
      default: return type;
    }
  };

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setNewPhoto(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSaveChild = () => {
    if (!newName || !newBirthDate) {
      alert("Por favor, preencha o nome e a data de nascimento.");
      return;
    }

    const newChild: ChildOfPrayer = {
      id: Date.now().toString(),
      name: newName,
      type: newType,
      birthDate: newBirthDate,
      location: newLocation || 'Não informada',
      photo: newPhoto,
      notes: '',
      startDate: new Date().toISOString(),
      prayerMinutes: 0,
      individualRequests: []
    };

    setChildren(prev => [newChild, ...prev]);
    resetChildForm();
    setShowAddModal(false);
  };

  const handleAddRequest = () => {
    if (!selectedChild || !newReqText) {
      alert("Por favor, informe o motivo da oração.");
      return;
    }

    const newReq: ChildPrayerRequest = {
      id: Date.now().toString(),
      request: newReqText,
      verse: newReqVerse,
      status: newReqStatus,
    };

    setChildren(prev => {
      const updated = prev.map(child => {
        if (child.id === selectedChild.id) {
          const updatedChild = {
            ...child,
            individualRequests: [...child.individualRequests, newReq]
          };
          // Sync detail view immediately
          setSelectedChild(updatedChild);
          return updatedChild;
        }
        return child;
      });
      return updated;
    });

    resetRequestForm();
    setShowAddRequestModal(false);
  };

  const toggleRequestStatus = (requestId: string) => {
    if (!selectedChild) return;

    setChildren(prev => {
      const updated = prev.map(child => {
        if (child.id === selectedChild.id) {
          const updatedRequests = child.individualRequests.map(req => {
            if (req.id === requestId) {
              return { ...req, status: req.status === 'em_oracao' ? 'respondido' : 'em_oracao' as any };
            }
            return req;
          });
          const updatedChild = { ...child, individualRequests: updatedRequests };
          setSelectedChild(updatedChild);
          return updatedChild;
        }
        return child;
      });
      return updated;
    });
  };

  const resetChildForm = () => {
    setNewName('');
    setNewType('biologico');
    setNewBirthDate('');
    setNewLocation('');
    setNewPhoto(undefined);
  };

  const resetRequestForm = () => {
    setNewReqText('');
    setNewReqVerse('');
    setNewReqStatus('em_oracao');
  };

  return (
    <div className="space-y-6 pb-20">
      <div className="flex items-center justify-between">
        <h2 className="serif-font text-2xl font-bold text-brand-deepPink">Filhos de Oração</h2>
        <button 
          onClick={() => setShowAddModal(true)}
          className="bg-brand-rose text-white w-10 h-10 rounded-full flex items-center justify-center shadow-lg active:scale-90 transition-transform"
        >
          <i className="fa-solid fa-plus"></i>
        </button>
      </div>

      <p className="text-sm text-gray-500 leading-relaxed bg-brand-pink/30 p-4 rounded-2xl border border-brand-pink italic">
        "Aqui você acompanha os filhos que Deus confiou a você para interceder, crendo que, por meio da oração, Ele está formando uma Geração Compromisso."
      </p>

      {/* Children List */}
      <div className="grid grid-cols-1 gap-4">
        {children.length > 0 ? (
          children.map(child => (
            <div 
              key={child.id} 
              onClick={() => setSelectedChild(child)}
              className="bg-white rounded-3xl p-4 border border-brand-pink shadow-sm flex gap-4 cursor-pointer hover:shadow-md transition-shadow active:scale-[0.99]"
            >
              <div className="w-20 h-20 rounded-2xl overflow-hidden flex-shrink-0 bg-brand-lavender border border-brand-pink/20">
                <img 
                    src={child.photo || `https://picsum.photos/seed/${child.id}/200`} 
                    alt={child.name} 
                    className="w-full h-full object-cover" 
                />
              </div>
              <div className="flex-1 space-y-2">
                <div className="flex justify-between items-start">
                  <h3 className="font-bold text-brand-deepPink">{child.name}</h3>
                  <span className={`text-[9px] uppercase font-bold px-2 py-0.5 rounded-full border ${getSelo(child.type)}`}>
                    {getLabel(child.type)}
                  </span>
                </div>
                <p className="text-xs text-gray-500">
                  <i className="fa-solid fa-cake-candles mr-1 opacity-60"></i> {calculateAge(child.birthDate)} anos • 
                  <i className="fa-solid fa-location-dot ml-2 mr-1 opacity-60"></i> {child.location}
                </p>
                <div className="flex items-center justify-between pt-1">
                  <div className="flex items-center gap-2">
                    <i className="fa-solid fa-hands-praying text-brand-rose text-xs"></i>
                    <span className="text-[10px] text-gray-400 font-medium">
                      {child.individualRequests.filter(r => r.status === 'em_oracao').length} ativos
                    </span>
                  </div>
                  <div className="flex items-center gap-1.5 bg-brand-pink/50 px-2 py-0.5 rounded-full">
                    <i className="fa-solid fa-clock text-brand-rose text-[10px]"></i>
                    <span className="text-[10px] text-brand-deepPink font-black">{child.prayerMinutes}m</span>
                  </div>
                </div>
              </div>
            </div>
          ))
        ) : (
          <div className="text-center py-24 text-gray-400">
            <i className="fa-solid fa-users-rays text-6xl mb-6 opacity-20"></i>
            <p className="text-sm font-medium">Sua lista de intercessão está vazia.</p>
            <p className="text-xs mt-1">Toque no + para começar a cadastrar seus filhos.</p>
          </div>
        )}
      </div>

      {/* Detail Modal */}
      {selectedChild && (
        <div className="fixed inset-0 bg-black/60 z-[60] flex items-end sm:items-center justify-center p-0 sm:p-4">
          <div className="bg-white w-full max-w-lg rounded-t-[2.5rem] sm:rounded-3xl p-6 animate-slideUp overflow-y-auto max-h-[95vh] no-scrollbar">
            <div className="w-12 h-1.5 bg-gray-200 rounded-full mx-auto mb-6 sm:hidden"></div>

            <div className="flex justify-between items-start mb-6">
              <div className="flex items-center gap-4">
                <div className="w-20 h-20 rounded-2xl overflow-hidden bg-brand-lavender border-2 border-brand-pink shadow-sm">
                  <img src={selectedChild.photo || `https://picsum.photos/seed/${selectedChild.id}/200`} className="w-full h-full object-cover" alt={selectedChild.name} />
                </div>
                <div className="space-y-1">
                  <h3 className="text-xl font-bold text-brand-deepPink leading-tight">{selectedChild.name}</h3>
                  <p className="text-xs font-bold text-brand-rose uppercase tracking-wider">{getLabel(selectedChild.type)}</p>
                </div>
              </div>
              <button onClick={() => setSelectedChild(null)} className="w-10 h-10 rounded-full bg-gray-100 flex items-center justify-center active:bg-gray-200 transition-colors">
                <i className="fa-solid fa-xmark text-gray-500"></i>
              </button>
            </div>

            <div className="space-y-8">
              <section>
                <div className="flex items-center justify-between mb-4">
                  <h4 className="text-xs font-black uppercase text-brand-deepPink tracking-widest flex items-center gap-2">
                    <i className="fa-solid fa-heart-pulse text-brand-rose"></i>
                    Pedidos de Oração
                  </h4>
                  <button 
                    onClick={() => setShowAddRequestModal(true)}
                    className="text-[10px] font-black uppercase text-brand-rose bg-brand-pink px-4 py-1.5 rounded-full hover:bg-brand-rose hover:text-white transition-all active:scale-95"
                  >
                    + Novo Pedido
                  </button>
                </div>

                <div className="space-y-3">
                  {selectedChild.individualRequests.length > 0 ? (
                    selectedChild.individualRequests.map(req => (
                      <div key={req.id} className="bg-brand-cream/50 p-4 rounded-2xl border border-brand-pink/40 space-y-3 shadow-sm transition-all">
                        <div className="flex items-start justify-between gap-4">
                          <span className="text-sm font-bold text-gray-800 flex-1 leading-snug">{req.request}</span>
                          <button 
                            onClick={() => toggleRequestStatus(req.id)}
                            className={`text-[8px] font-black uppercase px-2 py-1 rounded-full whitespace-nowrap transition-all active:scale-90 ${req.status === 'em_oracao' ? 'bg-orange-100 text-orange-700' : 'bg-green-100 text-green-700'}`}
                          >
                            {req.status === 'em_oracao' ? 'Em Oração' : 'Respondido'}
                          </button>
                        </div>
                        {req.verse && (
                          <p className="text-[11px] text-brand-rose/80 font-medium italic bg-white/60 p-2 rounded-lg border border-brand-pink/20">
                            <i className="fa-solid fa-book-bible mr-1.5"></i> "{req.verse}"
                          </p>
                        )}
                      </div>
                    ))
                  ) : (
                    <div className="text-center py-8 bg-gray-50 rounded-2xl border-2 border-dashed border-gray-100">
                      <p className="text-[11px] text-gray-400 font-medium italic">Nenhum pedido específico cadastrado ainda.</p>
                    </div>
                  )}
                </div>
              </section>

              <section>
                <h4 className="text-xs font-black uppercase text-brand-deepPink tracking-widest mb-4 flex items-center gap-2">
                  <i className="fa-solid fa-chart-pie text-brand-rose"></i>
                  Histórico Espiritual
                </h4>
                <div className="flex items-center justify-around bg-brand-lavender/30 p-5 rounded-3xl border border-brand-pink/30">
                  <div className="text-center">
                    <p className="text-2xl font-black text-brand-deepPink">{selectedChild.prayerMinutes}</p>
                    <p className="text-[9px] uppercase font-black text-gray-400 tracking-tighter">Minutos</p>
                  </div>
                  <div className="h-10 w-[1px] bg-brand-pink"></div>
                  <div className="text-center">
                    <p className="text-2xl font-black text-brand-deepPink">
                      {selectedChild.individualRequests.filter(r => r.status === 'respondido').length}
                    </p>
                    <p className="text-[9px] uppercase font-black text-gray-400 tracking-tighter">Vitórias</p>
                  </div>
                  <div className="h-10 w-[1px] bg-brand-pink"></div>
                  <div className="text-center">
                    <p className="text-2xl font-black text-brand-deepPink">
                      {selectedChild.individualRequests.length}
                    </p>
                    <p className="text-[9px] uppercase font-black text-gray-400 tracking-tighter">Total</p>
                  </div>
                </div>
              </section>

