interface ProfileProps {
  profile: UserProfile;
  stats: UserStats;
}

const ProfileView: React.FC<ProfileProps> = ({ profile, stats }) => {
  const [notifEnabled, setNotifEnabled] = useState(false);

  useEffect(() => {
    if ("Notification" in window) {
      setNotifEnabled(Notification.permission === "granted");
    }
  }, []);

  const handleToggleNotifications = async () => {
    if (!("Notification" in window)) {
      alert("Seu navegador não suporta notificações.");
      return;
    }

    if (Notification.permission === "default") {
      const permission = await Notification.requestPermission();
      setNotifEnabled(permission === "granted");
    } else if (Notification.permission === "denied") {
      alert("As notificações estão bloqueadas nas configurações do seu navegador.");
    } else {
      // Permission already granted, just visual toggle
      setNotifEnabled(!notifEnabled);
    }
  };

  return (
    <div className="space-y-8 animate-fadeIn pb-24">
      {/* Profile Header */}
      <div className="flex flex-col items-center text-center space-y-4">
