import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import HomeView from './views/Home';
import PrayersView from './views/Prayers';
import FilhosView from './views/Filhos';
import CommunityView from './views/Community';
import TimerView from './views/Timer';
import ProfileView from './views/Profile';
import { PrayerRequest, ChildOfPrayer, UserStats, UserProfile } from './types';
import { INITIAL_PRAYER_REQUESTS, INSTITUTIONAL } from './constants';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [isLoading, setIsLoading] = useState(true);
  const [prayers, setPrayers] = useState<PrayerRequest[]>(INITIAL_PRAYER_REQUESTS);
  const [children, setChildren] = useState<ChildOfPrayer[]>([]);
  const [stats, setStats] = useState<UserStats>({
    streak: 3,
    totalMinutes: 245,
    totalDays: 12,
    hasDailyTrophy: false
  });
  const [profile] = useState<UserProfile>({
    name: "Ana Cláudia",
    birthDate: "1985-05-20",
    church: "Igreja Batista Aliança",
    participationTime: "2 anos",
    groupName: "Déboras de Curitiba"
  });

  // Splash Screen Effect
  useEffect(() => {
    const timer = setTimeout(() => setIsLoading(false), 2000);
    return () => clearTimeout(timer);
  }, []);

  // Example child data
  useEffect(() => {
    const threeDaysAgo = new Date();
    threeDaysAgo.setDate(threeDaysAgo.getDate() - 4);

    setChildren([
      {
        id: '1',
        name: 'Mateus Oliveira',
        type: 'biologico',
        birthDate: '2010-08-15',
        location: 'Curitiba, PR',
        photo: 'https://images.unsplash.com/photo-1519238263530-99bdd11df2ea?w=400&h=400&fit=crop',
        notes: 'Mateus está na fase dos desafios da adolescência.',
        startDate: '2023-01-01',
        prayerMinutes: 120,
        individualRequests: [
          { 
            id: 'r1', 
            request: 'Sabedoria nos estudos', 
            status: 'em_oracao', 
            createdAt: threeDaysAgo.toISOString() 
          },
          { 
            id: 'r2', 
            request: 'Proteção contra más amizades', 
            status: 'em_oracao', 
            createdAt: new Date().toISOString() 
          }
        ]
      }
    ]);
  }, []);

  // Notification Logic
  useEffect(() => {
    const checkPendingPrayers = () => {
      if (!("Notification" in window)) return;
      if (Notification.permission !== "granted") return;

      const now = new Date();
      children.forEach(child => {
        const staleRequest = child.individualRequests.find(req => {
          if (req.status !== 'em_oracao') return false;
          const created = new Date(req.createdAt);
          const diffDays = (now.getTime() - created.getTime()) / (1000 * 3600 * 24);
          return diffDays >= 3;
        });

        if (staleRequest) {
          new Notification("Lembrete de Intercessão", {
            body: `Débora, ${child.name.split(' ')[0]} ainda precisa de oração por: "${staleRequest.request}"`,
            icon: child.photo || "/favicon.ico"
          });
        }
      });
    };

    const timer = setTimeout(checkPendingPrayers, 3000);
    return () => clearTimeout(timer);
  }, [children]);

  if (isLoading) {
    return (
      <div className="fixed inset-0 bg-brand-dark flex flex-col items-center justify-center z-[100] animate-fadeIn">
        <div className="w-48 h-48 mb-6 animate-pulse">
           <img src={INSTITUTIONAL.logoUrl} alt="Logo Splash" className="w-full h-full object-contain" />
        </div>
        <div className="flex flex-col items-center">
            <h1 className="serif-font text-3xl text-white font-black tracking-widest uppercase">
                {INSTITUTIONAL.ministryName}
            </h1>
            <div className="h-1 w-12 bg-brand-primary mt-4 rounded-full"></div>
            <p className="calligraphy-font text-2xl text-brand-accent mt-6">
                "{INSTITUTIONAL.slogan}"
            </p>
        </div>
        <div className="absolute bottom-12 text-white/40 text-[10px] uppercase font-black tracking-[0.3em]">
            Carregando sua jornada...
        </div>
      </div>
    );
  }

  const renderView = () => {
    switch (activeTab) {
      case 'home':
        return <HomeView stats={stats} prayers={prayers} onNavigate={setActiveTab} />;
      case 'prayers':
        return <PrayersView prayers={prayers} setPrayers={setPrayers} />;
      case 'filhos':
        return <FilhosView children={children} setChildren={setChildren} />;
      case 'community':
        return <CommunityView />;
      case 'timer':
        return <TimerView stats={stats} setStats={setStats} onFinish={() => setActiveTab('home')} />;
      case 'profile':
        return <ProfileView profile={profile} stats={stats} />;
      default:
        return <HomeView stats={stats} prayers={prayers} onNavigate={setActiveTab} />;
    }
  };

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab}>
      {renderView()}
    </Layout>
  );
};

export default App;

