import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import HomeView from './views/Home';
import PrayersView from './views/Prayers';
import FilhosView from './views/Filhos';
import CommunityView from './views/Community';
import TimerView from './views/Timer';
import ProfileView from './views/Profile';
import { PrayerRequest, ChildOfPrayer, UserStats, UserProfile } from './types';
import { INITIAL_PRAYER_REQUESTS, INSTITUTIONAL } from './constants';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [isLoading, setIsLoading] = useState(true);
  const [prayers, setPrayers] = useState<PrayerRequest[]>(INITIAL_PRAYER_REQUESTS);
  const [children, setChildren] = useState<ChildOfPrayer[]>([]);
  const [pendingChildren, setPendingChildren] = useState<ChildOfPrayer[]>([]);
  const [stats, setStats] = useState<UserStats>({
    streak: 3,
    totalMinutes: 245,
    totalDays: 12,
    hasDailyTrophy: false
  });
  const [profile] = useState<UserProfile>({
    name: "Ana Cláudia",
    birthDate: "1985-05-20",
    church: "Igreja Batista Aliança",
    participationTime: "2 anos",
    groupName: "Déboras de Curitiba"
  });

  // Splash Screen Effect
  useEffect(() => {
    const timer = setTimeout(() => setIsLoading(false), 2000);
    return () => clearTimeout(timer);
  }, []);

  // Simulate receiving a child from the website after 5 seconds
  useEffect(() => {
    if (isLoading) return;

    const arrivalTimer = setTimeout(() => {
      const websiteChild: ChildOfPrayer = {
        id: 'gc-web-101',
        name: 'Tiago Ferreira (Web)',
        type: 'geracao_compromisso',
        birthDate: '2008-04-12',
        location: 'Belo Horizonte, MG',
        photo: 'https://images.unsplash.com/photo-1503910360127-b328529ba44c?w=400&h=400&fit=crop',
        notes: 'Solicitou cobertura de oração através do site oficial do Despertar de Débora.',
        startDate: new Date().toISOString(),
        prayerMinutes: 0,
        individualRequests: [
          {
            id: 'web-req-1',
            request: 'Fortalecimento na fé e discernimento vocacional',
            status: 'em_oracao',
            createdAt: new Date().toISOString()
          }
        ]
      };
      setPendingChildren([websiteChild]);
    }, 5000);

    return () => clearTimeout(arrivalTimer);
  }, [isLoading]);

  // Initial data
  useEffect(() => {
    const threeDaysAgo = new Date();
    threeDaysAgo.setDate(threeDaysAgo.getDate() - 4);

    setChildren([
      {
        id: '1',
        name: 'Mateus Oliveira',
        type: 'biologico',
        birthDate: '2010-08-15',
        location: 'Curitiba, PR',
        photo: 'https://images.unsplash.com/photo-1519238263530-99bdd11df2ea?w=400&h=400&fit=crop',
        notes: 'Mateus está na fase dos desafios da adolescência.',
        startDate: '2023-01-01',
        prayerMinutes: 120,
        individualRequests: [
          { 
            id: 'r1', 
            request: 'Sabedoria nos estudos', 
            status: 'em_oracao', 
            createdAt: threeDaysAgo.toISOString() 
          },
          { 
            id: 'r2', 
            request: 'Proteção contra más amizades', 
            status: 'em_oracao', 
            createdAt: new Date().toISOString() 
          }
        ]
      }
    ]);
  }, []);

  // Notification Logic
  useEffect(() => {
    const checkPendingPrayers = () => {
      if (!("Notification" in window)) return;
      if (Notification.permission !== "granted") return;

      const now = new Date();
      children.forEach(child => {
        const staleRequest = child.individualRequests.find(req => {
          if (req.status !== 'em_oracao') return false;
          const created = new Date(req.createdAt);
          const diffDays = (now.getTime() - created.getTime()) / (1000 * 3600 * 24);
          return diffDays >= 3;
        });

        if (staleRequest) {
          try {
            new Notification(`Intercessão Urgente: ${child.name}`, {
              body: `Há pedidos de oração pendentes há mais de 3 dias. Vamos clamar?`,
              icon: INSTITUTIONAL.logoUrl
            });
          } catch (err) {
            console.error("Error displaying notification:", err);
          }
        }
      });
    };

    const interval = setInterval(checkPendingPrayers, 1000 * 60 * 60);
    return () => clearInterval(interval);
  }, [children]);

  if (isLoading) {
    return (
      <div className="fixed inset-0 bg-brand-soft flex flex-col items-center justify-center z-[100] animate-fadeIn">
        <div className="w-64 mb-10 animate-pulse">
          <img src={INSTITUTIONAL.logoUrl} alt="Logo" className="w-full h-auto" />
        </div>
        <div className="flex flex-col items-center gap-2">
          <div className="w-12 h-12 border-4 border-brand-primary border-t-transparent rounded-full animate-spin"></div>
          <p className="text-brand-dark/40 text-xs font-black uppercase tracking-[0.3em] mt-6">Aqueça seu altar...</p>
        </div>
      </div>
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'home':
        return <HomeView stats={stats} prayers={prayers} onNavigate={setActiveTab} />;
      case 'prayers':
        return <PrayersView prayers={prayers} setPrayers={setPrayers} />;
      case 'filhos':
        return <FilhosView 
          children={children} 
          setChildren={setChildren} 
          pendingChildren={pendingChildren}
          setPendingChildren={setPendingChildren}
        />;
      case 'community':
        return <CommunityView />;
      case 'timer':
        return <TimerView stats={stats} setStats={setStats} onFinish={() => setActiveTab('home')} />;
      case 'profile':
        return <ProfileView profile={profile} stats={stats} />;
      default:
        return <HomeView stats={stats} prayers={prayers} onNavigate={setActiveTab} />;
    }
  };

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab} hasPending={pendingChildren.length > 0}>
      <div className="pb-10">
        {renderContent()}
      </div>
    </Layout>
  );
};

export default App;

