import React, { useState, useRef } from 'react';
import { ChildOfPrayer, ChildPrayerRequest } from '../types';
import { INSTITUTIONAL } from '../constants';

interface FilhosProps {
  children: ChildOfPrayer[];
  setChildren: React.Dispatch<React.SetStateAction<ChildOfPrayer[]>>;
  pendingChildren?: ChildOfPrayer[];
  setPendingChildren?: React.Dispatch<React.SetStateAction<ChildOfPrayer[]>>;
}

const FilhosView: React.FC<FilhosProps> = ({ children, setChildren, pendingChildren = [], setPendingChildren }) => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [showAddRequestModal, setShowAddRequestModal] = useState(false);
  const [selectedChild, setSelectedChild] = useState<ChildOfPrayer | null>(null);
  const [viewMode, setViewMode] = useState<'list' | 'card'>('list');

  // Form State for Child
  const [newName, setNewName] = useState('');
  const [newType, setNewType] = useState<ChildOfPrayer['type']>('biologico');
  const [newBirthDate, setNewBirthDate] = useState('');
  const [newLocation, setNewLocation] = useState('');
  const [newPhoto, setNewPhoto] = useState<string | undefined>(undefined);
  const [newWhatsapp, setNewWhatsapp] = useState('');

  // Form State for Request
  const [newReqText, setNewReqText] = useState('');
  const [newReqVerse, setNewReqVerse] = useState('');
  const [newReqStatus, setNewReqStatus] = useState<'em_oracao' | 'respondido'>('em_oracao');

  const fileInputRef = useRef<HTMLInputElement>(null);

  const calculateAge = (birthDate: string) => {
    if (!birthDate) return 0;
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) age--;
    return age;
  };

  const isStale = (child: ChildOfPrayer) => {
    const now = new Date();
    return child.individualRequests.some(req => {
      if (req.status !== 'em_oracao') return false;
      const created = new Date(req.createdAt);
      const diffDays = (now.getTime() - created.getTime()) / (1000 * 3600 * 24);
      return diffDays >= 3;
    });
  };

  const getSeloStyles = (type: string) => {
    switch (type) {
      case 'geracao_compromisso': return 'bg-brand-gc text-white border-brand-gc';
      case 'biologico': return 'bg-brand-primary/10 text-brand-primary border-brand-primary/20';
      case 'espiritual': return 'bg-brand-secondary/10 text-brand-secondary border-brand-secondary/20';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  const getLabel = (type: string) => {
    switch (type) {
      case 'geracao_compromisso': return 'GC';
      case 'biologico': return 'Biológico';
      case 'espiritual': return 'Espiritual';
      case 'adotivo': return 'Adotivo';
      default: return type;
    }
  };

  const handleAcceptPending = (pending: ChildOfPrayer) => {
    setChildren(prev => [pending, ...prev]);
    if (setPendingChildren) {
      setPendingChildren(prev => prev.filter(p => p.id !== pending.id));
    }
  };

  const handleDeclinePending = (id: string) => {
    if (setPendingChildren) {
      setPendingChildren(prev => prev.filter(p => p.id !== id));
    }
  };

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setNewPhoto(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSaveChild = () => {
    if (!newName || !newBirthDate) {
      alert("Por favor, preencha o nome e a data de nascimento.");
      return;
    }

    const newChild: ChildOfPrayer = {
      id: Date.now().toString(),
      name: newName,
      type: newType,
      birthDate: newBirthDate,
      location: newLocation || 'Não informada',
      photo: newPhoto,
      whatsapp: newWhatsapp,
      notes: '',
      startDate: new Date().toISOString(),
      prayerMinutes: 0,
      individualRequests: []
    };

    setChildren(prev => [newChild, ...prev]);
    resetChildForm();
    setShowAddModal(false);
  };

  const handleAddRequest = () => {
    if (!selectedChild || !newReqText) {
      alert("Por favor, informe o motivo da oração.");
      return;
    }

    const newReq: ChildPrayerRequest = {
      id: Date.now().toString(),
      request: newReqText,
      verse: newReqVerse,
      status: newReqStatus,
      createdAt: new Date().toISOString(),
    };

    setChildren(prev => {
      const updated = prev.map(child => {
        if (child.id === selectedChild.id) {
          const updatedChild = {
            ...child,
            individualRequests: [...child.individualRequests, newReq]
          };
          setSelectedChild(updatedChild);
          return updatedChild;
        }
        return child;
      });
      return updated;
    });

    resetRequestForm();
    setShowAddRequestModal(false);
  };

  const toggleRequestStatus = (requestId: string) => {
    if (!selectedChild) return;

    setChildren(prev => {
      const updated = prev.map(child => {
        if (child.id === selectedChild.id) {
          const updatedRequests = child.individualRequests.map(req => {
            if (req.id === requestId) {
              return { ...req, status: req.status === 'em_oracao' ? 'respondido' : 'em_oracao' as any };
            }
            return req;
          });
          const updatedChild = { ...child, individualRequests: updatedRequests };
          setSelectedChild(updatedChild);
          return updatedChild;
        }
        return child;
      });
      return updated;
    });
  };

  const handleSendWhatsapp = (child: ChildOfPrayer) => {
    if (!child.whatsapp) {
      alert("Número de WhatsApp não cadastrado para este filho.");
      return;
    }
    // Remove caracteres não numéricos
    const cleanNumber = child.whatsapp.replace(/\D/g, '');
    const message = encodeURIComponent(`Olá ${child.name.split(' ')[0]}, hoje estou intercedendo por você no Despertar de Débora. Saiba que você é muito amado(a) por Deus! "Mães de joelhos, filhos de pé!" 🙏✨`);
    window.open(`https://wa.me/${cleanNumber}?text=${message}`, '_blank');
  };

  const resetChildForm = () => {
    setNewName('');
    setNewType('biologico');
    setNewBirthDate('');
    setNewLocation('');
    setNewPhoto(undefined);
    setNewWhatsapp('');
  };

  const resetRequestForm = () => {
    setNewReqText('');
    setNewReqVerse('');
    setNewReqStatus('em_oracao');
  };

  return (
    <div className="space-y-6 pb-20">
      <div className="flex items-center justify-between">
        <h2 className="serif-font text-2xl font-bold text-brand-dark">Filhos de Oração</h2>
        <div className="flex items-center gap-3">
          <div className="bg-brand-soft p-1 rounded-xl flex items-center border border-brand-border">
            <button 
              onClick={() => setViewMode('list')}
              className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all ${viewMode === 'list' ? 'bg-white text-brand-primary shadow-sm' : 'text-gray-400'}`}
            >
              <i className="fa-solid fa-list-ul text-xs"></i>
            </button>
            <button 
              onClick={() => setViewMode('card')}
              className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all ${viewMode === 'card' ? 'bg-white text-brand-primary shadow-sm' : 'text-gray-400'}`}
            >
              <i className="fa-solid fa-grip text-xs"></i>
            </button>
          </div>
          <button 
            onClick={() => setShowAddModal(true)}
            className="bg-brand-gc text-white w-10 h-10 rounded-full flex items-center justify-center shadow-lg active:scale-90 transition-transform"
          >
            <i className="fa-solid fa-plus"></i>
          </button>
        </div>
      </div>

      {/* Pending Arrivals Section */}
      {pendingChildren.length > 0 && (
        <section className="space-y-3 animate-fadeIn">
          <div className="flex items-center gap-2 px-1">
            <span className="relative flex h-2 w-2">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-brand-gc opacity-75"></span>
              <span className="relative inline-flex rounded-full h-2 w-2 bg-brand-gc"></span>
            </span>
            <h3 className="text-[10px] font-black uppercase text-brand-gc tracking-[0.2em]">Novas Solicitações (Web)</h3>
          </div>
          <div className="space-y-3">
            {pendingChildren.map(pending => (
              <div key={pending.id} className="bg-white rounded-3xl p-4 border-2 border-brand-gc/20 shadow-lg shadow-brand-gc/5 flex flex-col gap-4">
                <div className="flex gap-4">
                  <div className="w-16 h-16 rounded-2xl overflow-hidden border border-brand-gc/30">
                    <img src={pending.photo} className="w-full h-full object-cover" alt={pending.name} />
                  </div>
                  <div className="flex-1">
                    <div className="flex justify-between">
                      <h4 className="font-black text-brand-dark">{pending.name}</h4>
                      <span className="bg-brand-gc text-white text-[8px] font-black px-2 py-0.5 rounded-full uppercase">Geração Compromisso</span>
                    </div>
                    <p className="text-[10px] text-gray-500 mt-1 line-clamp-2 italic">"{pending.notes}"</p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button 
                    onClick={() => handleAcceptPending(pending)}
                    className="flex-1 bg-brand-gc text-white py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest active:scale-[0.98]"
                  >
                    Aceitar Cobertura
                  </button>
                  <button 
                    onClick={() => handleDeclinePending(pending.id)}
                    className="px-4 bg-gray-100 text-gray-400 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest active:scale-[0.98]"
                  >
                    Ignorar
                  </button>
                </div>
              </div>
            ))}
          </div>
        </section>
      )}

      <div className="bg-brand-gc text-white p-4 rounded-3xl border border-white/20 relative overflow-hidden shadow-inner">
        <div className="relative z-10 flex gap-3 items-center">
            <div className="w-10 h-10 bg-white/20 p-1.5 rounded-xl backdrop-blur-md">
                <img src={INSTITUTIONAL.gcLogoUrl} alt="GC Logo" className="w-full h-full object-contain" />
            </div>
            <p className="text-[11px] font-medium leading-tight opacity-90 italic">
                "Aqui você acompanha os filhos que Deus confiou a você para interceder, formando uma Geração Compromisso."
            </p>
        </div>
        <div className="absolute -right-4 -bottom-4 w-16 h-16 bg-white/5 rounded-full blur-xl"></div>
      </div>

      {/* Children List/Grid */}
      <div className={viewMode === 'list' ? "grid grid-cols-1 gap-4" : "grid grid-cols-2 gap-4"}>
        {children.length > 0 ? (
          children.map(child => {
            const stale = isStale(child);
            return viewMode === 'list' ? (
              <div 
                key={child.id} 
                className={`bg-white rounded-3xl p-4 border shadow-sm flex gap-4 cursor-pointer hover:shadow-md transition-shadow active:scale-[0.99] animate-fadeIn relative ${stale ? 'border-orange-300 ring-1 ring-orange-100 shadow-orange-50' : (child.type === 'geracao_compromisso' ? 'border-brand-gc/30' : 'border-brand-border')}`}
              >
                {stale && <div className="absolute -top-1 -left-1 bg-orange-500 text-white text-[8px] font-black px-2 py-0.5 rounded-full shadow-sm animate-pulse z-10">URGENTE</div>}
                <div onClick={() => setSelectedChild(child)} className="w-20 h-20 rounded-2xl overflow-hidden flex-shrink-0 bg-brand-soft border border-brand-border relative">
                  <img 
                      src={child.photo || `https://picsum.photos/seed/${child.id}/200`} 
                      alt={child.name} 
                      className="w-full h-full object-cover" 
                  />
                </div>
                <div className="flex-1 space-y-2">
                  <div className="flex justify-between items-start" onClick={() => setSelectedChild(child)}>
                    <h3 className="font-bold text-brand-dark line-clamp-1">{child.name}</h3>
                    <span className={`text-[8px] uppercase font-black px-2 py-0.5 rounded-full border tracking-tighter ${getSeloStyles(child.type)}`}>
                      {getLabel(child.type)}
                    </span>
                  </div>
                  <div className="flex items-center gap-3">
                    <p className="text-xs text-gray-500">
                      <i className="fa-solid fa-cake-candles mr-1 opacity-60"></i> {calculateAge(child.birthDate)} anos
                    </p>
                    {child.whatsapp && (
                      <button 
                        onClick={(e) => { e.stopPropagation(); handleSendWhatsapp(child); }}
                        className="text-green-500 hover:text-green-600 active:scale-90 transition-all flex items-center gap-1"
                      >
                        <i className="fa-brands fa-whatsapp text-sm"></i>
                        <span className="text-[9px] font-black uppercase">Mensagem</span>
                      </button>
                    )}
                  </div>
                  <div className="flex items-center justify-between pt-1" onClick={() => setSelectedChild(child)}>
                    <div className="flex items-center gap-2">
                      <i className={`fa-solid fa-hands-praying text-xs ${stale ? 'text-orange-500' : (child.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary')}`}></i>
                      <span className="text-[10px] text-gray-400 font-medium">
                        {child.individualRequests.filter(r => r.status === 'em_oracao').length} clamores
                      </span>
                    </div>
                    <div className={`flex items-center gap-1.5 px-2 py-0.5 rounded-full ${child.type === 'geracao_compromisso' ? 'bg-brand-gc/10' : 'bg-brand-soft'}`}>
                      <i className={`fa-solid fa-clock text-[10px] ${child.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary'}`}></i>
                      <span className={`text-[10px] font-black ${child.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary'}`}>{child.prayerMinutes}m</span>
                    </div>
                  </div>
                </div>
              </div>
            ) : (
              <div 
                key={child.id} 
                className={`bg-white rounded-[2rem] p-3 border shadow-sm cursor-pointer hover:shadow-md transition-all active:scale-[0.97] animate-fadeIn relative overflow-hidden group ${stale ? 'border-orange-300 ring-1 ring-orange-100' : (child.type === 'geracao_compromisso' ? 'border-brand-gc/30' : 'border-brand-border')}`}
              >
                {stale && <div className="absolute top-2 left-2 bg-orange-500 text-white text-[7px] font-black px-2 py-1 rounded-lg z-10 shadow-lg animate-pulse">PRECISA DE ATENÇÃO</div>}
                <div onClick={() => setSelectedChild(child)} className="aspect-square w-full rounded-[1.5rem] overflow-hidden mb-3 bg-brand-soft relative">
                  <img 
                      src={child.photo || `https://picsum.photos/seed/${child.id}/200`} 
                      alt={child.name} 
                      className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" 
                  />
                  <div className="absolute top-2 right-2">
                    <span className={`text-[7px] uppercase font-black px-2 py-1 rounded-lg border shadow-sm backdrop-blur-md ${getSeloStyles(child.type)}`}>
                      {getLabel(child.type)}
                    </span>
                  </div>
                </div>
                <div className="px-1 pb-1 text-center" onClick={() => setSelectedChild(child)}>
                  <h3 className="font-bold text-brand-dark text-sm line-clamp-1 mb-1">{child.name}</h3>
                  <div className="flex items-center justify-center gap-2 text-[10px] text-gray-400 font-medium">
                    <span>{calculateAge(child.birthDate)} anos</span>
                    <span>•</span>
                    <span className={`${child.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary'} font-black`}>{child.prayerMinutes}m</span>
                  </div>
                </div>
                {child.whatsapp && (
                  <button 
                    onClick={(e) => { e.stopPropagation(); handleSendWhatsapp(child); }}
                    className="absolute bottom-3 right-3 w-8 h-8 bg-green-500 text-white rounded-full flex items-center justify-center shadow-md active:scale-90 transition-transform"
                  >
                    <i className="fa-brands fa-whatsapp"></i>
                  </button>
                )}
              </div>
            );
          })
        ) : (
          <div className="col-span-full text-center py-24 text-gray-400">
            <i className="fa-solid fa-users-rays text-6xl mb-6 opacity-20"></i>
            <p className="text-sm font-medium">Sua lista de intercessão está vazia.</p>
            <p className="text-xs mt-1">Toque no + para começar a cadastrar seus filhos.</p>
          </div>
        )}
      </div>

      {/* Detail Modal */}
      {selectedChild && (
        <div className="fixed inset-0 bg-black/60 z-[60] flex items-end sm:items-center justify-center p-0 sm:p-4">
          <div className="bg-white w-full max-w-lg rounded-t-[2.5rem] sm:rounded-3xl p-6 animate-slideUp overflow-y-auto max-h-[95vh] no-scrollbar">
            <div className="w-12 h-1.5 bg-gray-200 rounded-full mx-auto mb-6 sm:hidden"></div>

            <div className="flex justify-between items-start mb-6">
              <div className="flex items-center gap-4">
                <div className={`w-20 h-20 rounded-2xl overflow-hidden border-2 shadow-sm ${selectedChild.type === 'geracao_compromisso' ? 'border-brand-gc' : 'border-brand-primary'}`}>
                  <img src={selectedChild.photo || `https://picsum.photos/seed/${selectedChild.id}/200`} className="w-full h-full object-cover" alt={selectedChild.name} />
                </div>
                <div className="space-y-1">
                  <h3 className="text-xl font-bold text-brand-dark leading-tight">{selectedChild.name}</h3>
                  <p className={`text-[10px] font-black uppercase tracking-wider ${selectedChild.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary'}`}>{selectedChild.type.replace('_', ' ')}</p>
                </div>
              </div>
              <div className="flex gap-2">
                {selectedChild.whatsapp && (
                  <button 
                    onClick={() => handleSendWhatsapp(selectedChild)}
                    className="w-10 h-10 rounded-full bg-green-500 text-white flex items-center justify-center active:scale-90 transition-transform shadow-md"
                  >
                    <i className="fa-brands fa-whatsapp text-lg"></i>
                  </button>
                )}
                <button onClick={() => setSelectedChild(null)} className="w-10 h-10 rounded-full bg-gray-100 flex items-center justify-center active:bg-gray-200 transition-colors">
                  <i className="fa-solid fa-xmark text-gray-500"></i>
                </button>
              </div>
            </div>

            <div className="space-y-8">
              <section>
                <div className="flex items-center justify-between mb-4">
                  <h4 className={`text-xs font-black uppercase tracking-widest flex items-center gap-2 ${selectedChild.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary'}`}>
                    <i className="fa-solid fa-heart-pulse"></i>
                    Pedidos de Oração
                  </h4>
                  <button 
                    onClick={() => setShowAddRequestModal(true)}
                    className={`text-[10px] font-black uppercase px-4 py-1.5 rounded-full transition-all active:scale-95 ${selectedChild.type === 'geracao_compromisso' ? 'bg-brand-gc text-white shadow-md shadow-brand-gc/20' : 'bg-brand-primary text-white shadow-md shadow-brand-primary/20'}`}
                  >
                    + Novo Pedido
                  </button>
                </div>

                <div className="space-y-3">
                  {selectedChild.individualRequests.length > 0 ? (
                    selectedChild.individualRequests.map(req => {
                      const reqDays = Math.floor((new Date().getTime() - new Date(req.createdAt).getTime()) / (1000 * 3600 * 24));
                      const staleReq = req.status === 'em_oracao' && reqDays >= 3;
                      return (
                        <div key={req.id} className={`p-4 rounded-2xl border space-y-3 shadow-sm transition-all ${staleReq ? 'bg-orange-50 border-orange-200' : 'bg-brand-cream/50 border-brand-border/40'}`}>
                          <div className="flex items-start justify-between gap-4">
                            <div className="flex-1 space-y-1">
                              <span className="text-sm font-bold text-gray-800 leading-snug block">{req.request}</span>
                              {staleReq && <span className="text-[9px] text-orange-600 font-black uppercase">Pendente há {reqDays} dias</span>}
                            </div>
                            <button 
                              onClick={() => toggleRequestStatus(req.id)}
                              className={`text-[8px] font-black uppercase px-2 py-1 rounded-full whitespace-nowrap transition-all active:scale-90 ${req.status === 'em_oracao' ? 'bg-orange-100 text-orange-700' : 'bg-green-100 text-green-700'}`}
                            >
                              {req.status === 'em_oracao' ? 'Em Oração' : 'Respondido'}
                            </button>
                          </div>
                          {req.verse && (
                            <p className="text-[11px] text-brand-primary/80 font-medium italic bg-white/60 p-2 rounded-lg border border-brand-border/20">
                              <i className="fa-solid fa-book-bible mr-1.5"></i> "{req.verse}"
                            </p>
                          )}
                        </div>
                      );
                    })
                  ) : (
                    <div className="text-center py-8 bg-gray-50 rounded-2xl border-2 border-dashed border-gray-100">
                      <p className="text-[11px] text-gray-400 font-medium italic">Nenhum pedido específico cadastrado ainda.</p>
                    </div>
                  )}
                </div>
              </section>

              <section>
                <h4 className={`text-xs font-black uppercase tracking-widest mb-4 flex items-center gap-2 ${selectedChild.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary'}`}>
                  <i className="fa-solid fa-chart-pie"></i>
                  Histórico Espiritual
                </h4>
                <div className={`flex items-center justify-around p-5 rounded-3xl border ${selectedChild.type === 'geracao_compromisso' ? 'bg-brand-gc/5 border-brand-gc/20' : 'bg-brand-soft/30 border-brand-border'}`}>
                  <div className="text-center">
                    <p className={`text-2xl font-black ${selectedChild.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary'}`}>{selectedChild.prayerMinutes}</p>
                    <p className="text-[9px] uppercase font-black text-gray-400 tracking-tighter">Minutos</p>
                  </div>
                  <div className={`h-10 w-[1px] ${selectedChild.type === 'geracao_compromisso' ? 'bg-brand-gc/20' : 'bg-brand-border'}`}></div>
                  <div className="text-center">
                    <p className={`text-2xl font-black ${selectedChild.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary'}`}>
                      {selectedChild.individualRequests.filter(r => r.status === 'respondido').length}
                    </p>
                    <p className="text-[9px] uppercase font-black text-gray-400 tracking-tighter">Vitórias</p>
                  </div>
                </div>
              </section>

              <button className={`w-full py-5 rounded-full text-white font-black uppercase tracking-widest shadow-xl active:scale-[0.97] transition-all flex items-center justify-center gap-3 ${selectedChild.type === 'geracao_compromisso' ? 'bg-brand-gc shadow-brand-gc/30' : 'gradient-brand shadow-brand-primary/30'}`}>
                <i className="fa-solid fa-hands-praying"></i>
                Orar por {selectedChild.name.split(' ')[0]}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Add Request Modal */}
      {showAddRequestModal && (
        <div className="fixed inset-0 bg-black/70 z-[70] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-sm rounded-[2rem] p-8 space-y-6 animate-fadeIn shadow-2xl">
            <div className="text-center">
              <h3 className={`serif-font text-2xl font-bold ${selectedChild?.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary'}`}>Nova Intercessão</h3>
              <p className="text-xs text-gray-400 mt-1">Coloque o clamor no altar do Senhor.</p>
            </div>

            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase ml-2 tracking-widest">Qual o motivo?</label>
                <textarea 
                  placeholder="Ex: Sabedoria nos estudos, proteção..." 
                  value={newReqText}
                  onChange={(e) => setNewReqText(e.target.value)}
                  className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary h-28 resize-none shadow-inner" 
                />
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase ml-2 tracking-widest">Versículo da Promessa</label>
                <input 
                  type="text" 
                  placeholder="Ex: Filipenses 4:13" 
                  value={newReqVerse}
                  onChange={(e) => setNewReqVerse(e.target.value)}
                  className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner" 
                />
              </div>
            </div>

            <div className="flex gap-4 pt-2">
              <button 
                onClick={() => { setShowAddRequestModal(false); resetRequestForm(); }} 
                className="flex-1 py-4 bg-gray-100 text-gray-500 rounded-full text-xs font-black uppercase tracking-widest"
              >
                Cancelar
              </button>
              <button 
                onClick={handleAddRequest} 
                className={`flex-1 py-4 text-white rounded-full text-xs font-black uppercase tracking-widest shadow-lg active:scale-95 ${selectedChild?.type === 'geracao_compromisso' ? 'bg-brand-gc shadow-brand-gc/20' : 'gradient-brand shadow-brand-primary/20'}`}
              >
                Salvar
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Add Child Modal */}
      {showAddModal && (
        <div className="fixed inset-0 bg-black/70 z-[60] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 space-y-6 animate-fadeIn overflow-y-auto max-h-[90vh] no-scrollbar shadow-2xl">
            <div className="text-center">
              <h3 className="serif-font text-2xl font-bold text-brand-dark">Novo Filho de Oração</h3>
              <p className="text-xs text-gray-400 mt-1">Cobrindo um jovem com intercessão.</p>
            </div>

            <div className="space-y-4">
              {/* Photo Upload Section */}
              <div className="flex flex-col items-center gap-3 mb-4">
                <div 
                  onClick={() => fileInputRef.current?.click()}
                  className="w-32 h-32 rounded-3xl bg-brand-soft border-2 border-dashed border-brand-primary/30 flex flex-col items-center justify-center cursor-pointer overflow-hidden relative group shadow-sm"
                >
                  {newPhoto ? (
                    <img src={newPhoto} alt="Preview" className="w-full h-full object-cover" />
                  ) : (
                    <div className="flex flex-col items-center text-center px-4">
                      <i className="fa-solid fa-camera text-brand-primary text-3xl mb-2 opacity-50"></i>
                      <span className="text-[10px] font-black text-brand-primary/50 uppercase tracking-widest">Toque para adicionar foto</span>
                    </div>
                  )}
                  <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                    <i className="fa-solid fa-camera text-white text-xl"></i>
                  </div>
                </div>
                <input 
                  type="file" 
                  ref={fileInputRef} 
                  onChange={handlePhotoUpload} 
                  accept="image/*" 
                  className="hidden" 
                />
                <div className="flex gap-4">
                  <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="text-[10px] font-black uppercase text-brand-primary tracking-widest flex items-center gap-1.5"
                  >
                    <i className="fa-solid fa-images"></i>
                    Galeria / Câmera
                  </button>
                  {newPhoto && (
                    <button 
                      onClick={() => setNewPhoto(undefined)}
                      className="text-[10px] font-black uppercase text-red-400 tracking-widest flex items-center gap-1.5"
                    >
                      <i className="fa-solid fa-trash"></i>
                      Remover
                    </button>
                  )}
                </div>
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black text-brand-primary uppercase ml-2 tracking-widest">Nome Completo</label>
                <input 
                  type="text" 
                  placeholder="Nome do jovem" 
                  value={newName}
                  onChange={(e) => setNewName(e.target.value)}
                  className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner" 
                />
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black text-brand-primary uppercase ml-2 tracking-widest">WhatsApp</label>
                <input 
                  type="tel" 
                  placeholder="Ex: 41999999999" 
                  value={newWhatsapp}
                  onChange={(e) => setNewWhatsapp(e.target.value)}
                  className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner" 
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-brand-primary uppercase ml-2 tracking-widest">Vínculo</label>
                  <select 
                    value={newType}
                    onChange={(e) => setNewType(e.target.value as any)}
                    className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner appearance-none"
                  >
                    <option value="biologico">Biológico</option>
                    <option value="espiritual">Espiritual</option>
                    <option value="adotivo">Adotivo</option>
                    <option value="geracao_compromisso">Geração Compromisso</option>
                  </select>
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-brand-primary uppercase ml-2 tracking-widest">Nascimento</label>
                  <input 
                    type="date" 
                    value={newBirthDate}
                    onChange={(e) => setNewBirthDate(e.target.value)}
                    className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner" 
                  />
                </div>
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black text-brand-primary uppercase ml-2 tracking-widest">Localização (Cidade/Estado)</label>
                <input 
                  type="text" 
                  placeholder="Ex: Curitiba, PR" 
                  value={newLocation}
                  onChange={(e) => setNewLocation(e.target.value)}
                  className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner" 
                />
              </div>
            </div>

            <div className="flex gap-4 pt-4">
              <button 
                onClick={() => { setShowAddModal(false); resetChildForm(); }} 
                className="flex-1 py-4 bg-gray-100 text-gray-500 rounded-full text-xs font-black uppercase tracking-widest"
              >
                Cancelar
              </button>
              <button 
                onClick={handleSaveChild} 
                className="flex-1 py-4 gradient-brand text-white rounded-full text-xs font-black uppercase tracking-widest shadow-xl active:scale-95"
              >
                Salvar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default FilhosView;

