import React, { useState, useRef } from 'react';
import { ChildOfPrayer, ChildPrayerRequest } from '../types';
import { INSTITUTIONAL } from '../constants';

interface FilhosProps {
  children: ChildOfPrayer[];
  setChildren: React.Dispatch<React.SetStateAction<ChildOfPrayer[]>>;
  pendingChildren?: ChildOfPrayer[];
  setPendingChildren?: React.Dispatch<React.SetStateAction<ChildOfPrayer[]>>;
}

const FilhosView: React.FC<FilhosProps> = ({ children, setChildren, pendingChildren = [], setPendingChildren }) => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [showAddRequestModal, setShowAddRequestModal] = useState(false);
  const [selectedChild, setSelectedChild] = useState<ChildOfPrayer | null>(null);
  const [viewMode, setViewMode] = useState<'list' | 'card'>('list');

  // Form State for Child
  const [newName, setNewName] = useState('');
  const [newType, setNewType] = useState<ChildOfPrayer['type']>('biologico');
  const [newBirthDate, setNewBirthDate] = useState('');
  const [newLocation, setNewLocation] = useState('');
  const [newPhoto, setNewPhoto] = useState<string | undefined>(undefined);
  const [newWhatsapp, setNewWhatsapp] = useState('');

  // Form State for Request
  const [newReqText, setNewReqText] = useState('');
  const [newReqVerse, setNewReqVerse] = useState('');
  const [newReqStatus, setNewReqStatus] = useState<'em_oracao' | 'respondido'>('em_oracao');

  const fileInputRef = useRef<HTMLInputElement>(null);

  const calculateAge = (birthDate: string) => {
    if (!birthDate) return 0;
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) age--;
    return age;
  };

  const isStale = (child: ChildOfPrayer) => {
    const now = new Date();
    return child.individualRequests.some(req => {
      if (req.status !== 'em_oracao') return false;
      const created = new Date(req.createdAt);
      const diffDays = (now.getTime() - created.getTime()) / (1000 * 3600 * 24);
      return diffDays >= 3;
    });
  };

  const getSeloStyles = (type: string) => {
    switch (type) {
      case 'geracao_compromisso': return 'bg-brand-gc text-white border-brand-gc';
      case 'biologico': return 'bg-brand-rose/10 text-brand-rose border-brand-rose/20';
      case 'espiritual': return 'bg-brand-lavender text-brand-gc border-brand-gc/20';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  const getLabel = (type: string) => {
    switch (type) {
      case 'geracao_compromisso': return 'GC';
      case 'biologico': return 'Biológico';
      case 'espiritual': return 'Espiritual';
      case 'adotivo': return 'Adotivo';
      default: return type;
    }
  };

  const handleSendWhatsapp = (child: ChildOfPrayer) => {
    if (!child.whatsapp) {
      alert("Por favor, adicione um número de WhatsApp para este filho.");
      return;
    }
    const cleanNumber = child.whatsapp.replace(/\D/g, '');
    const message = encodeURIComponent(`Olá ${child.name.split(' ')[0]}, hoje parei um momento especial para orar por você no Despertar de Débora. Saiba que você está guardado(a) no coração de Deus! "Mães de joelhos, filhos de pé!" 🙏🔥`);
    window.open(`https://wa.me/${cleanNumber}?text=${message}`, '_blank');
  };

  const handleSaveChild = () => {
    if (!newName || !newBirthDate) {
      alert("Por favor, preencha o nome e a data de nascimento.");
      return;
    }

    const newChild: ChildOfPrayer = {
      id: Date.now().toString(),
      name: newName,
      type: newType,
      birthDate: newBirthDate,
      location: newLocation || 'Não informada',
      photo: newPhoto,
      whatsapp: newWhatsapp,
      notes: '',
      startDate: new Date().toISOString(),
      prayerMinutes: 0,
      individualRequests: []
    };

    setChildren(prev => [newChild, ...prev]);
    resetChildForm();
    setShowAddModal(false);
  };

  const resetChildForm = () => {
    setNewName('');
    setNewType('biologico');
    setNewBirthDate('');
    setNewLocation('');
    setNewPhoto(undefined);
    setNewWhatsapp('');
  };

  const handleAddRequest = () => {
    if (!selectedChild || !newReqText) {
      alert("Por favor, informe o motivo da oração.");
      return;
    }

    const newReq: ChildPrayerRequest = {
      id: Date.now().toString(),
      request: newReqText,
      verse: newReqVerse,
      status: newReqStatus,
      createdAt: new Date().toISOString(),
    };

    setChildren(prev => {
      const updated = prev.map(child => {
        if (child.id === selectedChild.id) {
          const updatedChild = {
            ...child,
            individualRequests: [...child.individualRequests, newReq]
          };
          setSelectedChild(updatedChild);
          return updatedChild;
        }
        return child;
      });
      return updated;
    });

    resetRequestForm();
    setShowAddRequestModal(false);
  };

  const resetRequestForm = () => {
    setNewReqText('');
    setNewReqVerse('');
    setNewReqStatus('em_oracao');
  };

  return (
    <div className="space-y-6 pb-20">
      <div className="flex items-center justify-between">
        <h2 className="serif-font text-2xl font-bold text-brand-dark">Filhos de Oração</h2>
        <div className="flex items-center gap-3">
          <div className="bg-brand-lavender/50 p-1 rounded-xl flex items-center border border-brand-rose/20">
            <button 
              onClick={() => setViewMode('list')}
              className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all ${viewMode === 'list' ? 'bg-white text-brand-rose shadow-sm' : 'text-gray-400'}`}
            >
              <i className="fa-solid fa-list-ul text-xs"></i>
            </button>
            <button 
              onClick={() => setViewMode('card')}
              className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all ${viewMode === 'card' ? 'bg-white text-brand-rose shadow-sm' : 'text-gray-400'}`}
            >
              <i className="fa-solid fa-grip text-xs"></i>
            </button>
          </div>
          <button 
            onClick={() => setShowAddModal(true)}
            className="bg-brand-rose text-white w-10 h-10 rounded-full flex items-center justify-center shadow-lg active:scale-90 transition-transform"
          >
            <i className="fa-solid fa-plus"></i>
          </button>
        </div>
      </div>

      {/* Intro Header com Logo Geração Compromisso Oficial */}
      <div className="bg-brand-pink/50 text-brand-gc p-5 rounded-3xl border border-brand-rose/20 relative overflow-hidden shadow-sm">
        <div className="relative z-10 flex gap-5 items-center">
            <div className="w-16 h-16 bg-white p-2 rounded-2xl shadow-md border border-brand-lavender transition-transform hover:scale-105">
                <img 
                  src={INSTITUTIONAL.gcLogoUrl} 
                  alt="Logo Geração Compromisso Oficial" 
                  className="w-full h-full object-contain" 
                />
            </div>
            <div className="flex-1">
              <p className="text-[12px] font-bold leading-snug text-brand-gc uppercase tracking-tighter mb-1">Geração Compromisso</p>
              <p className="text-[11px] font-medium leading-tight italic text-brand-dark/70">
                  "Você acompanha os filhos confiados por Deus para interceder por uma nova geração salva e comprometida."
              </p>
            </div>
        </div>
        <div className="absolute -left-4 -bottom-4 w-12 h-12 bg-white/10 rounded-full blur-xl"></div>
      </div>

      {/* Children List */}
      <div className={viewMode === 'list' ? "grid grid-cols-1 gap-4" : "grid grid-cols-2 gap-4"}>
        {children.length > 0 ? (
          children.map(child => {
            const stale = isStale(child);
            return (
              <div 
                key={child.id} 
                className={`bg-white rounded-[2rem] p-4 border shadow-sm flex flex-col gap-4 animate-fadeIn relative transition-all hover:shadow-md ${stale ? 'border-orange-200 bg-orange-50/30' : 'border-brand-lavender'}`}
              >
                <div className="flex gap-4">
                  <div onClick={() => setSelectedChild(child)} className="w-16 h-16 rounded-2xl overflow-hidden flex-shrink-0 border border-brand-rose/10 cursor-pointer shadow-sm">
                    <img 
                      src={child.photo || `https://picsum.photos/seed/${child.id}/200`} 
                      className="w-full h-full object-cover" 
                      alt={child.name} 
                    />
                  </div>
                  <div className="flex-1 min-w-0" onClick={() => setSelectedChild(child)}>
                    <div className="flex justify-between items-start">
                      <h3 className="font-bold text-brand-dark text-sm truncate pr-2">{child.name}</h3>
                      <span className={`text-[7px] font-black px-2 py-0.5 rounded-full border uppercase whitespace-nowrap ${getSeloStyles(child.type)}`}>
                        {getLabel(child.type)}
                      </span>
                    </div>
                    <p className="text-[10px] text-gray-400 mt-1">
                      <i className="fa-solid fa-cake-candles mr-1"></i> {calculateAge(child.birthDate)} anos
                    </p>
                  </div>
                </div>

                <div className="flex items-center justify-between pt-2 border-t border-gray-50">
                  <div className="flex gap-4">
                    <div className="flex items-center gap-1.5 text-brand-gc">
                      <i className="fa-solid fa-hands-praying text-[10px]"></i>
                      <span className="text-[10px] font-black">{child.individualRequests.filter(r => r.status === 'em_oracao').length}</span>
                    </div>
                    <div className="flex items-center gap-1.5 text-brand-rose">
                      <i className="fa-solid fa-clock text-[10px]"></i>
                      <span className="text-[10px] font-black">{child.prayerMinutes}m</span>
                    </div>
                  </div>

                  {child.whatsapp && (
                    <button 
                      onClick={() => handleSendWhatsapp(child)}
                      className="bg-green-500 text-white px-4 py-2 rounded-full text-[9px] font-black uppercase flex items-center gap-2 shadow-sm active:scale-95 transition-transform"
                    >
                      <i className="fa-brands fa-whatsapp"></i>
                      Abençoar
                    </button>
                  )}
                </div>
              </div>
            );
          })
        ) : (
          <div className="col-span-full text-center py-20 text-gray-400 bg-white/50 rounded-3xl border-2 border-dashed border-brand-rose/20">
            <i className="fa-solid fa-users-rays text-5xl mb-4 opacity-10"></i>
            <p className="text-sm font-medium">Nenhum filho cadastrado ainda.</p>
          </div>
        )}
      </div>

      {/* Add Child Modal */}
      {showAddModal && (
        <div className="fixed inset-0 bg-black/60 z-[70] flex items-center justify-center p-6 backdrop-blur-sm">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 space-y-6 shadow-2xl animate-fadeIn overflow-y-auto max-h-[90vh] no-scrollbar">
            <div className="text-center">
              <h3 className="serif-font text-2xl font-bold text-brand-dark">Novo Filho</h3>
              <p className="text-xs text-brand-rose font-medium mt-1">Coloque um novo jovem em sua cobertura.</p>
            </div>

            <div className="space-y-4">
              <div className="flex flex-col items-center mb-2">
                <div 
                  onClick={() => fileInputRef.current?.click()}
                  className="w-24 h-24 rounded-[2rem] bg-brand-pink border-2 border-dashed border-brand-rose/30 flex items-center justify-center cursor-pointer overflow-hidden relative"
                >
                  {newPhoto ? (
                    <img src={newPhoto} className="w-full h-full object-cover" alt="Preview" />
                  ) : (
                    <i className="fa-solid fa-camera text-brand-rose/40 text-2xl"></i>
                  )}
                </div>
                <input type="file" ref={fileInputRef} onChange={(e) => {
                  const file = e.target.files?.[0];
                  if (file) {
                    const reader = new FileReader();
                    reader.onloadend = () => setNewPhoto(reader.result as string);
                    reader.readAsDataURL(file);
                  }
                }} className="hidden" accept="image/*" />
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black text-brand-rose uppercase ml-3">Nome do Filho</label>
                <input 
                  type="text" 
                  value={newName}
                  onChange={(e) => setNewName(e.target.value)}
                  placeholder="Nome completo"
                  className="w-full bg-gray-50 border border-brand-rose/10 p-4 rounded-2xl text-sm focus:ring-1 focus:ring-brand-rose outline-none"
                />
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black text-brand-rose uppercase ml-3">WhatsApp</label>
                <input 
                  type="tel" 
                  value={newWhatsapp}
                  onChange={(e) => setNewWhatsapp(e.target.value)}
                  placeholder="Ex: 11999999999"
                  className="w-full bg-gray-50 border border-brand-rose/10 p-4 rounded-2xl text-sm focus:ring-1 focus:ring-brand-rose outline-none"
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-brand-rose uppercase ml-3">Vínculo</label>
                  <select 
                    value={newType}
                    onChange={(e) => setNewType(e.target.value as any)}
                    className="w-full bg-gray-50 border border-brand-rose/10 p-4 rounded-2xl text-sm outline-none"
                  >
                    <option value="biologico">Biológico</option>
                    <option value="espiritual">Espiritual</option>
                    <option value="adotivo">Adotivo</option>
                    <option value="geracao_compromisso">GC</option>
                  </select>
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-brand-rose uppercase ml-3">Nascimento</label>
                  <input 
                    type="date" 
                    value={newBirthDate}
                    onChange={(e) => setNewBirthDate(e.target.value)}
                    className="w-full bg-gray-50 border border-brand-rose/10 p-4 rounded-2xl text-sm outline-none"
                  />
                </div>
              </div>
            </div>

            <div className="flex gap-4 pt-2">
              <button 
                onClick={() => setShowAddModal(false)}
                className="flex-1 py-4 bg-gray-100 text-gray-500 rounded-full text-xs font-black uppercase tracking-widest"
              >
                Cancelar
              </button>
              <button 
                onClick={handleSaveChild}
                className="flex-[2] py-4 bg-brand-rose text-white rounded-full text-xs font-black uppercase tracking-widest shadow-lg shadow-brand-rose/20 active:scale-95"
              >
                Salvar Filho
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Detail Modal */}
      {selectedChild && (
        <div className="fixed inset-0 bg-black/60 z-[60] flex items-end sm:items-center justify-center p-0 sm:p-4">
          <div className="bg-white w-full max-w-lg rounded-t-[2.5rem] sm:rounded-3xl p-8 animate-slideUp overflow-y-auto max-h-[90vh] no-scrollbar">
            <div className="flex justify-between items-start mb-6">
              <div className="flex gap-5 items-center">
                <div className="w-20 h-20 rounded-[1.5rem] overflow-hidden border-2 border-brand-rose/20 shadow-sm">
                  <img src={selectedChild.photo || `https://picsum.photos/seed/${selectedChild.id}/200`} className="w-full h-full object-cover" alt={selectedChild.name} />
                </div>
                <div>
                  <h3 className="text-xl font-bold text-brand-dark leading-tight">{selectedChild.name}</h3>
                  <div className="flex items-center gap-2 mt-1">
                    <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-full ${getSeloStyles(selectedChild.type)}`}>
                      {getLabel(selectedChild.type)}
                    </span>
                    <p className="text-[10px] text-gray-400 font-medium">{calculateAge(selectedChild.birthDate)} anos</p>
                  </div>
                </div>
              </div>
              <button onClick={() => setSelectedChild(null)} className="w-10 h-10 rounded-full bg-gray-50 flex items-center justify-center active:bg-gray-200">
                <i className="fa-solid fa-xmark text-gray-400"></i>
              </button>
            </div>

            <div className="space-y-8">
              {/* Se o filho for da GC, exibir selo oficial no detalhe */}
              {selectedChild.type === 'geracao_compromisso' && (
                <div className="bg-brand-gc/5 border border-brand-gc/20 rounded-2xl p-4 flex items-center gap-4">
                   <img src={INSTITUTIONAL.gcLogoUrl} className="w-10 h-10 object-contain" alt="GC Seal" />
                   <p className="text-[10px] font-black uppercase text-brand-gc tracking-widest leading-tight">Este jovem faz parte da Geração Compromisso</p>
                </div>
              )}

              {selectedChild.whatsapp && (
                <button 
                  onClick={() => handleSendWhatsapp(selectedChild)}
                  className="w-full bg-green-50/50 border border-green-200 text-green-700 py-4 rounded-2xl flex items-center justify-center gap-3 active:scale-[0.98] transition-all"
                >
                  <div className="w-8 h-8 bg-green-500 rounded-full flex items-center justify-center text-white shadow-sm">
                    <i className="fa-brands fa-whatsapp text-lg"></i>
                  </div>
                  <div className="text-left">
                    <p className="text-[10px] font-black uppercase tracking-widest leading-none">Enviar Mensagem</p>
                    <p className="text-[11px] font-medium opacity-70">Abençoe seu filho agora</p>
                  </div>
                </button>
              )}

              <section>
                <div className="flex items-center justify-between mb-4">
                  <h4 className="text-[10px] font-black uppercase text-brand-gc tracking-[0.2em] flex items-center gap-2">
                    <i className="fa-solid fa-heart-pulse"></i>
                    Clamores Ativos
                  </h4>
                  <button 
                    onClick={() => setShowAddRequestModal(true)}
                    className="text-[9px] font-black uppercase text-brand-rose bg-brand-pink px-4 py-1.5 rounded-full"
                  >
                    + Novo
                  </button>
                </div>

                <div className="space-y-3">
                  {selectedChild.individualRequests.length > 0 ? (
                    selectedChild.individualRequests.map(req => (
                      <div key={req.id} className="p-4 bg-brand-lavender/30 rounded-2xl border border-brand-rose/5">
                        <p className="text-sm font-bold text-brand-dark leading-snug">{req.request}</p>
                        {req.verse && (
