                    <p className="text-center py-6 text-[11px] text-gray-400 italic">Nenhum clamor registrado ainda.</p>
                  )}
                </div>
              </section>

              <button className={`w-full py-5 text-white rounded-full font-black uppercase tracking-widest shadow-xl active:scale-95 transition-all flex items-center justify-center gap-3 ${selectedChild.type === 'geracao_compromisso' ? 'bg-brand-gc shadow-brand-gc/20' : 'bg-brand-rose shadow-brand-rose/20'}`}>
                <i className="fa-solid fa-hands-praying"></i>
                Iniciar Oração por {selectedChild.name.split(' ')[0]}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default FilhosView;

