            <div className="text-center">
              <h3 className={`serif-font text-2xl font-bold ${selectedChild?.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary'}`}>Nova Intercessão</h3>
              <p className="text-xs text-gray-400 mt-1">Coloque o clamor no altar do Senhor.</p>
            </div>

            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase ml-2 tracking-widest">Qual o motivo?</label>
                <textarea 
                  placeholder="Ex: Sabedoria nos estudos, proteção..." 
                  value={newReqText}
                  onChange={(e) => setNewReqText(e.target.value)}
                  className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary h-28 resize-none shadow-inner" 
                />
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase ml-2 tracking-widest">Versículo da Promessa</label>
                <input 
                  type="text" 
                  placeholder="Ex: Filipenses 4:13" 
                  value={newReqVerse}
                  onChange={(e) => setNewReqVerse(e.target.value)}
                  className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner" 
                />
              </div>
            </div>

            <div className="flex gap-4 pt-2">
              <button 
                onClick={() => { setShowAddRequestModal(false); resetRequestForm(); }} 
                className="flex-1 py-4 bg-gray-100 text-gray-500 rounded-full text-xs font-black uppercase tracking-widest"
              >
                Cancelar
              </button>
              <button 
                onClick={handleAddRequest} 
                className={`flex-1 py-4 text-white rounded-full text-xs font-black uppercase tracking-widest shadow-lg active:scale-95 ${selectedChild?.type === 'geracao_compromisso' ? 'bg-brand-gc shadow-brand-gc/20' : 'gradient-brand shadow-brand-primary/20'}`}
              >
                Salvar
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Add Child Modal */}
      {showAddModal && (
        <div className="fixed inset-0 bg-black/70 z-[60] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 space-y-6 animate-fadeIn overflow-y-auto max-h-[90vh] no-scrollbar shadow-2xl">
            <div className="text-center">
              <h3 className="serif-font text-2xl font-bold text-brand-dark">Novo Filho de Oração</h3>
              <p className="text-xs text-gray-400 mt-1">Cobrindo um jovem com intercessão.</p>
            </div>

            <div className="space-y-4">
              <div className="flex flex-col items-center gap-3 mb-4">
                <div 
                  onClick={() => fileInputRef.current?.click()}
                  className="w-32 h-32 rounded-3xl bg-brand-soft border-2 border-dashed border-brand-primary/30 flex flex-col items-center justify-center cursor-pointer overflow-hidden relative group shadow-sm"
                >
                  {newPhoto ? (
                    <img src={newPhoto} alt="Preview" className="w-full h-full object-cover" />
                  ) : (
                    <div className="flex flex-col items-center text-center px-4">
                      <i className="fa-solid fa-camera text-brand-primary text-3xl mb-2 opacity-50"></i>
                      <span className="text-[10px] font-black text-brand-primary/50 uppercase tracking-widest">Toque para adicionar foto</span>
                    </div>
                  )}
                  <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                    <i className="fa-solid fa-camera text-white text-xl"></i>
                  </div>
                </div>
                <input 
                  type="file" 
                  ref={fileInputRef} 
                  onChange={handlePhotoUpload} 
                  accept="image/*" 
                  className="hidden" 
                />
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black text-brand-primary uppercase ml-2 tracking-widest">Nome Completo</label>
                <input 
                  type="text" 
                  placeholder="Nome do jovem" 
                  value={newName}
                  onChange={(e) => setNewName(e.target.value)}
                  className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner" 
                />
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black text-brand-primary uppercase ml-2 tracking-widest">WhatsApp</label>
                <input 
                  type="tel" 
                  placeholder="Ex: 41999999999" 
                  value={newWhatsapp}
                  onChange={(e) => setNewWhatsapp(e.target.value)}
                  className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner" 
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-brand-primary uppercase ml-2 tracking-widest">Vínculo</label>
                  <select 
                    value={newType}
                    onChange={(e) => setNewType(e.target.value as any)}
                    className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner appearance-none"
                  >
                    <option value="biologico">Biológico</option>
                    <option value="espiritual">Espiritual</option>
                    <option value="adotivo">Adotivo</option>
                    <option value="geracao_compromisso">Geração Compromisso</option>
                  </select>
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-brand-primary uppercase ml-2 tracking-widest">Nascimento</label>
                  <input 
                    type="date" 
                    value={newBirthDate}
                    onChange={(e) => setNewBirthDate(e.target.value)}
                    className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner" 
                  />
                </div>
              </div>
            </div>

            <div className="flex gap-4 pt-4">
              <button 
                onClick={() => { setShowAddModal(false); resetChildForm(); }} 
                className="flex-1 py-4 bg-gray-100 text-gray-500 rounded-full text-xs font-black uppercase tracking-widest"
              >
                Cancelar
              </button>
              <button 
                onClick={handleSaveChild} 
                className="flex-1 py-4 gradient-brand text-white rounded-full text-xs font-black uppercase tracking-widest shadow-xl active:scale-95"
              >
                Salvar
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

