import React, { useMemo } from 'react';
import { UserStats, PrayerRequest } from '../types';
import { INSTITUTIONAL, IMAGENS } from '../constants';

interface HomeProps {
  stats: UserStats;
  prayers: PrayerRequest[];
  onNavigate: (tab: string) => void;
}

const HomeView: React.FC<HomeProps> = ({ stats, prayers, onNavigate }) => {
  const featuredPrayer = useMemo(() => {
    const unprayed = prayers.filter(p => !p.isPrayed);
    return unprayed.length > 0 ? unprayed[Math.floor(Math.random() * unprayed.length)] : prayers[0];
  }, [prayers]);

  return (
    <div className="space-y-6 animate-fadeIn pb-10">
      {/* Featured Verse Card */}
      <section 
        onClick={() => onNavigate('prayers')}
        className="gradient-female rounded-[2.5rem] p-8 shadow-md border border-brand-pink relative overflow-hidden cursor-pointer active:scale-[0.98] transition-transform"
      >
        <div className="relative z-10">
          <span className="text-[10px] font-black text-brand-rose uppercase tracking-[0.2em] mb-3 block">Palavra de Hoje</span>
          <h2 className="serif-font text-2xl font-bold text-brand-dark mb-5 leading-snug">
            "{featuredPrayer.verse}"
          </h2>
          <div className="flex items-center gap-3">
            <div className="h-0.5 w-8 bg-brand-rose/40"></div>
            <p className="text-xs font-bold text-brand-rose/80 uppercase tracking-tighter">Intercedendo por: {featuredPrayer.title}</p>
          </div>
        </div>
        <i className="fa-solid fa-quote-right absolute -right-6 -bottom-6 text-brand-rose/5 text-9xl"></i>
      </section>

      {/* Dashboard Stats */}
      <section className="grid grid-cols-2 gap-4">
        <StatCard 
          icon="fa-fire-flame-curved" 
          label="Ofensiva" 
          value={`${stats.streak} dias`} 
          color="text-brand-primary" 
          bgColor="bg-brand-soft" 
        />
        <StatCard 
          icon="fa-clock-rotate-left" 
          label="Minutos" 
          value={stats.totalMinutes} 
          color="text-brand-rose" 
          bgColor="bg-brand-pink" 
        />
        <StatCard 
          icon="fa-calendar-check" 
          label="Dias Totais" 
          value={stats.totalDays} 
          color="text-brand-dark" 
          bgColor="bg-gray-100" 
        />
        <StatCard 
          icon="fa-trophy" 
          label="Troféu" 
          value={stats.hasDailyTrophy ? "Conquistado" : "Pendente"} 
          color={stats.hasDailyTrophy ? "text-brand-accent" : "text-gray-400"} 
          bgColor={stats.hasDailyTrophy ? "bg-yellow-50" : "bg-gray-100"} 
        />
      </section>

      {/* Geração Compromisso Callout */}
      <section className="bg-brand-gc rounded-[2rem] p-6 text-white flex items-center justify-between shadow-xl shadow-brand-gc/20 relative overflow-hidden">
        <div className="relative z-10 space-y-1">
          <h3 className="font-bold text-lg leading-tight">Geração<br/>Compromisso</h3>
          <p className="text-[10px] uppercase font-black tracking-widest text-brand-pink/60">Cobertura de oração</p>
        </div>
        <div className="relative z-10 flex items-center gap-3">
          <div className="w-14 h-14 bg-white p-1.5 rounded-2xl flex items-center justify-center shadow-lg">
            <img 
              src={IMAGENS.logoGC} 
              alt="Logo Geração Compromisso" 
              className="w-full h-full object-contain"
            />
          </div>

          <button 
            onClick={() => onNavigate('filhos')} 
            className="bg-white text-brand-gc px-5 py-2.5 rounded-full text-[10px] font-black shadow-lg active:scale-95 transition-transform uppercase tracking-widest"
          >
            Ver Filhos
          </button>
        </div>
        <div className="absolute -right-6 -bottom-6 w-24 h-24 bg-white/5 rounded-full blur-2xl"></div>
      </section>

      {/* Mission & Vision Section */}
      <section className="pt-8 pb-12 border-t border-brand-border/40 flex flex-col items-center text-center">
        <div className="w-24 h-24 mb-6 transition-transform hover:rotate-3">
          <img src={INSTITUTIONAL.logoUrl} alt="DD Institutional" className="w-full h-full object-contain" />
        </div>
        <p className="calligraphy-font text-3xl text-brand-rose mb-8">
          "{INSTITUTIONAL.slogan}"
        </p>

        <div className="space-y-10 px-4">
            <div>
                <h4 className="text-[10px] font-black uppercase tracking-[0.3em] text-brand-rose mb-4 opacity-60">Nossa Visão</h4>
                <p className="text-sm text-gray-600 italic leading-relaxed font-medium">
                    "{INSTITUTIONAL.vision}"
                </p>
            </div>

            <div className="p-8 bg-brand-lavender/50 rounded-[2.5rem] w-full border border-brand-lavender relative">
                <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-white px-6 py-1 rounded-full border border-brand-lavender shadow-sm">
                    <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-brand-rose">Nossa Missão</h4>
                </div>
                <p className="text-sm text-gray-600 leading-relaxed font-medium">
                    {INSTITUTIONAL.mission}
                </p>
            </div>
        </div>

        {/* MPC Credit Footer */}
        <div className="mt-14 px-8 py-6 border-t border-brand-lavender/30 w-full">
          <p className="text-[9px] text-gray-400 leading-relaxed font-black uppercase tracking-widest italic opacity-60">
            {INSTITUTIONAL.mpcCredit}
          </p>
        </div>
      </section>
    </div>
  );
};

const StatCard = ({ icon, label, value, color, bgColor }: any) => (
  <div className={`${bgColor} p-5 rounded-[2rem] flex flex-col items-center justify-center text-center space-y-3 border border-white/50 shadow-sm transition-all hover:shadow-md hover:scale-[1.02] active:scale-[0.98]`}>
    <i className={`fa-solid ${icon} ${color} text-2xl opacity-80`}></i>
    <div>
      <p className="text-[9px] uppercase font-black text-gray-400 tracking-widest mb-1">{label}</p>
      <p className={`font-black text-base ${color} tracking-tighter`}>{value}</p>
    </div>
  </div>
);

export default HomeView;

