        notes: 'Solicitou cobertura de oração através do site oficial do Despertar de Débora.',
        startDate: new Date().toISOString(),
        prayerMinutes: 0,
        individualRequests: [
          {
            id: 'web-req-1',
            request: 'Fortalecimento na fé e discernimento vocacional',
            status: 'em_oracao',
            createdAt: new Date().toISOString()
          }
        ]
      };
      setPendingChildren([websiteChild]);
    }, 5000);

    return () => clearTimeout(arrivalTimer);
  }, [isLoading]);

  // Initial data
  useEffect(() => {
    const threeDaysAgo = new Date();
    threeDaysAgo.setDate(threeDaysAgo.getDate() - 4);

    setChildren([
      {
        id: '1',
        name: 'Mateus Oliveira',
        type: 'biologico',
        birthDate: '2010-08-15',
        location: 'Curitiba, PR',
        photo: 'https://images.unsplash.com/photo-1519238263530-99bdd11df2ea?w=400&h=400&fit=crop',
        notes: 'Mateus está na fase dos desafios da adolescência.',
        startDate: '2023-01-01',
        prayerMinutes: 120,
        individualRequests: [
          { 
            id: 'r1', 
            request: 'Sabedoria nos estudos', 
            status: 'em_oracao', 
            createdAt: threeDaysAgo.toISOString() 
          },
          { 
            id: 'r2', 
            request: 'Proteção contra más amizades', 
            status: 'em_oracao', 
            createdAt: new Date().toISOString() 
          }
        ]
      }
    ]);
  }, []);

  if (isLoading) {
    return (
      <div className="fixed inset-0 bg-brand-lavender flex flex-col items-center justify-center z-[100] animate-fadeIn px-8">
        <div className="w-64 mb-10 transition-all duration-700 animate-pulse">
          <img src={INSTITUTIONAL.logoUrl} alt="Logo" className="w-full h-auto drop-shadow-xl" />
        </div>
        <div className="flex flex-col items-center gap-2">
          <div className="w-14 h-14 border-4 border-brand-rose border-t-transparent rounded-full animate-spin"></div>
          <p className="text-brand-rose text-[10px] font-black uppercase tracking-[0.4em] mt-8 opacity-70">Despertando o Altar...</p>
        </div>
        <p className="absolute bottom-12 calligraphy-font text-2xl text-brand-dark/40 italic">"Mães de joelhos, filhos de pé!"</p>
      </div>
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'home':
        return <HomeView stats={stats} prayers={prayers} onNavigate={setActiveTab} />;
      case 'prayers':
        return <PrayersView prayers={prayers} setPrayers={setPrayers} />;
      case 'filhos':
        return <FilhosView 
          children={children} 
          setChildren={setChildren} 
          pendingChildren={pendingChildren}
          setPendingChildren={setPendingChildren}
        />;
      case 'community':
        return <CommunityView />;
      case 'timer':
        return <TimerView stats={stats} setStats={setStats} onFinish={() => setActiveTab('home')} />;
      case 'profile':
        return <ProfileView profile={profile} stats={stats} />;
      default:
        return <HomeView stats={stats} prayers={prayers} onNavigate={setActiveTab} />;
    }
  };

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab} hasPending={pendingChildren.length > 0}>
      <div className="pb-10">
        {renderContent()}
      </div>
    </Layout>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { ChildOfPrayer, ChildPrayerRequest } from '../types';
import { INSTITUTIONAL, IMAGENS } from '../constants';

interface FilhosProps {
  children: ChildOfPrayer[];
  setChildren: React.Dispatch<React.SetStateAction<ChildOfPrayer[]>>;
  pendingChildren?: ChildOfPrayer[];
  setPendingChildren?: React.Dispatch<React.SetStateAction<ChildOfPrayer[]>>;
}

const LogoGC = () => (
  <img 
    src={IMAGENS.logoGC} 
    alt="Logo Geração Compromisso" 
    className="w-32 h-auto object-contain grayscale opacity-50 hover:grayscale-0 hover:opacity-100 transition-all duration-500" 
  />
);

const FilhosView: React.FC<FilhosProps> = ({ children, setChildren, pendingChildren = [], setPendingChildren }) => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [showAddRequestModal, setShowAddRequestModal] = useState(false);
  const [selectedChild, setSelectedChild] = useState<ChildOfPrayer | null>(null);
  const [viewMode, setViewMode] = useState<'list' | 'card'>('list');

  // Form State for Child (used for Add and Edit)
  const [newName, setNewName] = useState('');
  const [newType, setNewType] = useState<ChildOfPrayer['type']>('biologico');
  const [newBirthDate, setNewBirthDate] = useState('');
  const [newLocation, setNewLocation] = useState('');
  const [newPhoto, setNewPhoto] = useState<string | undefined>(undefined);
  const [newWhatsapp, setNewWhatsapp] = useState('');

  // Form State for Request
  const [newReqText, setNewReqText] = useState('');
  const [newReqVerse, setNewReqVerse] = useState('');
  const [newReqStatus, setNewReqStatus] = useState<'em_oracao' | 'respondido'>('em_oracao');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const editFileInputRef = useRef<HTMLInputElement>(null);

  // Máscara para WhatsApp: (XX) XXXXX-XXXX
  const formatPhoneNumber = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 11) {
      return numbers
        .replace(/^(\d{2})(\d)/g, '($1) $2')
        .replace(/(\d{5})(\d)/, '$1-$2');
    }
    return numbers.slice(0, 11)
      .replace(/^(\d{2})(\d)/g, '($1) $2')
      .replace(/(\d{5})(\d)/, '$1-$2');
  };

  const handleWhatsappChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const formatted = formatPhoneNumber(e.target.value);
    setNewWhatsapp(formatted);
  };

  const calculateAge = (birthDate: string) => {
    if (!birthDate) return 0;
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) age--;
    return age;
  };

  const isStale = (child: ChildOfPrayer) => {
    const now = new Date();
    return child.individualRequests.some(req => {
      if (req.status !== 'em_oracao') return false;
      const created = new Date(req.createdAt);
      const diffDays = (now.getTime() - created.getTime()) / (1000 * 3600 * 24);
      return diffDays >= 3;
    });
  };

  const getSeloStyles = (type: string) => {
    switch (type) {
      case 'geracao_compromisso': return 'bg-brand-gc text-white border-brand-gc';
      case 'biologico': return 'bg-brand-primary/10 text-brand-primary border-brand-primary/20';
      case 'espiritual': return 'bg-brand-secondary/10 text-brand-secondary border-brand-secondary/20';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  const getLabel = (type: string) => {
    switch (type) {
      case 'geracao_compromisso': return 'GC';
      case 'biologico': return 'Biológico';
      case 'espiritual': return 'Espiritual';
      case 'adotivo': return 'Adotivo';
      default: return type;
    }
  };

  const handleAcceptPending = (pending: ChildOfPrayer) => {
    setChildren(prev => [pending, ...prev]);
    if (setPendingChildren) {
      setPendingChildren(prev => prev.filter(p => p.id !== pending.id));
    }
  };

  const handleDeclinePending = (id: string) => {
    if (setPendingChildren) {
      setPendingChildren(prev => prev.filter(p => p.id !== id));
    }
  };

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>, isEdit = false) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setNewPhoto(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSaveChild = () => {
    if (!newName || !newBirthDate) {
      alert("Por favor, preencha o nome e a data de nascimento.");
      return;
    }

    const newChild: ChildOfPrayer = {
      id: Date.now().toString(),
      name: newName,
      type: newType,
      birthDate: newBirthDate,
      location: newLocation || 'Não informada',
      photo: newPhoto,
      whatsapp: newWhatsapp,
      notes: '',
      startDate: new Date().toISOString(),
      prayerMinutes: 0,
      individualRequests: []
    };

    setChildren(prev => [newChild, ...prev]);
    resetChildForm();
    setShowAddModal(false);
  };

  const handleOpenEdit = () => {
    if (!selectedChild) return;
    setNewName(selectedChild.name);
    setNewType(selectedChild.type);
    setNewBirthDate(selectedChild.birthDate);
    setNewLocation(selectedChild.location);
    setNewPhoto(selectedChild.photo);
    setNewWhatsapp(selectedChild.whatsapp || '');
    setShowEditModal(true);
  };

  const handleUpdateChild = () => {
    if (!selectedChild || !newName || !newBirthDate) {
      alert("Por favor, preencha o nome e a data de nascimento.");
      return;
    }

    const updatedChild: ChildOfPrayer = {
      ...selectedChild,
      name: newName,
      type: newType,
      birthDate: newBirthDate,
      location: newLocation,
      photo: newPhoto,
      whatsapp: newWhatsapp,
    };

    setChildren(prev => prev.map(c => c.id === selectedChild.id ? updatedChild : c));
    setSelectedChild(updatedChild);
    resetChildForm();
    setShowEditModal(false);
  };

  const handleAddRequest = () => {
    if (!selectedChild || !newReqText) {
      alert("Por favor, informe o motivo da oração.");
      return;
    }

    const newReq: ChildPrayerRequest = {
      id: Date.now().toString(),
      request: newReqText,
      verse: newReqVerse,
      status: newReqStatus,
      createdAt: new Date().toISOString(),
    };

    setChildren(prev => {
      const updated = prev.map(child => {
        if (child.id === selectedChild.id) {
          const updatedChild = {
            ...child,
            individualRequests: [...child.individualRequests, newReq]
          };
          setSelectedChild(updatedChild);
          return updatedChild;
        }
        return child;
      });
      return updated;
    });

    resetRequestForm();
    setShowAddRequestModal(false);
  };

  const toggleRequestStatus = (requestId: string) => {
    if (!selectedChild) return;

    setChildren(prev => {
      const updated = prev.map(child => {
        if (child.id === selectedChild.id) {
          const updatedRequests = child.individualRequests.map(req => {
            if (req.id === requestId) {
              return { ...req, status: req.status === 'em_oracao' ? 'respondido' : 'em_oracao' as any };
            }
            return req;
          });
          const updatedChild = { ...child, individualRequests: updatedRequests };
          setSelectedChild(updatedChild);
          return updatedChild;
        }
        return child;
      });
      return updated;
    });
  };

  const handleSendWhatsapp = (child: ChildOfPrayer) => {
    if (!child.whatsapp) {
      alert("Número de WhatsApp não cadastrado para este filho.");
      return;
    }
    const cleanNumber = child.whatsapp.replace(/\D/g, '');
    const message = encodeURIComponent(`Olá, estou orando por você agora mesmo`);
    window.open(`https://wa.me/55${cleanNumber}?text=${message}`, '_blank');
  };

  const resetChildForm = () => {
    setNewName('');
    setNewType('biologico');
    setNewBirthDate('');
    setNewLocation('');
    setNewPhoto(undefined);
    setNewWhatsapp('');
  };

  const resetRequestForm = () => {
    setNewReqText('');
    setNewReqVerse('');
    setNewReqStatus('em_oracao');
  };

  return (
    <div className="space-y-6 pb-20">
      <div className="flex items-center justify-between">
        <h2 className="serif-font text-2xl font-bold text-brand-dark">Filhos de Oração</h2>
        <div className="flex items-center gap-3">
          <div className="bg-brand-soft p-1 rounded-xl flex items-center border border-brand-border">
            <button 
              onClick={() => setViewMode('list')}
              className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all ${viewMode === 'list' ? 'bg-white text-brand-primary shadow-sm' : 'text-gray-400'}`}
            >
              <i className="fa-solid fa-list-ul text-xs"></i>
            </button>
            <button 
              onClick={() => setViewMode('card')}
              className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all ${viewMode === 'card' ? 'bg-white text-brand-primary shadow-sm' : 'text-gray-400'}`}
            >
              <i className="fa-solid fa-grip text-xs"></i>
            </button>
          </div>
          <button 
            onClick={() => setShowAddModal(true)}
            className="bg-brand-gc text-white w-10 h-10 rounded-full flex items-center justify-center shadow-lg active:scale-90 transition-transform"
          >
            <i className="fa-solid fa-plus"></i>
          </button>
        </div>
      </div>

      {/* Pending Arrivals Section */}
      {pendingChildren.length > 0 && (
        <section className="space-y-3 animate-fadeIn">
          <div className="flex items-center gap-2 px-1">
            <span className="relative flex h-2 w-2">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-brand-gc opacity-75"></span>
              <span className="relative inline-flex rounded-full h-2 w-2 bg-brand-gc"></span>
            </span>
            <h3 className="text-[10px] font-black uppercase text-brand-gc tracking-[0.2em]">Novas Solicitações (Web)</h3>
          </div>
          <div className="space-y-3">
            {pendingChildren.map(pending => (
              <div key={pending.id} className="bg-white rounded-3xl p-4 border-2 border-brand-gc/20 shadow-lg shadow-brand-gc/5 flex flex-col gap-4">
                <div className="flex gap-4">
                  <div className="w-16 h-16 rounded-2xl overflow-hidden border border-brand-gc/30">
                    <img src={pending.photo} className="w-full h-full object-cover" alt={pending.name} />
                  </div>
                  <div className="flex-1">
                    <div className="flex justify-between">
                      <h4 className="font-black text-brand-dark">{pending.name}</h4>
                      <span className="bg-brand-gc text-white text-[8px] font-black px-2 py-0.5 rounded-full uppercase">Geração Compromisso</span>
                    </div>
                    <p className="text-[10px] text-gray-500 mt-1 line-clamp-2 italic">"{pending.notes}"</p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button 
                    onClick={() => handleAcceptPending(pending)}
                    className="flex-1 bg-brand-gc text-white py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest active:scale-[0.98]"
                  >
                    Aceitar Cobertura
                  </button>
                  <button 
                    onClick={() => handleDeclinePending(pending.id)}
                    className="px-4 bg-gray-100 text-gray-400 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest active:scale-[0.98]"
                  >
                    Ignorar
                  </button>
                </div>
              </div>
            ))}
          </div>
        </section>
      )}

      {/* Intro Box with Base64 Logo */}
      <div className="bg-brand-gc text-white p-5 rounded-3xl border border-white/20 relative overflow-hidden shadow-inner">
        <div className="relative z-10 flex gap-4 items-center">
            <div className="w-12 h-12 bg-white p-2 rounded-xl shadow-lg flex-shrink-0">
                <img 
                  src={IMAGENS.logoGC} 
                  alt="Geração Compromisso" 
                  className="w-full h-full object-contain" 
                />
            </div>
            <p className="text-[11px] font-semibold leading-snug opacity-95 italic">
                "Aqui você acompanha os filhos que Deus confiou a você para interceder, formando uma Geração Compromisso sólida e fiel."
            </p>
        </div>
        <div className="absolute -right-4 -bottom-4 w-16 h-16 bg-white/5 rounded-full blur-xl"></div>
      </div>

      {/* Children List/Grid */}
      <div className={viewMode === 'list' ? "grid grid-cols-1 gap-4" : "grid grid-cols-2 gap-4"}>
        {children.length > 0 ? (
          children.map(child => {
            const stale = isStale(child);
            return viewMode === 'list' ? (
              <div 
                key={child.id} 
                className={`bg-white rounded-3xl p-4 border shadow-sm flex gap-4 cursor-pointer hover:shadow-md transition-shadow active:scale-[0.99] animate-fadeIn relative ${stale ? 'border-orange-300 ring-1 ring-orange-100 shadow-orange-50' : (child.type === 'geracao_compromisso' ? 'border-brand-gc/30' : 'border-brand-border')}`}
              >
                {stale && <div className="absolute -top-1 -left-1 bg-orange-500 text-white text-[8px] font-black px-2 py-0.5 rounded-full shadow-sm animate-pulse z-10">URGENTE</div>}
                <div onClick={() => setSelectedChild(child)} className="w-20 h-20 rounded-2xl overflow-hidden flex-shrink-0 bg-brand-soft border border-brand-border relative shadow-sm">
                  <img 
                      src={child.photo || `https://picsum.photos/seed/${child.id}/200`} 
                      alt={child.name} 
                      className="w-full h-full object-cover" 
                  />
                </div>
                <div className="flex-1 space-y-2">
                  <div className="flex justify-between items-start" onClick={() => setSelectedChild(child)}>
                    <h3 className="font-bold text-brand-dark line-clamp-1">{child.name}</h3>
                    <span className={`text-[8px] uppercase font-black px-2 py-0.5 rounded-full border tracking-tighter ${getSeloStyles(child.type)}`}>
                      {getLabel(child.type)}
                    </span>
                  </div>
                  <div className="flex items-center gap-3">
                    <p className="text-xs text-gray-500">
                      <i className="fa-solid fa-cake-candles mr-1 opacity-60"></i> {calculateAge(child.birthDate)} anos
                    </p>
                    {child.whatsapp && (
                      <button 
                        onClick={(e) => { e.stopPropagation(); handleSendWhatsapp(child); }}
                        className="text-green-500 hover:text-green-600 active:scale-90 transition-all flex items-center gap-1.5 bg-green-50 px-2 py-1 rounded-lg border border-green-100"
                      >
                        <i className="fa-brands fa-whatsapp text-sm"></i>
                        <span className="text-[9px] font-black uppercase">Avisar</span>
                      </button>
                    )}
                  </div>
                  <div className="flex items-center justify-between pt-1" onClick={() => setSelectedChild(child)}>
                    <div className="flex items-center gap-2">
                      <i className={`fa-solid fa-hands-praying text-xs ${stale ? 'text-orange-500' : (child.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary')}`}></i>
                      <span className="text-[10px] text-gray-400 font-medium">
                        {child.individualRequests.filter(r => r.status === 'em_oracao').length} clamores
                      </span>
                    </div>
                    <div className={`flex items-center gap-1.5 px-2 py-0.5 rounded-full ${child.type === 'geracao_compromisso' ? 'bg-brand-gc/10' : 'bg-brand-soft'}`}>
                      <i className={`fa-solid fa-clock text-[10px] ${child.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary'}`}></i>
                      <span className={`text-[10px] font-black ${child.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary'}`}>{child.prayerMinutes}m</span>
                    </div>
                  </div>
                </div>
              </div>
            ) : (
              <div 
                key={child.id} 
                className={`bg-white rounded-[2rem] p-3 border shadow-sm cursor-pointer hover:shadow-md transition-all active:scale-[0.97] animate-fadeIn relative overflow-hidden group ${stale ? 'border-orange-300 ring-1 ring-orange-100' : (child.type === 'geracao_compromisso' ? 'border-brand-gc/30' : 'border-brand-border')}`}
              >
                {stale && <div className="absolute top-2 left-2 bg-orange-500 text-white text-[7px] font-black px-2 py-1 rounded-lg z-10 shadow-lg animate-pulse">PRECISA DE ATENÇÃO</div>}
                <div onClick={() => setSelectedChild(child)} className="aspect-square w-full rounded-[1.5rem] overflow-hidden mb-3 bg-brand-soft relative">
                  <img 
                      src={child.photo || `https://picsum.photos/seed/${child.id}/200`} 
                      alt={child.name} 
                      className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" 
                  />
                  <div className="absolute top-2 right-2">
                    <span className={`text-[7px] uppercase font-black px-2 py-1 rounded-lg border shadow-sm backdrop-blur-md ${getSeloStyles(child.type)}`}>
                      {getLabel(child.type)}
                    </span>
                  </div>
                </div>
                <div className="px-1 pb-1 text-center" onClick={() => setSelectedChild(child)}>
                  <h3 className="font-bold text-brand-dark text-sm line-clamp-1 mb-1">{child.name}</h3>
                  <div className="flex items-center justify-center gap-2 text-[10px] text-gray-400 font-medium">
                    <span>{calculateAge(child.birthDate)} anos</span>
                    <span>•</span>
                    <span className={`${child.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary'} font-black`}>{child.prayerMinutes}m</span>
                  </div>
                </div>
                {child.whatsapp && (
                  <button 
                    onClick={(e) => { e.stopPropagation(); handleSendWhatsapp(child); }}
                    className="absolute bottom-3 right-3 w-8 h-8 bg-green-500 text-white rounded-full flex items-center justify-center shadow-md active:scale-90 transition-transform"
                  >
                    <i className="fa-brands fa-whatsapp"></i>
                  </button>
                )}
              </div>
            );
          })
        ) : (
          <div className="col-span-full text-center py-24 text-gray-400">
            <i className="fa-solid fa-users-rays text-6xl mb-6 opacity-20"></i>
            <p className="text-sm font-medium">Sua lista de intercessão está vazia.</p>
            <p className="text-xs mt-1">Toque no + para começar a cadastrar seus filhos.</p>
          </div>
        )}
      </div>

      {/* Detail Modal */}
      {selectedChild && (
        <div className="fixed inset-0 bg-black/60 z-[60] flex items-end sm:items-center justify-center p-0 sm:p-4">
          <div className="bg-white w-full max-w-lg rounded-t-[2.5rem] sm:rounded-3xl p-6 animate-slideUp overflow-y-auto max-h-[95vh] no-scrollbar">
            <div className="w-12 h-1.5 bg-gray-200 rounded-full mx-auto mb-6 sm:hidden"></div>

            <div className="flex justify-between items-start mb-6">
              <div className="flex items-center gap-4">
                <div className={`w-20 h-20 rounded-2xl overflow-hidden border-2 shadow-sm ${selectedChild.type === 'geracao_compromisso' ? 'border-brand-gc' : 'border-brand-primary'}`}>
                  <img src={selectedChild.photo || `https://picsum.photos/seed/${selectedChild.id}/200`} className="w-full h-full object-cover" alt={selectedChild.name} />
                </div>
                <div className="space-y-1">
                  <h3 className="text-xl font-bold text-brand-dark leading-tight">{selectedChild.name}</h3>
                  <p className={`text-[10px] font-black uppercase tracking-wider ${selectedChild.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary'}`}>{selectedChild.type.replace('_', ' ')}</p>
                </div>
              </div>
              <div className="flex gap-2">
                <button 
                  onClick={handleOpenEdit}
                  className="w-10 h-10 rounded-full bg-brand-soft text-brand-primary flex items-center justify-center active:scale-90 transition-transform shadow-sm"
