              )}

              <section>
                <div className="flex items-center justify-between mb-4">
                  <h4 className={`text-xs font-black uppercase tracking-widest flex items-center gap-2 ${selectedChild.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary'}`}>
                    <i className="fa-solid fa-heart-pulse"></i>
                    Pedidos de Oração
                  </h4>
                  <button 
                    onClick={() => setShowAddRequestModal(true)}
                    className={`text-[10px] font-black uppercase px-4 py-1.5 rounded-full transition-all active:scale-95 ${selectedChild.type === 'geracao_compromisso' ? 'bg-brand-gc text-white shadow-md shadow-brand-gc/20' : 'bg-brand-primary text-white shadow-md shadow-brand-primary/20'}`}
                  >
                    + Novo Pedido
                  </button>
                </div>

                <div className="space-y-3">
                  {selectedChild.individualRequests.length > 0 ? (
                    selectedChild.individualRequests.map(req => {
                      const reqDays = Math.floor((new Date().getTime() - new Date(req.createdAt).getTime()) / (1000 * 3600 * 24));
                      const staleReq = req.status === 'em_oracao' && reqDays >= 3;
                      return (
                        <div key={req.id} className={`p-4 rounded-2xl border space-y-3 shadow-sm transition-all ${staleReq ? 'bg-orange-50 border-orange-200' : 'bg-brand-cream/50 border-brand-border/40'}`}>
                          <div className="flex items-start justify-between gap-4">
                            <div className="flex-1 space-y-1">
                              <span className="text-sm font-bold text-gray-800 leading-snug block">{req.request}</span>
                              {staleReq && <span className="text-[9px] text-orange-600 font-black uppercase">Pendente há {reqDays} dias</span>}
                            </div>
                            <button 
                              onClick={() => toggleRequestStatus(req.id)}
                              className={`text-[8px] font-black uppercase px-2 py-1 rounded-full whitespace-nowrap transition-all active:scale-90 ${req.status === 'em_oracao' ? 'bg-orange-100 text-orange-700' : 'bg-green-100 text-green-700'}`}
                            >
                              {req.status === 'em_oracao' ? 'Em Oração' : 'Respondido'}
                            </button>
                          </div>
                          {req.verse && (
                            <p className="text-[11px] text-brand-primary/80 font-medium italic bg-white/60 p-2 rounded-lg border border-brand-border/20">
                              <i className="fa-solid fa-book-bible mr-1.5"></i> "{req.verse}"
