                onClick={() => { setShowAddModal(false); setShowEditModal(false); resetChildForm(); }} 
                className="flex-1 py-4 bg-gray-100 text-gray-500 rounded-full text-xs font-black uppercase tracking-widest"
              >
                Cancelar
              </button>
              <button 
                onClick={showEditModal ? handleUpdateChild : handleSaveChild} 
                className="flex-1 py-4 gradient-brand text-white rounded-full text-xs font-black uppercase tracking-widest shadow-xl active:scale-95"
              >
                {showEditModal ? 'Salvar Alterações' : 'Salvar'}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Footer Logo Requested */}
      <div className="mt-20 flex justify-center opacity-70">
        <LogoGC />
      </div>
    </div>
  );
};

