import React, { useState, useRef } from 'react';
import { ChildOfPrayer, ChildPrayerRequest } from '../types';
import { INSTITUTIONAL, IMAGENS } from '../constants';

interface FilhosProps {
  children: ChildOfPrayer[];
  setChildren: React.Dispatch<React.SetStateAction<ChildOfPrayer[]>>;
  pendingChildren?: ChildOfPrayer[];
  setPendingChildren?: React.Dispatch<React.SetStateAction<ChildOfPrayer[]>>;
}

const FilhosView: React.FC<FilhosProps> = ({ children, setChildren, pendingChildren = [], setPendingChildren }) => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [showAddRequestModal, setShowAddRequestModal] = useState(false);
  const [selectedChild, setSelectedChild] = useState<ChildOfPrayer | null>(null);
  const [viewMode, setViewMode] = useState<'list' | 'card'>('list');

  // Form State for Child (used for Add and Edit)
  const [newName, setNewName] = useState('');
  const [newType, setNewType] = useState<ChildOfPrayer['type']>('biologico');
  const [newBirthDate, setNewBirthDate] = useState('');
  const [newLocation, setNewLocation] = useState('');
  const [newPhoto, setNewPhoto] = useState<string | undefined>(undefined);
  const [newWhatsapp, setNewWhatsapp] = useState('');

  // Form State for Request
  const [newReqText, setNewReqText] = useState('');
  const [newReqVerse, setNewReqVerse] = useState('');
  const [newReqStatus, setNewReqStatus] = useState<'em_oracao' | 'respondido'>('em_oracao');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const editFileInputRef = useRef<HTMLInputElement>(null);

  // Máscara para WhatsApp: (XX) XXXXX-XXXX
  const formatPhoneNumber = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 11) {
      return numbers
        .replace(/^(\d{2})(\d)/g, '($1) $2')
        .replace(/(\d{5})(\d)/, '$1-$2');
    }
    return numbers.slice(0, 11)
      .replace(/^(\d{2})(\d)/g, '($1) $2')
      .replace(/(\d{5})(\d)/, '$1-$2');
  };

  const handleWhatsappChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const formatted = formatPhoneNumber(e.target.value);
    setNewWhatsapp(formatted);
  };

  const calculateAge = (birthDate: string) => {
    if (!birthDate) return 0;
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) age--;
    return age;
  };

  const isStale = (child: ChildOfPrayer) => {
    const now = new Date();
    return child.individualRequests.some(req => {
      if (req.status !== 'em_oracao') return false;
      const created = new Date(req.createdAt);
      const diffDays = (now.getTime() - created.getTime()) / (1000 * 3600 * 24);
      return diffDays >= 3;
    });
  };

  const getSeloStyles = (type: string) => {
    switch (type) {
      case 'geracao_compromisso': return 'bg-brand-gc text-white border-brand-gc';
      case 'biologico': return 'bg-brand-primary/10 text-brand-primary border-brand-primary/20';
      case 'espiritual': return 'bg-brand-secondary/10 text-brand-secondary border-brand-secondary/20';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  const getLabel = (type: string) => {
    switch (type) {
      case 'geracao_compromisso': return 'GC';
      case 'biologico': return 'Biológico';
      case 'espiritual': return 'Espiritual';
      case 'adotivo': return 'Adotivo';
      default: return type;
    }
  };

  const handleAcceptPending = (pending: ChildOfPrayer) => {
    setChildren(prev => [pending, ...prev]);
    if (setPendingChildren) {
      setPendingChildren(prev => prev.filter(p => p.id !== pending.id));
    }
  };

  const handleDeclinePending = (id: string) => {
    if (setPendingChildren) {
      setPendingChildren(prev => prev.filter(p => p.id !== id));
    }
  };

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setNewPhoto(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSaveChild = () => {
    if (!newName || !newBirthDate) {
      alert("Por favor, preencha o nome e a data de nascimento.");
      return;
    }

    const newChild: ChildOfPrayer = {
      id: Date.now().toString(),
      name: newName,
      type: newType,
      birthDate: newBirthDate,
      location: newLocation || 'Não informada',
      photo: newPhoto,
      whatsapp: newWhatsapp,
      notes: '',
      startDate: new Date().toISOString(),
      prayerMinutes: 0,
      individualRequests: []
    };

    setChildren(prev => [newChild, ...prev]);
    resetChildForm();
    setShowAddModal(false);
  };

  const handleOpenEdit = () => {
    if (!selectedChild) return;
    setNewName(selectedChild.name);
    setNewType(selectedChild.type);
    setNewBirthDate(selectedChild.birthDate);
    setNewLocation(selectedChild.location);
    setNewPhoto(selectedChild.photo);
    setNewWhatsapp(selectedChild.whatsapp || '');
    setShowEditModal(true);
  };

  const handleUpdateChild = () => {
    if (!selectedChild || !newName || !newBirthDate) {
      alert("Por favor, preencha o nome e a data de nascimento.");
      return;
    }

    const updatedChild: ChildOfPrayer = {
      ...selectedChild,
      name: newName,
      type: newType,
      birthDate: newBirthDate,
      location: newLocation,
      photo: newPhoto,
      whatsapp: newWhatsapp,
    };

    setChildren(prev => prev.map(c => c.id === selectedChild.id ? updatedChild : c));
    setSelectedChild(updatedChild);
    resetChildForm();
    setShowEditModal(false);
  };

  const handleAddRequest = () => {
    if (!selectedChild || !newReqText) {
      alert("Por favor, informe o motivo da oração.");
      return;
    }

    const newReq: ChildPrayerRequest = {
      id: Date.now().toString(),
      request: newReqText,
      verse: newReqVerse,
      status: newReqStatus,
      createdAt: new Date().toISOString(),
    };

    setChildren(prev => {
      const updated = prev.map(child => {
        if (child.id === selectedChild.id) {
          const updatedChild = {
            ...child,
            individualRequests: [...child.individualRequests, newReq]
          };
          setSelectedChild(updatedChild);
          return updatedChild;
        }
        return child;
      });
      return updated;
    });

    resetRequestForm();
    setShowAddRequestModal(false);
  };

  const toggleRequestStatus = (requestId: string) => {
    if (!selectedChild) return;

    setChildren(prev => {
      const updated = prev.map(child => {
        if (child.id === selectedChild.id) {
          const updatedRequests = child.individualRequests.map(req => {
            if (req.id === requestId) {
              return { ...req, status: req.status === 'em_oracao' ? 'respondido' : 'em_oracao' as any };
            }
            return req;
          });
          const updatedChild = { ...child, individualRequests: updatedRequests };
          setSelectedChild(updatedChild);
          return updatedChild;
        }
        return child;
      });
      return updated;
    });
  };

  const handleSendWhatsapp = (child: ChildOfPrayer) => {
    if (!child.whatsapp) {
      alert("Número de WhatsApp não cadastrado para este filho.");
      return;
    }
    const cleanNumber = child.whatsapp.replace(/\D/g, '');
    const message = encodeURIComponent(`Olá, estou orando por você agora mesmo`);
    window.open(`https://wa.me/55${cleanNumber}?text=${message}`, '_blank');
  };

  const resetChildForm = () => {
    setNewName('');
    setNewType('biologico');
    setNewBirthDate('');
    setNewLocation('');
    setNewPhoto(undefined);
    setNewWhatsapp('');
  };

  const resetRequestForm = () => {
    setNewReqText('');
    setNewReqVerse('');
    setNewReqStatus('em_oracao');
  };

  return (
    <div className="space-y-6 pb-20">
      <div className="flex items-center justify-between">
        <h2 className="serif-font text-2xl font-bold text-brand-dark">Filhos de Oração</h2>
        <div className="flex items-center gap-3">
          <div className="bg-brand-soft p-1 rounded-xl flex items-center border border-brand-border">
            <button 
              onClick={() => setViewMode('list')}
              className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all ${viewMode === 'list' ? 'bg-white text-brand-primary shadow-sm' : 'text-gray-400'}`}
            >
              <i className="fa-solid fa-list-ul text-xs"></i>
            </button>
            <button 
              onClick={() => setViewMode('card')}
              className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all ${viewMode === 'card' ? 'bg-white text-brand-primary shadow-sm' : 'text-gray-400'}`}
            >
              <i className="fa-solid fa-grip text-xs"></i>
            </button>
          </div>
          <button 
            onClick={() => setShowAddModal(true)}
            className="bg-brand-gc text-white w-10 h-10 rounded-full flex items-center justify-center shadow-lg active:scale-90 transition-transform"
          >
            <i className="fa-solid fa-plus"></i>
          </button>
        </div>
      </div>

      {/* Pending Arrivals Section */}
      {pendingChildren.length > 0 && (
        <section className="space-y-3 animate-fadeIn">
          <div className="flex items-center gap-2 px-1">
            <span className="relative flex h-2 w-2">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-brand-gc opacity-75"></span>
              <span className="relative inline-flex rounded-full h-2 w-2 bg-brand-gc"></span>
            </span>
            <h3 className="text-[10px] font-black uppercase text-brand-gc tracking-[0.2em]">Novas Solicitações (Web)</h3>
          </div>
          <div className="space-y-3">
            {pendingChildren.map(pending => (
              <div key={pending.id} className="bg-white rounded-3xl p-4 border-2 border-brand-gc/20 shadow-lg shadow-brand-gc/5 flex flex-col gap-4">
                <div className="flex gap-4">
                  <div className="w-16 h-16 rounded-2xl overflow-hidden border border-brand-gc/30">
                    <img src={pending.photo} className="w-full h-full object-cover" alt={pending.name} />
                  </div>
                  <div className="flex-1">
                    <div className="flex justify-between">
                      <h4 className="font-black text-brand-dark">{pending.name}</h4>
                      <span className="bg-brand-gc text-white text-[8px] font-black px-2 py-0.5 rounded-full uppercase">Geração Compromisso</span>
                    </div>
                    <p className="text-[10px] text-gray-500 mt-1 line-clamp-2 italic">"{pending.notes}"</p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button 
                    onClick={() => handleAcceptPending(pending)}
                    className="flex-1 bg-brand-gc text-white py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest active:scale-[0.98]"
                  >
                    Aceitar Cobertura
                  </button>
                  <button 
                    onClick={() => handleDeclinePending(pending.id)}
                    className="px-4 bg-gray-100 text-gray-400 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest active:scale-[0.98]"
                  >
                    Ignorar
                  </button>
                </div>
              </div>
            ))}
          </div>
        </section>
      )}

      {/* Intro Box */}
      <div className="bg-brand-gc text-white p-5 rounded-3xl border border-white/20 relative overflow-hidden shadow-inner">
        <div className="relative z-10 flex gap-4 items-center">
            <div className="w-10 h-10 bg-white/10 rounded-xl flex items-center justify-center flex-shrink-0">
                <i className="fa-solid fa-hands-praying text-xl"></i>
            </div>
            <p className="text-[11px] font-semibold leading-snug opacity-95 italic">
                "Aqui você acompanha os filhos que Deus confiou a você para interceder, formando uma Geração Compromisso sólida e fiel."
            </p>
        </div>
        <div className="absolute -right-4 -bottom-4 w-16 h-16 bg-white/5 rounded-full blur-xl"></div>
      </div>

      {/* Children List/Grid */}
      <div className={viewMode === 'list' ? "grid grid-cols-1 gap-4" : "grid grid-cols-2 gap-4"}>
        {children.length > 0 ? (
          children.map(child => {
            const stale = isStale(child);
            return viewMode === 'list' ? (
              <div 
                key={child.id} 
                className={`bg-white rounded-3xl p-4 border shadow-sm flex gap-4 cursor-pointer hover:shadow-md transition-shadow active:scale-[0.99] animate-fadeIn relative ${stale ? 'border-orange-300 ring-1 ring-orange-100 shadow-orange-50' : (child.type === 'geracao_compromisso' ? 'border-brand-gc/30' : 'border-brand-border')}`}
              >
                {stale && <div className="absolute -top-1 -left-1 bg-orange-500 text-white text-[8px] font-black px-2 py-0.5 rounded-full shadow-sm animate-pulse z-10">URGENTE</div>}
                <div onClick={() => setSelectedChild(child)} className="w-20 h-20 rounded-2xl overflow-hidden flex-shrink-0 bg-brand-soft border border-brand-border relative shadow-sm">
                  <img 
                      src={child.photo || `https://picsum.photos/seed/${child.id}/200`} 
                      alt={child.name} 
                      className="w-full h-full object-cover" 
                  />
                </div>
                <div className="flex-1 space-y-2">
                  <div className="flex justify-between items-start" onClick={() => setSelectedChild(child)}>
                    <h3 className="font-bold text-brand-dark line-clamp-1">{child.name}</h3>
                    <span className={`text-[8px] uppercase font-black px-2 py-0.5 rounded-full border tracking-tighter ${getSeloStyles(child.type)}`}>
                      {getLabel(child.type)}
                    </span>
                  </div>
                  <div className="flex items-center gap-3">
                    <p className="text-xs text-gray-500">
                      <i className="fa-solid fa-cake-candles mr-1 opacity-60"></i> {calculateAge(child.birthDate)} anos
                    </p>
                    {child.whatsapp && (
                      <button 
                        onClick={(e) => { e.stopPropagation(); handleSendWhatsapp(child); }}
                        className="text-green-500 hover:text-green-600 active:scale-90 transition-all flex items-center gap-1.5 bg-green-50 px-2 py-1 rounded-lg border border-green-100"
                      >
                        <i className="fa-brands fa-whatsapp text-sm"></i>
                        <span className="text-[9px] font-black uppercase">Avisar</span>
                      </button>
                    )}
                  </div>
                  <div className="flex items-center justify-between pt-1" onClick={() => setSelectedChild(child)}>
                    <div className="flex items-center gap-2">
                      <i className={`fa-solid fa-hands-praying text-xs ${stale ? 'text-orange-500' : (child.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary')}`}></i>
                      <span className="text-[10px] text-gray-400 font-medium">
                        {child.individualRequests.filter(r => r.status === 'em_oracao').length} clamores
                      </span>
                    </div>
                    <div className={`flex items-center gap-1.5 px-2 py-0.5 rounded-full ${child.type === 'geracao_compromisso' ? 'bg-brand-gc/10' : 'bg-brand-soft'}`}>
                      <i className={`fa-solid fa-clock text-[10px] ${child.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary'}`}></i>
                      <span className={`text-[10px] font-black ${child.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary'}`}>{child.prayerMinutes}m</span>
                    </div>
                  </div>
                </div>
              </div>
            ) : (
              <div 
                key={child.id} 
                className={`bg-white rounded-[2rem] p-3 border shadow-sm cursor-pointer hover:shadow-md transition-all active:scale-[0.97] animate-fadeIn relative overflow-hidden group ${stale ? 'border-orange-300 ring-1 ring-orange-100' : (child.type === 'geracao_compromisso' ? 'border-brand-gc/30' : 'border-brand-border')}`}
              >
                {stale && <div className="absolute top-2 left-2 bg-orange-500 text-white text-[7px] font-black px-2 py-1 rounded-lg z-10 shadow-lg animate-pulse">PRECISA DE ATENÇÃO</div>}
                <div onClick={() => setSelectedChild(child)} className="aspect-square w-full rounded-[1.5rem] overflow-hidden mb-3 bg-brand-soft relative">
                  <img 
                      src={child.photo || `https://picsum.photos/seed/${child.id}/200`} 
                      alt={child.name} 
                      className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" 
                  />
                  <div className="absolute top-2 right-2">
                    <span className={`text-[7px] uppercase font-black px-2 py-1 rounded-lg border shadow-sm backdrop-blur-md ${getSeloStyles(child.type)}`}>
                      {getLabel(child.type)}
                    </span>
                  </div>
                </div>
                <div className="px-1 pb-1 text-center" onClick={() => setSelectedChild(child)}>
                  <h3 className="font-bold text-brand-dark text-sm line-clamp-1 mb-1">{child.name}</h3>
                  <div className="flex items-center justify-center gap-2 text-[10px] text-gray-400 font-medium">
                    <span>{calculateAge(child.birthDate)} anos</span>
                    <span>•</span>
                    <span className={`${child.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary'} font-black`}>{child.prayerMinutes}m</span>
                  </div>
                </div>
                {child.whatsapp && (
                  <button 
                    onClick={(e) => { e.stopPropagation(); handleSendWhatsapp(child); }}
                    className="absolute bottom-3 right-3 w-8 h-8 bg-green-500 text-white rounded-full flex items-center justify-center shadow-md active:scale-90 transition-transform"
                  >
                    <i className="fa-brands fa-whatsapp"></i>
                  </button>
                )}
              </div>
            );
          })
        ) : (
          <div className="col-span-full text-center py-24 text-gray-400">
            <i className="fa-solid fa-users-rays text-6xl mb-6 opacity-20"></i>
            <p className="text-sm font-medium">Sua lista de intercessão está vazia.</p>
            <p className="text-xs mt-1">Toque no + para começar a cadastrar seus filhos.</p>
          </div>
        )}
      </div>

      {/* Detail Modal */}
      {selectedChild && (
        <div className="fixed inset-0 bg-black/60 z-[60] flex items-end sm:items-center justify-center p-0 sm:p-4">
          <div className="bg-white w-full max-w-lg rounded-t-[2.5rem] sm:rounded-3xl p-6 animate-slideUp overflow-y-auto max-h-[95vh] no-scrollbar">
            <div className="w-12 h-1.5 bg-gray-200 rounded-full mx-auto mb-6 sm:hidden"></div>

            <div className="flex justify-between items-start mb-6">
              <div className="flex items-center gap-4">
                <div className={`w-20 h-20 rounded-2xl overflow-hidden border-2 shadow-sm ${selectedChild.type === 'geracao_compromisso' ? 'border-brand-gc' : 'border-brand-primary'}`}>
                  <img src={selectedChild.photo || `https://picsum.photos/seed/${selectedChild.id}/200`} className="w-full h-full object-cover" alt={selectedChild.name} />
                </div>
                <div className="space-y-1">
                  <h3 className="text-xl font-bold text-brand-dark leading-tight">{selectedChild.name}</h3>
                  <p className={`text-[10px] font-black uppercase tracking-wider ${selectedChild.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary'}`}>{selectedChild.type.replace('_', ' ')}</p>
                </div>
              </div>
              <div className="flex gap-2">
                <button 
                  onClick={handleOpenEdit}
                  className="w-10 h-10 rounded-full bg-brand-soft text-brand-primary flex items-center justify-center active:scale-90 transition-transform shadow-sm"
                  title="Editar informações"
                >
                  <i className="fa-solid fa-pen-to-square"></i>
                </button>
                {selectedChild.whatsapp && (
                  <button 
                    onClick={() => handleSendWhatsapp(selectedChild)}
                    className="w-10 h-10 rounded-full bg-green-500 text-white flex items-center justify-center active:scale-90 transition-transform shadow-md"
                  >
                    <i className="fa-brands fa-whatsapp text-lg"></i>
                  </button>
                )}
                <button onClick={() => setSelectedChild(null)} className="w-10 h-10 rounded-full bg-gray-100 flex items-center justify-center active:bg-gray-200 transition-colors">
                  <i className="fa-solid fa-xmark text-gray-500"></i>
                </button>
              </div>
            </div>

            <div className="space-y-8">
              {/* GC Special Header in Detail Modal */}
              {selectedChild.type === 'geracao_compromisso' && (
                <div className="bg-brand-gc/5 border border-brand-gc/20 rounded-2xl p-4 flex items-center gap-4 animate-fadeIn">
                  <div className="w-10 h-10 bg-brand-gc/10 flex items-center justify-center rounded-lg shadow-sm text-brand-gc">
                    <i className="fa-solid fa-shield-heart"></i>
                  </div>
                  <p className="text-[10px] font-black uppercase text-brand-gc tracking-[0.15em] leading-tight">
                    Membro Coberto pela Geração Compromisso
                  </p>
                </div>
              )}

              <section>
                <div className="flex items-center justify-between mb-4">
                  <h4 className={`text-xs font-black uppercase tracking-widest flex items-center gap-2 ${selectedChild.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary'}`}>
                    <i className="fa-solid fa-heart-pulse"></i>
                    Pedidos de Oração
                  </h4>
                  <button 
                    onClick={() => setShowAddRequestModal(true)}
                    className={`text-[10px] font-black uppercase px-4 py-1.5 rounded-full transition-all active:scale-95 ${selectedChild.type === 'geracao_compromisso' ? 'bg-brand-gc text-white shadow-md shadow-brand-gc/20' : 'bg-brand-primary text-white shadow-md shadow-brand-primary/20'}`}
                  >
                    + Novo Pedido
                  </button>
                </div>

                <div className="space-y-3">
                  {selectedChild.individualRequests.length > 0 ? (
                    selectedChild.individualRequests.map(req => {
                      const reqDays = Math.floor((new Date().getTime() - new Date(req.createdAt).getTime()) / (1000 * 3600 * 24));
                      const staleReq = req.status === 'em_oracao' && reqDays >= 3;
                      return (
                        <div key={req.id} className={`p-4 rounded-2xl border space-y-3 shadow-md transition-all relative overflow-hidden ${staleReq ? 'bg-orange-50 border-orange-400 ring-2 ring-orange-100/50' : 'bg-brand-cream/50 border-brand-border/40'}`}>
                          {staleReq && (
                            <div className="absolute top-0 right-0 left-0 h-1 bg-gradient-to-r from-orange-400 via-brand-primary to-orange-400 animate-pulse"></div>
                          )}
                          <div className="flex items-start justify-between gap-4">
                            <div className="flex-1 space-y-2">
                              <div className="flex items-center gap-2">
                                <span className="text-sm font-bold text-gray-800 leading-snug block">{req.request}</span>
                                {staleReq && (
                                  <i className="fa-solid fa-fire text-orange-500 animate-bounce text-xs"></i>
                                )}
                              </div>
                              {staleReq && (
                                <div className="flex items-center gap-2">
                                  <span className="bg-orange-500 text-white text-[8px] font-black px-2 py-0.5 rounded shadow-sm uppercase tracking-tighter animate-pulse">Prioridade Intercessão</span>
                                  <span className="text-[9px] text-orange-600 font-black uppercase">Pendente há {reqDays} dias</span>
                                </div>
                              )}
                            </div>
                            <button 
                              onClick={() => toggleRequestStatus(req.id)}
                              className={`text-[8px] font-black uppercase px-2 py-1 rounded-full whitespace-nowrap transition-all active:scale-90 shadow-sm ${req.status === 'em_oracao' ? (staleReq ? 'bg-orange-600 text-white' : 'bg-orange-100 text-orange-700') : 'bg-green-100 text-green-700'}`}
                            >
                              {req.status === 'em_oracao' ? 'Em Oração' : 'Respondido'}
                            </button>
                          </div>
                          {req.verse && (
                            <p className="text-[11px] text-brand-primary/80 font-medium italic bg-white/60 p-2 rounded-lg border border-brand-border/20">
                              <i className="fa-solid fa-book-bible mr-1.5"></i> "{req.verse}"
                            </p>
                          )}
                        </div>
                      );
                    })
                  ) : (
                    <div className="text-center py-8 bg-gray-50 rounded-2xl border-2 border-dashed border-gray-100">
                      <p className="text-[11px] text-gray-400 font-medium italic">Nenhum pedido específico cadastrado ainda.</p>
                    </div>
                  )}
                </div>
              </section>

              <div className="flex flex-col gap-3">
                <button className={`w-full py-5 rounded-full text-white font-black uppercase tracking-widest shadow-xl active:scale-[0.97] transition-all flex items-center justify-center gap-3 ${selectedChild.type === 'geracao_compromisso' ? 'bg-brand-gc shadow-brand-gc/30' : 'gradient-brand shadow-brand-primary/30'}`}>
                  <i className="fa-solid fa-hands-praying"></i>
                  Orar por {selectedChild.name.split(' ')[0]}
                </button>

                {selectedChild.whatsapp && (
                  <button 
                    onClick={() => handleSendWhatsapp(selectedChild)}
                    className="w-full py-4 rounded-full bg-green-500 text-white font-black uppercase tracking-widest shadow-lg active:scale-[0.97] transition-all flex items-center justify-center gap-3"
                  >
                    <i className="fa-brands fa-whatsapp"></i>
                    Avisar: "Estou orando por você"
                  </button>
                )}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Add Request Modal */}
      {showAddRequestModal && (
        <div className="fixed inset-0 bg-black/70 z-[70] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-sm rounded-[2rem] p-8 space-y-6 animate-fadeIn shadow-2xl">
            <div className="text-center">
              <h3 className={`serif-font text-2xl font-bold ${selectedChild?.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary'}`}>Nova Intercessão</h3>
              <p className="text-xs text-gray-400 mt-1">Coloque o clamor no altar do Senhor.</p>
            </div>

            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase ml-2 tracking-widest">Qual o motivo?</label>
                <textarea 
                  placeholder="Ex: Sabedoria nos estudos, proteção..." 
                  value={newReqText}
                  onChange={(e) => setNewReqText(e.target.value)}
                  className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary h-28 resize-none shadow-inner" 
                />
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase ml-2 tracking-widest">Versículo da Promessa</label>
                <input 
                  type="text" 
                  placeholder="Ex: Filipenses 4:13" 
                  value={newReqVerse}
                  onChange={(e) => setNewReqVerse(e.target.value)}
                  className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner" 
                />
              </div>
            </div>

            <div className="flex gap-4 pt-2">
              <button 
                onClick={() => { setShowAddRequestModal(false); resetRequestForm(); }} 
                className="flex-1 py-4 bg-gray-100 text-gray-500 rounded-full text-xs font-black uppercase tracking-widest"
              >
                Cancelar
              </button>
              <button 
                onClick={handleAddRequest} 
                className={`flex-1 py-4 text-white rounded-full text-xs font-black uppercase tracking-widest shadow-lg active:scale-95 ${selectedChild?.type === 'geracao_compromisso' ? 'bg-brand-gc shadow-brand-gc/20' : 'gradient-brand shadow-brand-primary/20'}`}
              >
                Salvar
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Add/Edit Child Modal (Shared logic UI) */}
      {(showAddModal || showEditModal) && (
        <div className="fixed inset-0 bg-black/70 z-[70] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 space-y-6 animate-fadeIn overflow-y-auto max-h-[90vh] no-scrollbar shadow-2xl">
            <div className="text-center">
              <h3 className="serif-font text-2xl font-bold text-brand-dark">{showEditModal ? 'Editar Filho' : 'Novo Filho de Oração'}</h3>
              <p className="text-xs text-gray-400 mt-1">{showEditModal ? 'Atualize as informações do seu filho de oração.' : 'Cobrindo um jovem com intercessão.'}</p>
            </div>

            <div className="space-y-4">
              <div className="flex flex-col items-center gap-3 mb-4">
                <div 
                  onClick={() => (showEditModal ? editFileInputRef : fileInputRef).current?.click()}
                  className="w-32 h-32 rounded-3xl bg-brand-soft border-2 border-dashed border-brand-primary/30 flex flex-col items-center justify-center cursor-pointer overflow-hidden relative group shadow-sm"
                >
                  {newPhoto ? (
                    <img src={newPhoto} alt="Preview" className="w-full h-full object-cover" />
                  ) : (
                    <div className="flex flex-col items-center text-center px-4">
                      <i className="fa-solid fa-camera text-brand-primary text-3xl mb-2 opacity-50"></i>
                      <span className="text-[10px] font-black text-brand-primary/50 uppercase tracking-widest">Toque para adicionar foto</span>
                    </div>
                  )}
                  <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                    <i className="fa-solid fa-camera text-white text-xl"></i>
                  </div>
                </div>
                <input 
                  type="file" 
                  ref={showEditModal ? editFileInputRef : fileInputRef} 
                  onChange={(e) => handlePhotoUpload(e)} 
                  accept="image/*" 
                  className="hidden" 
                />
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black text-brand-primary uppercase ml-2 tracking-widest">Nome Completo</label>
                <input 
                  type="text" 
                  placeholder="Nome do jovem" 
                  value={newName}
                  onChange={(e) => setNewName(e.target.value)}
                  className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner" 
                />
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-black text-brand-primary uppercase ml-2 tracking-widest">WhatsApp (Celular)</label>
                <input 
                  type="tel" 
                  placeholder="(XX) XXXXX-XXXX" 
                  value={newWhatsapp}
                  onChange={handleWhatsappChange}
                  className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner" 
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-brand-primary uppercase ml-2 tracking-widest">Vínculo</label>
                  <select 
                    value={newType}
                    onChange={(e) => setNewType(e.target.value as any)}
                    className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner appearance-none"
                  >
                    <option value="biologico">Biológico</option>
                    <option value="espiritual">Espiritual</option>
                    <option value="adotivo">Adotivo</option>
                    <option value="geracao_compromisso">Geração Compromisso</option>
                  </select>
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-brand-primary uppercase ml-2 tracking-widest">Nascimento</label>
                  <input 
                    type="date" 
                    value={newBirthDate}
                    onChange={(e) => setNewBirthDate(e.target.value)}
                    className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner" 
                  />
                </div>
              </div>
            </div>

            <div className="flex gap-4 pt-4">
              <button 
                onClick={() => { setShowAddModal(false); setShowEditModal(false); resetChildForm(); }} 
                className="flex-1 py-4 bg-gray-100 text-gray-500 rounded-full text-xs font-black uppercase tracking-widest"
              >
                Cancelar
              </button>
              <button 
                onClick={showEditModal ? handleUpdateChild : handleSaveChild} 
                className="flex-1 py-4 gradient-brand text-white rounded-full text-xs font-black uppercase tracking-widest shadow-xl active:scale-95"
              >
                {showEditModal ? 'Salvar Alterações' : 'Salvar'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default FilhosView;

export interface PrayerRequest {
  id: number;
  title: string;
  description: string;
  verse: string;
  category: string;
  isFavorite: boolean;
  isPrayed: boolean;
  personalNotes?: string;
}

export interface ChildOfPrayer {
  id: string;
  name: string;
  photo?: string;
  whatsapp?: string;
  type: 'biologico' | 'espiritual' | 'adotivo' | 'geracao_compromisso';
  birthDate: string;
  location: string;
  notes: string;
  startDate: string;
  prayerMinutes: number;
  individualRequests: ChildPrayerRequest[];
}

export interface ChildPrayerRequest {
  id: string;
  request: string;
  verse?: string;
  status: 'em_oracao' | 'respondido';
  createdAt: string; // ISO String
  resolvedAt?: string; // ISO String quando marcado como respondido
  lastPrayedAt?: string; // ISO String da última vez que foi especificamente intercedido
  notes?: string;
}

export interface UserStats {
  streak: number;
  totalMinutes: number;
  totalDays: number;
  hasDailyTrophy: boolean;
}

export interface UserProfile {
  name: string;
  photo?: string;
  birthDate: string;
  church: string;
  participationTime: string;
  groupName: string;
}

export interface CommunityRequest {
  id: string;
  userName: string;
  content: string;
  timestamp: string;
  reactions: {
    pray: number;
    done: number;
    heart: number;
  };
  commentCount: number;
}

import React, { useState, useRef, useMemo } from 'react';
import { ChildOfPrayer, ChildPrayerRequest } from '../types';
import { INSTITUTIONAL } from '../constants';

interface FilhosProps {
  children: ChildOfPrayer[];
  setChildren: React.Dispatch<React.SetStateAction<ChildOfPrayer[]>>;
  pendingChildren?: ChildOfPrayer[];
  setPendingChildren?: React.Dispatch<React.SetStateAction<ChildOfPrayer[]>>;
}

const FilhosView: React.FC<FilhosProps> = ({ children, setChildren, pendingChildren = [], setPendingChildren }) => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [showAddRequestModal, setShowAddRequestModal] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [selectedChild, setSelectedChild] = useState<ChildOfPrayer | null>(null);
  const [viewMode, setViewMode] = useState<'list' | 'card'>('list');

  // Form State for Child
  const [newName, setNewName] = useState('');
  const [newType, setNewType] = useState<ChildOfPrayer['type']>('biologico');
  const [newBirthDate, setNewBirthDate] = useState('');
  const [newLocation, setNewLocation] = useState('');
  const [newPhoto, setNewPhoto] = useState<string | undefined>(undefined);
  const [newWhatsapp, setNewWhatsapp] = useState('');

  // Form State for Request
  const [newReqText, setNewReqText] = useState('');
  const [newReqVerse, setNewReqVerse] = useState('');
  const [newReqStatus, setNewReqStatus] = useState<'em_oracao' | 'respondido'>('em_oracao');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const editFileInputRef = useRef<HTMLInputElement>(null);

  const formatPhoneNumber = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 11) {
      return numbers
        .replace(/^(\d{2})(\d)/g, '($1) $2')
        .replace(/(\d{5})(\d)/, '$1-$2');
    }
    return numbers.slice(0, 11)
      .replace(/^(\d{2})(\d)/g, '($1) $2')
      .replace(/(\d{5})(\d)/, '$1-$2');
  };

  const handleWhatsappChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setNewWhatsapp(formatPhoneNumber(e.target.value));
  };

  const calculateAge = (birthDate: string) => {
    if (!birthDate) return 0;
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) age--;
    return age;
  };

  const isStale = (child: ChildOfPrayer) => {
    const now = new Date();
    return child.individualRequests.some(req => {
      if (req.status !== 'em_oracao') return false;
      const created = new Date(req.createdAt);
      const diffDays = (now.getTime() - created.getTime()) / (1000 * 3600 * 24);
      return diffDays >= 3;
    });
  };

  const getSeloStyles = (type: string) => {
    switch (type) {
      case 'geracao_compromisso': return 'bg-brand-gc text-white border-brand-gc';
      case 'biologico': return 'bg-brand-primary/10 text-brand-primary border-brand-primary/20';
      case 'espiritual': return 'bg-brand-secondary/10 text-brand-secondary border-brand-secondary/20';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  const getLabel = (type: string) => {
    switch (type) {
      case 'geracao_compromisso': return 'GC';
      case 'biologico': return 'Biológico';
      case 'espiritual': return 'Espiritual';
      case 'adotivo': return 'Adotivo';
      default: return type;
    }
  };

  const handleAcceptPending = (pending: ChildOfPrayer) => {
    setChildren(prev => [pending, ...prev]);
    if (setPendingChildren) setPendingChildren(prev => prev.filter(p => p.id !== pending.id));
  };

  const handleDeclinePending = (id: string) => {
    if (setPendingChildren) setPendingChildren(prev => prev.filter(p => p.id !== id));
  };

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setNewPhoto(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleSaveChild = () => {
    if (!newName || !newBirthDate) return alert("Preencha nome e nascimento.");
    const newChild: ChildOfPrayer = {
      id: Date.now().toString(),
      name: newName,
      type: newType,
      birthDate: newBirthDate,
      location: newLocation || 'Não informada',
      photo: newPhoto,
      whatsapp: newWhatsapp,
      notes: '',
      startDate: new Date().toISOString(),
      prayerMinutes: 0,
      individualRequests: []
    };
    setChildren(prev => [newChild, ...prev]);
    resetChildForm();
    setShowAddModal(false);
  };

  const handleOpenEdit = () => {
    if (!selectedChild) return;
    setNewName(selectedChild.name);
    setNewType(selectedChild.type);
    setNewBirthDate(selectedChild.birthDate);
    setNewLocation(selectedChild.location);
    setNewPhoto(selectedChild.photo);
    setNewWhatsapp(selectedChild.whatsapp || '');
    setShowEditModal(true);
  };

  const handleUpdateChild = () => {
    if (!selectedChild || !newName || !newBirthDate) return;
    const updatedChild: ChildOfPrayer = {
      ...selectedChild,
      name: newName,
      type: newType,
      birthDate: newBirthDate,
      location: newLocation,
      photo: newPhoto,
      whatsapp: newWhatsapp,
    };
    setChildren(prev => prev.map(c => c.id === selectedChild.id ? updatedChild : c));
    setSelectedChild(updatedChild);
    resetChildForm();
    setShowEditModal(false);
  };

  const handleAddRequest = () => {
    if (!selectedChild || !newReqText) return alert("Informe o motivo.");
    const newReq: ChildPrayerRequest = {
      id: Date.now().toString(),
      request: newReqText,
      verse: newReqVerse,
      status: newReqStatus,
      createdAt: new Date().toISOString(),
    };
    setChildren(prev => {
      return prev.map(child => {
        if (child.id === selectedChild.id) {
          const updatedChild = { ...child, individualRequests: [...child.individualRequests, newReq] };
          setSelectedChild(updatedChild);
          return updatedChild;
        }
        return child;
      });
    });
    resetRequestForm();
    setShowAddRequestModal(false);
  };

  const toggleRequestStatus = (requestId: string) => {
    if (!selectedChild) return;
    setChildren(prev => {
      return prev.map(child => {
        if (child.id === selectedChild.id) {
          const updatedRequests = child.individualRequests.map(req => {
            if (req.id === requestId) {
              const newStatus = req.status === 'em_oracao' ? 'respondido' : 'em_oracao';
              return { 
                ...req, 
                status: newStatus as any,
                resolvedAt: newStatus === 'respondido' ? new Date().toISOString() : undefined
              };
            }
            return req;
          });
          const updatedChild = { ...child, individualRequests: updatedRequests };
          setSelectedChild(updatedChild);
          return updatedChild;
        }
        return child;
      });
    });
  };

  const handlePrayerAction = () => {
    if (!selectedChild) return;
    // Simula registrar intercessão direta no histórico
    setChildren(prev => {
      return prev.map(child => {
        if (child.id === selectedChild.id) {
          const updatedChild = { 
            ...child, 
            prayerMinutes: child.prayerMinutes + 1 
          };
          setSelectedChild(updatedChild);
          return updatedChild;
        }
        return child;
      });
    });
    alert(`Iniciando intercessão focada por ${selectedChild.name.split(' ')[0]}...`);
  };

  const handleSendWhatsapp = (child: ChildOfPrayer) => {
    if (!child.whatsapp) return alert("WhatsApp não cadastrado.");
    const cleanNumber = child.whatsapp.replace(/\D/g, '');
    const message = encodeURIComponent(`Olá, estou intercedendo por você agora mesmo! Creio no que Deus fará.`);
    window.open(`https://wa.me/55${cleanNumber}?text=${message}`, '_blank');
  };

  const resetChildForm = () => {
    setNewName(''); setNewType('biologico'); setNewBirthDate(''); setNewLocation(''); setNewPhoto(undefined); setNewWhatsapp('');
  };

  const resetRequestForm = () => {
    setNewReqText(''); setNewReqVerse(''); setNewReqStatus('em_oracao');
  };

  // Memoized history sorted chronologically
  const historyLog = useMemo(() => {
    if (!selectedChild) return [];
    return [...selectedChild.individualRequests].sort((a, b) => 
      new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
    );
  }, [selectedChild]);

  return (
    <div className="space-y-6 pb-20">
      <div className="flex items-center justify-between">
        <h2 className="serif-font text-2xl font-bold text-brand-dark">Filhos de Oração</h2>
        <div className="flex items-center gap-3">
          <div className="bg-brand-soft p-1 rounded-xl flex items-center border border-brand-border">
            <button onClick={() => setViewMode('list')} className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all ${viewMode === 'list' ? 'bg-white text-brand-primary shadow-sm' : 'text-gray-400'}`}>
              <i className="fa-solid fa-list-ul text-xs"></i>
            </button>
            <button onClick={() => setViewMode('card')} className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all ${viewMode === 'card' ? 'bg-white text-brand-primary shadow-sm' : 'text-gray-400'}`}>
              <i className="fa-solid fa-grip text-xs"></i>
            </button>
          </div>
          <button onClick={() => setShowAddModal(true)} className="bg-brand-gc text-white w-10 h-10 rounded-full flex items-center justify-center shadow-lg active:scale-90 transition-transform">
            <i className="fa-solid fa-plus"></i>
          </button>
        </div>
      </div>

      {pendingChildren.length > 0 && (
        <section className="space-y-3 animate-fadeIn">
          <div className="flex items-center gap-2 px-1">
            <span className="relative flex h-2 w-2">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-brand-gc opacity-75"></span>
              <span className="relative inline-flex rounded-full h-2 w-2 bg-brand-gc"></span>
            </span>
            <h3 className="text-[10px] font-black uppercase text-brand-gc tracking-[0.2em]">Novas Solicitações (Web)</h3>
          </div>
          <div className="space-y-3">
            {pendingChildren.map(pending => (
              <div key={pending.id} className="bg-white rounded-3xl p-4 border-2 border-brand-gc/20 shadow-lg shadow-brand-gc/5 flex flex-col gap-4">
                <div className="flex gap-4">
                  <div className="w-16 h-16 rounded-2xl overflow-hidden border border-brand-gc/30">
                    <img src={pending.photo} className="w-full h-full object-cover" alt={pending.name} />
                  </div>
                  <div className="flex-1">
                    <div className="flex justify-between">
                      <h4 className="font-black text-brand-dark">{pending.name}</h4>
                      <span className="bg-brand-gc text-white text-[8px] font-black px-2 py-0.5 rounded-full uppercase">Geração Compromisso</span>
                    </div>
                    <p className="text-[10px] text-gray-500 mt-1 line-clamp-2 italic">"{pending.notes}"</p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button onClick={() => handleAcceptPending(pending)} className="flex-1 bg-brand-gc text-white py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest active:scale-[0.98]">Aceitar Cobertura</button>
                  <button onClick={() => handleDeclinePending(pending.id)} className="px-4 bg-gray-100 text-gray-400 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest active:scale-[0.98]">Ignorar</button>
                </div>
              </div>
            ))}
          </div>
        </section>
      )}

      <div className="bg-brand-gc text-white p-5 rounded-3xl border border-white/20 relative overflow-hidden shadow-inner">
        <div className="relative z-10 flex gap-4 items-center">
            <div className="w-10 h-10 bg-white/10 rounded-xl flex items-center justify-center flex-shrink-0">
                <i className="fa-solid fa-hands-praying text-xl"></i>
            </div>
            <p className="text-[11px] font-semibold leading-snug opacity-95 italic">
                "Aqui você acompanha os filhos que Deus confiou a você para interceder, formando uma Geração Compromisso sólida e fiel."
            </p>
        </div>
        <div className="absolute -right-4 -bottom-4 w-16 h-16 bg-white/5 rounded-full blur-xl"></div>
      </div>

      <div className={viewMode === 'list' ? "grid grid-cols-1 gap-4" : "grid grid-cols-2 gap-4"}>
        {children.length > 0 ? (
          children.map(child => {
            const stale = isStale(child);
            return viewMode === 'list' ? (
              <div key={child.id} onClick={() => setSelectedChild(child)} className={`bg-white rounded-3xl p-4 border shadow-sm flex gap-4 cursor-pointer hover:shadow-md transition-shadow active:scale-[0.99] animate-fadeIn relative ${stale ? 'border-orange-300 ring-1 ring-orange-100 shadow-orange-50' : (child.type === 'geracao_compromisso' ? 'border-brand-gc/30' : 'border-brand-border')}`}>
                {stale && <div className="absolute -top-1 -left-1 bg-orange-500 text-white text-[8px] font-black px-2 py-0.5 rounded-full shadow-sm animate-pulse z-10">URGENTE</div>}
                <div className="w-20 h-20 rounded-2xl overflow-hidden flex-shrink-0 bg-brand-soft border border-brand-border relative shadow-sm">
                  <img src={child.photo || `https://picsum.photos/seed/${child.id}/200`} alt={child.name} className="w-full h-full object-cover" />
                </div>
                <div className="flex-1 space-y-2">
                  <div className="flex justify-between items-start">
                    <h3 className="font-bold text-brand-dark line-clamp-1">{child.name}</h3>
                    <span className={`text-[8px] uppercase font-black px-2 py-0.5 rounded-full border tracking-tighter ${getSeloStyles(child.type)}`}>
                      {getLabel(child.type)}
                    </span>
                  </div>
                  <div className="flex items-center gap-3 text-xs text-gray-500">
                    <p><i className="fa-solid fa-cake-candles mr-1 opacity-60"></i> {calculateAge(child.birthDate)} anos</p>
                  </div>
                  <div className="flex items-center justify-between pt-1">
                    <div className="flex items-center gap-2">
                      <i className={`fa-solid fa-hands-praying text-xs ${stale ? 'text-orange-500' : 'text-brand-primary'}`}></i>
                      <span className="text-[10px] text-gray-400 font-medium">{child.individualRequests.filter(r => r.status === 'em_oracao').length} clamores</span>
                    </div>
                  </div>
                </div>
              </div>
            ) : (
              <div key={child.id} onClick={() => setSelectedChild(child)} className={`bg-white rounded-[2rem] p-3 border shadow-sm cursor-pointer hover:shadow-md transition-all active:scale-[0.97] animate-fadeIn relative overflow-hidden group ${stale ? 'border-orange-300 ring-1 ring-orange-100' : (child.type === 'geracao_compromisso' ? 'border-brand-gc/30' : 'border-brand-border')}`}>
                {stale && <div className="absolute top-2 left-2 bg-orange-500 text-white text-[7px] font-black px-2 py-1 rounded-lg z-10 shadow-lg animate-pulse">ATENÇÃO</div>}
                <div className="aspect-square w-full rounded-[1.5rem] overflow-hidden mb-3 bg-brand-soft relative">
                  <img src={child.photo || `https://picsum.photos/seed/${child.id}/200`} alt={child.name} className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" />
                </div>
                <div className="px-1 pb-1 text-center">
                  <h3 className="font-bold text-brand-dark text-sm line-clamp-1 mb-1">{child.name}</h3>
                  <div className="flex items-center justify-center gap-2 text-[10px] text-gray-400 font-medium">
                    <span>{calculateAge(child.birthDate)} anos</span>
                  </div>
                </div>
              </div>
            );
          })
        ) : (
          <div className="col-span-full text-center py-24 text-gray-400">
            <i className="fa-solid fa-users-rays text-6xl mb-6 opacity-20"></i>
            <p className="text-sm font-medium">Sua lista está vazia.</p>
          </div>
        )}
      </div>

      {/* Detail Modal */}
      {selectedChild && !showHistory && (
        <div className="fixed inset-0 bg-black/60 z-[60] flex items-end sm:items-center justify-center p-0 sm:p-4">
          <div className="bg-white w-full max-w-lg rounded-t-[2.5rem] sm:rounded-3xl p-6 animate-slideUp overflow-y-auto max-h-[95vh] no-scrollbar">
            <div className="w-12 h-1.5 bg-gray-200 rounded-full mx-auto mb-6 sm:hidden"></div>

            <div className="flex justify-between items-start mb-6">
              <div className="flex items-center gap-4">
                <div className={`w-20 h-20 rounded-2xl overflow-hidden border-2 shadow-sm ${selectedChild.type === 'geracao_compromisso' ? 'border-brand-gc' : 'border-brand-primary'}`}>
                  <img src={selectedChild.photo || `https://picsum.photos/seed/${selectedChild.id}/200`} className="w-full h-full object-cover" alt={selectedChild.name} />
                </div>
                <div className="space-y-1">
                  <h3 className="text-xl font-bold text-brand-dark leading-tight">{selectedChild.name}</h3>
                  <p className={`text-[10px] font-black uppercase tracking-wider ${selectedChild.type === 'geracao_compromisso' ? 'text-brand-gc' : 'text-brand-primary'}`}>{selectedChild.type.replace('_', ' ')}</p>
                </div>
              </div>
              <div className="flex gap-2">
                <button onClick={handleOpenEdit} className="w-10 h-10 rounded-full bg-brand-soft text-brand-primary flex items-center justify-center active:scale-90 shadow-sm"><i className="fa-solid fa-pen-to-square"></i></button>
                <button onClick={() => setSelectedChild(null)} className="w-10 h-10 rounded-full bg-gray-100 flex items-center justify-center active:bg-gray-200 transition-colors"><i className="fa-solid fa-xmark text-gray-500"></i></button>
              </div>
            </div>

            <div className="space-y-6">
              <div className="flex gap-2">
                <button onClick={() => setShowHistory(true)} className="flex-1 py-3 px-4 rounded-2xl bg-brand-lavender text-brand-rose text-xs font-black uppercase tracking-widest flex items-center justify-center gap-2 border border-brand-rose/20 shadow-sm active:scale-95 transition-all">
                  <i className="fa-solid fa-clock-rotate-left"></i> Histórico Espiritual
                </button>
                {selectedChild.whatsapp && (
                   <button onClick={() => handleSendWhatsapp(selectedChild)} className="px-4 rounded-2xl bg-green-500 text-white flex items-center justify-center active:scale-95 transition-all shadow-md"><i className="fa-brands fa-whatsapp text-lg"></i></button>
                )}
              </div>

              <section>
                <div className="flex items-center justify-between mb-4">
                  <h4 className="text-xs font-black uppercase tracking-widest text-brand-primary flex items-center gap-2"><i className="fa-solid fa-heart-pulse"></i> Pedidos Ativos</h4>
                  <button onClick={() => setShowAddRequestModal(true)} className="text-[10px] font-black uppercase px-4 py-1.5 rounded-full bg-brand-primary text-white shadow-md active:scale-95 transition-all">+ Novo</button>
                </div>
                <div className="space-y-3">
                  {selectedChild.individualRequests.filter(r => r.status === 'em_oracao').map(req => (
                    <div key={req.id} className="p-4 rounded-2xl border border-brand-border/40 bg-brand-cream/50 space-y-2">
                      <div className="flex justify-between items-start gap-3">
                        <span className="text-sm font-bold text-gray-800 leading-snug">{req.request}</span>
                        <button onClick={() => toggleRequestStatus(req.id)} className="text-[8px] font-black uppercase px-2 py-1 rounded-full bg-orange-100 text-orange-700 shadow-sm">Em Oração</button>
                      </div>
                      {req.verse && <p className="text-[10px] text-brand-primary/80 italic font-medium"><i className="fa-solid fa-book-bible mr-1"></i> "{req.verse}"</p>}
                    </div>
                  ))}
                  {selectedChild.individualRequests.filter(r => r.status === 'em_oracao').length === 0 && (
                    <div className="text-center py-6 bg-gray-50 rounded-2xl border-2 border-dashed border-gray-100 text-[10px] text-gray-400">Nenhum pedido ativo.</div>
                  )}
                </div>
              </section>

              <button onClick={handlePrayerAction} className="w-full py-5 rounded-full gradient-brand text-white font-black uppercase tracking-widest shadow-xl active:scale-[0.97] flex items-center justify-center gap-3">
                <i className="fa-solid fa-hands-praying"></i> Interceder agora
              </button>
            </div>
          </div>
        </div>
      )}

      {/* History View Modal */}
      {selectedChild && showHistory && (
        <div className="fixed inset-0 bg-black/60 z-[65] flex items-end sm:items-center justify-center p-0 sm:p-4">
          <div className="bg-brand-cream w-full max-w-lg rounded-t-[2.5rem] sm:rounded-3xl p-6 animate-slideUp overflow-y-auto max-h-[95vh] no-scrollbar">
            <div className="flex items-center justify-between mb-8">
              <button onClick={() => setShowHistory(false)} className="w-10 h-10 rounded-full bg-white flex items-center justify-center text-brand-rose shadow-sm border border-brand-rose/10 active:scale-90 transition-transform">
                <i className="fa-solid fa-chevron-left"></i>
              </button>
              <div className="text-center">
                <h3 className="serif-font text-xl font-black text-brand-dark">Jornada de Fé</h3>
                <p className="text-[9px] font-black uppercase tracking-[0.2em] text-brand-rose/60">Histórico de {selectedChild.name.split(' ')[0]}</p>
              </div>
              <div className="w-10 h-10"></div>
            </div>

            <div className="relative space-y-10 pl-4 before:absolute before:left-[1.3rem] before:top-2 before:bottom-2 before:w-0.5 before:bg-brand-rose/20 before:rounded-full">
              {historyLog.length > 0 ? historyLog.map((log) => {
                const isResolved = log.status === 'respondido';
                return (
                  <div key={log.id} className="relative pl-10 animate-fadeIn">
                    <div className={`absolute left-[-1.1rem] top-1 w-5 h-5 rounded-full border-4 border-brand-cream z-10 shadow-sm transition-colors ${isResolved ? 'bg-green-500' : 'bg-brand-rose'}`}></div>
                    <div className="bg-white rounded-2xl p-4 border border-brand-rose/10 shadow-sm space-y-2 relative overflow-hidden">
                      {isResolved && <div className="absolute top-0 right-0 w-16 h-16 bg-green-500/5 rounded-full -mr-8 -mt-8 flex items-end justify-start pb-4 pl-4 text-green-500 opacity-20"><i className="fa-solid fa-check text-2xl"></i></div>}

                      <div className="flex justify-between items-start">
                         <span className={`text-[8px] font-black uppercase tracking-widest px-2 py-0.5 rounded-full ${isResolved ? 'bg-green-50 text-green-600' : 'bg-brand-soft text-brand-rose'}`}>
                           {isResolved ? 'Vitória Alcançada' : 'Em Oração'}
                         </span>
                         <span className="text-[9px] text-gray-400 font-bold">{new Date(log.createdAt).toLocaleDateString('pt-BR')}</span>
                      </div>

                      <p className="text-sm font-bold text-brand-dark leading-snug">{log.request}</p>
                      {log.verse && <p className="text-[10px] text-brand-primary/70 italic"><i className="fa-solid fa-book-bible mr-1"></i> {log.verse}</p>}

                      {isResolved && log.resolvedAt && (
                        <div className="pt-2 border-t border-dashed border-gray-100 flex items-center justify-between">
                          <span className="text-[8px] font-black text-gray-400 uppercase">Respondido em:</span>
                          <span className="text-[9px] font-black text-green-600">{new Date(log.resolvedAt).toLocaleDateString('pt-BR')}</span>
                        </div>
                      )}
                    </div>
                  </div>
                );
              }) : (
                <div className="text-center py-20 opacity-30">
                  <i className="fa-solid fa-seedling text-6xl mb-4 text-brand-rose"></i>
                  <p className="text-sm font-bold serif-font">As sementes da oração florescerão aqui.</p>
                </div>
              )}
            </div>

            <div className="mt-12 p-6 bg-brand-rose/5 rounded-3xl border border-brand-rose/10 text-center space-y-2">
              <i className="fa-solid fa-quote-left text-brand-rose/20 text-3xl"></i>
              <p className="text-sm text-brand-rose font-medium italic italic">"A oração feita por um justo pode muito em seus efeitos."</p>
              <p className="text-[9px] font-black text-brand-rose uppercase tracking-widest">— Tiago 5:16</p>
            </div>
          </div>
        </div>
      )}

      {/* Add Request Modal */}
      {showAddRequestModal && (
        <div className="fixed inset-0 bg-black/70 z-[70] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-sm rounded-[2rem] p-8 space-y-6 animate-fadeIn shadow-2xl">
            <div className="text-center">
              <h3 className="serif-font text-2xl font-bold text-brand-primary">Nova Intercessão</h3>
              <p className="text-xs text-gray-400 mt-1">Coloque o clamor no altar.</p>
            </div>
            <div className="space-y-4">
              <textarea placeholder="Motivo da oração..." value={newReqText} onChange={(e) => setNewReqText(e.target.value)} className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary h-28 resize-none shadow-inner" />
              <input type="text" placeholder="Versículo da Promessa" value={newReqVerse} onChange={(e) => setNewReqVerse(e.target.value)} className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner" />
            </div>
            <div className="flex gap-4 pt-2">
              <button onClick={() => { setShowAddRequestModal(false); resetRequestForm(); }} className="flex-1 py-4 bg-gray-100 text-gray-500 rounded-full text-xs font-black uppercase tracking-widest">Cancelar</button>
              <button onClick={handleAddRequest} className="flex-1 py-4 gradient-brand text-white rounded-full text-xs font-black uppercase tracking-widest shadow-lg active:scale-95">Salvar</button>
            </div>
          </div>
        </div>
      )}

      {/* Child Add/Edit Modal */}
      {(showAddModal || showEditModal) && (
        <div className="fixed inset-0 bg-black/70 z-[70] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] p-8 space-y-6 animate-fadeIn overflow-y-auto max-h-[90vh] no-scrollbar shadow-2xl">
            <h3 className="serif-font text-2xl font-bold text-brand-dark text-center">{showEditModal ? 'Editar Filho' : 'Novo Filho de Oração'}</h3>
            <div className="space-y-4">
              <div className="flex flex-col items-center gap-3 mb-4">
                <div onClick={() => (showEditModal ? editFileInputRef : fileInputRef).current?.click()} className="w-24 h-24 rounded-3xl bg-brand-soft border-2 border-dashed border-brand-primary/30 flex flex-col items-center justify-center cursor-pointer overflow-hidden relative">
                  {newPhoto ? <img src={newPhoto} alt="Preview" className="w-full h-full object-cover" /> : <i className="fa-solid fa-camera text-brand-primary text-xl opacity-50"></i>}
                </div>
                <input type="file" ref={showEditModal ? editFileInputRef : fileInputRef} onChange={handlePhotoUpload} accept="image/*" className="hidden" />
              </div>
              <input type="text" placeholder="Nome Completo" value={newName} onChange={(e) => setNewName(e.target.value)} className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner" />
              <input type="tel" placeholder="WhatsApp (XX) XXXXX-XXXX" value={newWhatsapp} onChange={handleWhatsappChange} className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner" />
              <div className="grid grid-cols-2 gap-4">
                <select value={newType} onChange={(e) => setNewType(e.target.value as any)} className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner appearance-none">
                  <option value="biologico">Biológico</option>
                  <option value="espiritual">Espiritual</option>
                  <option value="adotivo">Adotivo</option>
                  <option value="geracao_compromisso">GC</option>
                </select>
                <input type="date" value={newBirthDate} onChange={(e) => setNewBirthDate(e.target.value)} className="w-full p-4 bg-gray-50 rounded-2xl border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner" />
              </div>
            </div>
            <div className="flex gap-4 pt-4">
              <button onClick={() => { setShowAddModal(false); setShowEditModal(false); resetChildForm(); }} className="flex-1 py-4 bg-gray-100 text-gray-500 rounded-full text-xs font-black uppercase tracking-widest">Cancelar</button>
              <button onClick={showEditModal ? handleUpdateChild : handleSaveChild} className="flex-1 py-4 gradient-brand text-white rounded-full text-xs font-black uppercase tracking-widest shadow-xl active:scale-95">{showEditModal ? 'Salvar' : 'Criar'}</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

