        <div className="fixed inset-0 bg-black/80 z-[70] flex items-center justify-center p-4 backdrop-blur-sm">
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-8 space-y-6 animate-fadeIn shadow-2xl">
            <div className="text-center space-y-2">
              <div className="w-12 h-12 bg-brand-soft rounded-2xl flex items-center justify-center mx-auto text-brand-primary">
                <i className="fa-solid fa-hands-praying text-2xl"></i>
              </div>
              <h3 className="serif-font text-2xl font-black text-brand-dark">Novo Clamor</h3>
              <p className="text-xs text-gray-400 uppercase font-black tracking-widest">Coloque a intenção no altar</p>
