interface FilhosProps {
  children: ChildOfPrayer[];
  setChildren: React.Dispatch<React.SetStateAction<ChildOfPrayer[]>>;
  pendingChildren?: ChildOfPrayer[];
  setPendingChildren?: React.Dispatch<React.SetStateAction<ChildOfPrayer[]>>;
}

const FilhosView: React.FC<FilhosProps> = ({ children, setChildren, pendingChildren = [], setPendingChildren }) => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [showAddRequestModal, setShowAddRequestModal] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [selectedChild, setSelectedChild] = useState<ChildOfPrayer | null>(null);
  const [viewMode, setViewMode] = useState<'list' | 'card'>('list');

  // Form State for Child
  const [newName, setNewName] = useState('');
  const [newType, setNewType] = useState<ChildOfPrayer['type']>('biologico');
  const [newBirthDate, setNewBirthDate] = useState('');
  const [newLocation, setNewLocation] = useState('');
  const [newPhoto, setNewPhoto] = useState<string | undefined>(undefined);
  const [newWhatsapp, setNewWhatsapp] = useState('');

  // Form State for Request
  const [newReqText, setNewReqText] = useState('');
  const [newReqVerse, setNewReqVerse] = useState('');
  const [newReqStatus, setNewReqStatus] = useState<'em_oracao' | 'respondido'>('em_oracao');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const editFileInputRef = useRef<HTMLInputElement>(null);

  const formatPhoneNumber = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 11) {
      return numbers
        .replace(/^(\d{2})(\d)/g, '($1) $2')
        .replace(/(\d{5})(\d)/, '$1-$2');
    }
    return numbers.slice(0, 11)
      .replace(/^(\d{2})(\d)/g, '($1) $2')
      .replace(/(\d{5})(\d)/, '$1-$2');
  };

  const handleWhatsappChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setNewWhatsapp(formatPhoneNumber(e.target.value));
  };

  const calculateAge = (birthDate: string) => {
    if (!birthDate) return 0;
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) age--;
    return age;
  };

  const isStale = (child: ChildOfPrayer) => {
    const now = new Date();
    return child.individualRequests.some(req => {
      if (req.status !== 'em_oracao') return false;
      const created = new Date(req.createdAt);
      const diffDays = (now.getTime() - created.getTime()) / (1000 * 3600 * 24);
      return diffDays >= 3;
    });
  };

  const getSeloStyles = (type: string) => {
    switch (type) {
      case 'geracao_compromisso': return 'bg-brand-gc border-brand-gc text-white';
      case 'biologico': return 'bg-brand-primary/10 text-brand-primary border-brand-primary/20';
      case 'espiritual': return 'bg-brand-secondary/10 text-brand-secondary border-brand-secondary/20';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  const getLabel = (type: string) => {
    if (type === 'geracao_compromisso') {
      return (
        <div className="flex items-center justify-center">
          <img src={IMAGENS.logoGC} className="h-3 w-auto object-contain brightness-0 invert" alt="Logo GC" />
        </div>
      );
    }
    switch (type) {
      case 'biologico': return 'Biológico';
      case 'espiritual': return 'Espiritual';
      case 'adotivo': return 'Adotivo';
      default: return type;
    }
  };

  const handleAcceptPending = (pending: ChildOfPrayer) => {
    setChildren(prev => [pending, ...prev]);
    if (setPendingChildren) setPendingChildren(prev => prev.filter(p => p.id !== pending.id));
  };

  const handleDeclinePending = (id: string) => {
    if (setPendingChildren) setPendingChildren(prev => prev.filter(p => p.id !== id));
  };

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setNewPhoto(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleSaveChild = () => {
    if (!newName || !newBirthDate) return alert("Preencha nome e nascimento.");
    const newChild: ChildOfPrayer = {
      id: Date.now().toString(),
      name: newName,
      type: newType,
      birthDate: newBirthDate,
      location: newLocation || 'Não informada',
      photo: newPhoto,
      whatsapp: newWhatsapp,
      notes: '',
      startDate: new Date().toISOString(),
      prayerMinutes: 0,
      individualRequests: []
    };
    setChildren(prev => [newChild, ...prev]);
    resetChildForm();
    setShowAddModal(false);
  };

  const handleOpenEdit = () => {
    if (!selectedChild) return;
    setNewName(selectedChild.name);
    setNewType(selectedChild.type);
    setNewBirthDate(selectedChild.birthDate);
    setNewLocation(selectedChild.location);
    setNewPhoto(selectedChild.photo);
    setNewWhatsapp(selectedChild.whatsapp || '');
    setShowEditModal(true);
  };

  const handleUpdateChild = () => {
    if (!selectedChild || !newName || !newBirthDate) return;
    const updatedChild: ChildOfPrayer = {
      ...selectedChild,
      name: newName,
      type: newType,
      birthDate: newBirthDate,
      location: newLocation,
      photo: newPhoto,
      whatsapp: newWhatsapp,
    };
    setChildren(prev => prev.map(c => c.id === selectedChild.id ? updatedChild : c));
    setSelectedChild(updatedChild);
    resetChildForm();
    setShowEditModal(false);
  };

  const handleAddRequest = () => {
    if (!selectedChild || !newReqText) return alert("Informe o motivo.");
    const newReq: ChildPrayerRequest = {
      id: Date.now().toString(),
      request: newReqText,
      verse: newReqVerse,
      status: newReqStatus,
      createdAt: new Date().toISOString(),
    };
    setChildren(prev => {
      return prev.map(child => {
        if (child.id === selectedChild.id) {
          const updatedChild = { ...child, individualRequests: [...child.individualRequests, newReq] };
          setSelectedChild(updatedChild);
          return updatedChild;
        }
        return child;
      });
    });
    resetRequestForm();
    setShowAddRequestModal(false);
  };

  const toggleRequestStatus = (requestId: string) => {
    if (!selectedChild) return;
    setChildren(prev => {
      return prev.map(child => {
        if (child.id === selectedChild.id) {
          const updatedRequests = child.individualRequests.map(req => {
            if (req.id === requestId) {
              const newStatus = req.status === 'em_oracao' ? 'respondido' : 'em_oracao';
              return { 
                ...req, 
                status: newStatus as any,
                resolvedAt: newStatus === 'respondido' ? new Date().toISOString() : undefined
              };
            }
            return req;
          });
          const updatedChild = { ...child, individualRequests: updatedRequests };
          setSelectedChild(updatedChild);
          return updatedChild;
        }
        return child;
      });
    });
  };

  const handlePrayerAction = () => {
    if (!selectedChild) return;
    setChildren(prev => {
      return prev.map(child => {
        if (child.id === selectedChild.id) {
          const updatedChild = { 
            ...child, 
            prayerMinutes: child.prayerMinutes + 1 
          };
          setSelectedChild(updatedChild);
          return updatedChild;
        }
        return child;
      });
    });
    alert(`Intercessão por ${selectedChild.name.split(' ')[0]} registrada no céu!`);
  };

  const handleSendWhatsapp = (child: ChildOfPrayer) => {
    if (!child.whatsapp) return alert("WhatsApp não cadastrado.");
    const cleanNumber = child.whatsapp.replace(/\D/g, '');
    const message = encodeURIComponent(`Olá, estou intercedendo por você agora mesmo através do App Desperta Débora! Creio no que Deus fará.`);
    window.open(`https://wa.me/55${cleanNumber}?text=${message}`, '_blank');
  };

  const resetChildForm = () => {
    setNewName(''); setNewType('biologico'); setNewBirthDate(''); setNewLocation(''); setNewPhoto(undefined); setNewWhatsapp('');
  };

  const resetRequestForm = () => {
    setNewReqText(''); setNewReqVerse(''); setNewReqStatus('em_oracao');
  };

  const historyLog = useMemo(() => {
    if (!selectedChild) return [];
    return [...selectedChild.individualRequests].sort((a, b) => 
      new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
    );
  }, [selectedChild]);

  return (
    <div className="space-y-6 pb-20">
      {/* Header com Logomarca Visível */}
      <div className="flex items-center justify-between">
        <div className="flex flex-col">
          <h2 className="serif-font text-2xl font-bold text-brand-dark leading-tight">Filhos de Oração</h2>
          <div className="mt-2 flex items-center gap-2 h-7">
            <span className="text-[10px] font-black uppercase text-gray-400 tracking-[0.2em]">Pela</span>
            <img src={IMAGENS.logoGC} alt="Logo Geração Compromisso" className="h-full w-auto object-contain" />
          </div>
        </div>
        <div className="flex items-center gap-3">
          <div className="bg-brand-soft p-1 rounded-xl flex items-center border border-brand-border">
            <button onClick={() => setViewMode('list')} className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all ${viewMode === 'list' ? 'bg-white text-brand-primary shadow-sm' : 'text-gray-400'}`}>
              <i className="fa-solid fa-list-ul text-xs"></i>
            </button>
            <button onClick={() => setViewMode('card')} className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all ${viewMode === 'card' ? 'bg-white text-brand-primary shadow-sm' : 'text-gray-400'}`}>
              <i className="fa-solid fa-grip text-xs"></i>
            </button>
          </div>
          <button onClick={() => setShowAddModal(true)} className="bg-brand-gc text-white w-10 h-10 rounded-full flex items-center justify-center shadow-lg active:scale-90 transition-transform">
            <i className="fa-solid fa-plus"></i>
          </button>
        </div>
      </div>

      {pendingChildren.length > 0 && (
        <section className="space-y-3 animate-fadeIn">
          <div className="flex items-center gap-2 px-1">
            <span className="relative flex h-2 w-2">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-brand-gc opacity-75"></span>
              <span className="relative inline-flex rounded-full h-2 w-2 bg-brand-gc"></span>
            </span>
            <h3 className="text-[10px] font-black uppercase text-brand-gc tracking-[0.2em]">Novas Solicitações</h3>
          </div>
          <div className="space-y-3">
            {pendingChildren.map(pending => (
              <div key={pending.id} className="bg-white rounded-3xl p-4 border-2 border-brand-gc/20 shadow-lg shadow-brand-gc/5 flex flex-col gap-4">
                <div className="flex gap-4">
                  <div className="w-16 h-16 rounded-2xl overflow-hidden border border-brand-gc/30">
                    <img src={pending.photo} className="w-full h-full object-cover" alt={pending.name} />
                  </div>
                  <div className="flex-1">
                    <div className="flex justify-between items-center h-6">
                      <h4 className="font-black text-brand-dark">{pending.name}</h4>
                      <div className="bg-brand-gc px-3 py-1 rounded-full flex items-center justify-center">
                        <img src={IMAGENS.logoGC} className="h-3 w-auto object-contain brightness-0 invert" alt="GC" />
                      </div>
                    </div>
                    <p className="text-[10px] text-gray-500 mt-1 line-clamp-2 italic">"{pending.notes}"</p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button onClick={() => handleAcceptPending(pending)} className="flex-1 bg-brand-gc text-white py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest active:scale-[0.98]">Aceitar Cobertura</button>
                  <button onClick={() => handleDeclinePending(pending.id)} className="px-4 bg-gray-100 text-gray-400 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest active:scale-[0.98]">Ignorar</button>
                </div>
              </div>
            ))}
          </div>
        </section>
      )}

      {/* Caixa de Introdução - Logomarca VISÍVEL */}
      <div className="bg-brand-gc text-white p-6 rounded-[2.5rem] border border-white/20 relative overflow-hidden shadow-xl shadow-brand-gc/20">
        <div className="relative z-10 flex gap-5 items-center">
           <div className="w-16 h-16 bg-white/20 rounded-2xl flex items-center justify-center backdrop-blur-md flex-shrink-0 border border-white/10">
             <img src={IMAGENS.logoGC} className="w-12 h-12 object-contain brightness-0 invert" alt="Logo GC" />
           </div>
           <div>
             <div className="flex items-center gap-2 mb-1.5">
                <p className="text-[10px] font-black uppercase tracking-[0.2em] opacity-80">Geração</p>
                <img src={IMAGENS.logoGC} className="h-4 w-auto object-contain brightness-0 invert" alt="Compromisso" />
             </div>
             <p className="text-[13px] font-semibold leading-snug opacity-95">
                Cubra nossos jovens com o escudo da oração. Mães de joelhos, filhos de pé!
             </p>
           </div>
        </div>
        <div className="absolute -right-8 -bottom-8 w-32 h-32 bg-white/5 rounded-full blur-3xl"></div>
      </div>

      {/* Grid de Filhos */}
      <div className={viewMode === 'list' ? "grid grid-cols-1 gap-4" : "grid grid-cols-2 gap-4"}>
        {children.length > 0 ? (
          children.map(child => {
            const stale = isStale(child);
            return (
              <div 
                key={child.id} 
                onClick={() => setSelectedChild(child)} 
                className={`bg-white rounded-3xl p-4 border shadow-sm flex ${viewMode === 'list' ? 'gap-4' : 'flex-col gap-3 items-center text-center'} cursor-pointer hover:shadow-md transition-all active:scale-[0.99] relative ${stale ? 'border-orange-300 ring-1 ring-orange-100' : 'border-brand-border'}`}
              >
                {stale && <div className="absolute -top-1 -left-1 bg-orange-500 text-white text-[8px] font-black px-2 py-0.5 rounded-full z-10 shadow-sm animate-pulse">URGENTE</div>}
                <div className={`${viewMode === 'list' ? 'w-20 h-20' : 'w-full aspect-square'} rounded-2xl overflow-hidden flex-shrink-0 bg-brand-soft border border-brand-border`}>
                  <img src={child.photo || `https://picsum.photos/seed/${child.id}/200`} alt={child.name} className="w-full h-full object-cover" />
                </div>
                <div className="flex-1 w-full space-y-2">
                  <div className="flex justify-between items-start">
                    <h3 className="font-bold text-brand-dark line-clamp-1">{child.name}</h3>
                    {viewMode === 'list' && (
                      <span className={`text-[8px] uppercase font-black px-3 py-1.5 rounded-full border tracking-tighter flex items-center justify-center min-w-[60px] ${getSeloStyles(child.type)}`}>
                        {getLabel(child.type)}
                      </span>
                    )}
                  </div>
                  <div className="flex items-center gap-3 text-[11px] text-gray-500 font-medium">
                    <p><i className="fa-solid fa-cake-candles mr-1 opacity-60"></i> {calculateAge(child.birthDate)} anos</p>
                    <p><i className="fa-solid fa-clock mr-1 opacity-60"></i> {child.prayerMinutes}m</p>
                  </div>
                  {viewMode === 'card' && (
                    <span className={`text-[8px] uppercase font-black px-3 py-1.5 rounded-full border tracking-tighter inline-flex items-center justify-center min-w-[60px] ${getSeloStyles(child.type)}`}>
                      {getLabel(child.type)}
                    </span>
                  )}
                </div>
              </div>
            );
          })
        ) : (
          <div className="col-span-full text-center py-20 text-gray-400 opacity-60">
            <i className="fa-solid fa-hands-holding-child text-5xl mb-4"></i>
            <p className="text-sm font-bold serif-font">Sua lista está vazia</p>
          </div>
        )}
      </div>

      {/* RODAPÉ INSTITUCIONAL COM LOGO EM DESTAQUE */}
      <div className="flex flex-col items-center justify-center pt-16 pb-20 opacity-80 animate-fadeIn">
        <div className="relative group mb-4">
          <div className="absolute inset-0 bg-brand-gc/5 blur-3xl rounded-full transition-all group-hover:bg-brand-gc/10"></div>
          <img 
            src={IMAGENS.logoGC} 
            alt="Logo Geração Compromisso Rodapé" 
            className="w-56 h-auto object-contain relative z-10 filter drop-shadow-xl transition-transform hover:scale-105" 
          />
        </div>
        <div className="flex flex-col items-center gap-1">
          <p className="text-[11px] font-black uppercase text-brand-gc tracking-[0.5em] italic drop-shadow-sm">Mães de joelhos, filhos de pé!</p>
          <div className="w-20 h-0.5 bg-gradient-to-r from-transparent via-brand-gc/30 to-transparent mt-4 rounded-full"></div>
        </div>
      </div>

      {/* Modal de Detalhes do Filho */}
      {selectedChild && !showHistory && (
        <div className="fixed inset-0 bg-black/70 z-[60] flex items-end sm:items-center justify-center p-0 sm:p-4 backdrop-blur-sm">
          <div className="bg-white w-full max-w-lg rounded-t-[3rem] sm:rounded-[3rem] p-6 animate-slideUp overflow-y-auto max-h-[95vh] no-scrollbar shadow-2xl">
            <div className="w-12 h-1.5 bg-gray-200 rounded-full mx-auto mb-6 sm:hidden"></div>

            <div className="flex justify-between items-start mb-8">
              <div className="flex items-center gap-4">
                <div className={`w-24 h-24 rounded-[2rem] overflow-hidden border-4 shadow-sm ${getSeloStyles(selectedChild.type)}`}>
                  <img src={selectedChild.photo || `https://picsum.photos/seed/${selectedChild.id}/200`} className="w-full h-full object-cover" alt={selectedChild.name} />
                </div>
                <div className="space-y-1.5">
                  <h3 className="text-xl font-bold text-brand-dark leading-tight">{selectedChild.name}</h3>
                  <div className={`px-4 py-1.5 rounded-full border text-[9px] font-black uppercase tracking-widest inline-flex items-center justify-center min-w-[70px] ${getSeloStyles(selectedChild.type)}`}>
                    {getLabel(selectedChild.type)}
                  </div>
                </div>
              </div>
              <div className="flex gap-2">
                <button onClick={handleOpenEdit} className="w-10 h-10 rounded-full bg-brand-soft text-brand-primary flex items-center justify-center active:scale-90 transition-transform shadow-sm"><i className="fa-solid fa-pen-to-square"></i></button>
                <button onClick={() => setSelectedChild(null)} className="w-10 h-10 rounded-full bg-gray-100 flex items-center justify-center active:bg-gray-200 transition-colors"><i className="fa-solid fa-xmark text-gray-500"></i></button>
              </div>
            </div>

            <div className="space-y-8">
              <div className="flex gap-3">
                <button onClick={() => setShowHistory(true)} className="flex-1 py-4 px-4 rounded-2xl bg-brand-lavender text-brand-rose text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-3 border border-brand-rose/20 shadow-md active:scale-95 transition-all">
                  <i className="fa-solid fa-clock-rotate-left text-sm"></i> Jornada Espiritual
                </button>
                {selectedChild.whatsapp && (
                   <button onClick={() => handleSendWhatsapp(selectedChild)} className="px-5 rounded-2xl bg-green-500 text-white flex items-center justify-center active:scale-95 transition-all shadow-md"><i className="fa-brands fa-whatsapp text-xl"></i></button>
                )}
              </div>

              <section>
                <div className="flex items-center justify-between mb-4 px-1">
                  <h4 className="text-[11px] font-black uppercase tracking-[0.2em] text-brand-primary flex items-center gap-2"><i className="fa-solid fa-heart-pulse"></i> Clamores Ativos</h4>
                  <button onClick={() => setShowAddRequestModal(true)} className="text-[10px] font-black uppercase px-4 py-1.5 rounded-full bg-brand-primary text-white shadow-lg active:scale-95 transition-all">+ Novo Clamor</button>
                </div>
                <div className="space-y-3">
                  {selectedChild.individualRequests.filter(r => r.status === 'em_oracao').length > 0 ? (
                    selectedChild.individualRequests.filter(r => r.status === 'em_oracao').map(req => (
                      <div key={req.id} className="p-4 rounded-2xl border border-brand-border/30 bg-brand-cream/40 space-y-2 shadow-sm">
                        <div className="flex justify-between items-start gap-4">
                          <span className="text-sm font-bold text-gray-800 leading-snug">{req.request}</span>
                          <button onClick={() => toggleRequestStatus(req.id)} className="text-[8px] font-black uppercase px-2 py-1 rounded-full bg-brand-soft text-brand-rose border border-brand-rose/10 whitespace-nowrap">Em Oração</button>
                        </div>
                        {req.verse && <p className="text-[11px] text-brand-primary/80 italic font-medium bg-white/60 p-2 rounded-lg"><i className="fa-solid fa-book-bible mr-1"></i> "{req.verse}"</p>}
                      </div>
                    ))
                  ) : (
                    <div className="text-center py-10 bg-gray-50 rounded-2xl border-2 border-dashed border-gray-100">
                      <p className="text-[11px] text-gray-400 font-black uppercase tracking-widest italic">Nenhum pedido ativo</p>
                    </div>
                  )}
                </div>
              </section>

              <button onClick={handlePrayerAction} className="w-full py-6 rounded-full gradient-brand text-white font-black uppercase tracking-widest shadow-2xl active:scale-[0.97] flex items-center justify-center gap-4 transition-all mb-4">
                <i className="fa-solid fa-hands-praying text-lg"></i> Interceder agora
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Modal de Jornada Espiritual (Histórico) */}
      {selectedChild && showHistory && (
        <div className="fixed inset-0 bg-black/80 z-[65] flex items-end sm:items-center justify-center p-0 sm:p-4">
          <div className="bg-brand-cream w-full max-w-lg rounded-t-[3rem] sm:rounded-[3rem] p-8 animate-slideUp overflow-y-auto max-h-[95vh] no-scrollbar shadow-2xl border-t-8 border-brand-gc">
            <div className="flex items-center justify-between mb-10">
              <button onClick={() => setShowHistory(false)} className="w-12 h-12 rounded-2xl bg-white flex items-center justify-center text-brand-rose shadow-md border border-brand-rose/10 active:scale-90 transition-transform">
                <i className="fa-solid fa-arrow-left"></i>
              </button>
              <div className="text-center">
                <h3 className="serif-font text-2xl font-black text-brand-dark">Jornada de Fé</h3>
                <div className="mt-2 flex items-center justify-center gap-2">
                  <img src={IMAGENS.logoGC} className="h-4 w-auto object-contain" alt="GC" />
                  <p className="text-[10px] font-black uppercase tracking-widest text-brand-gc/60">{selectedChild.name}</p>
                </div>
              </div>
              <div className="w-12 h-12"></div>
            </div>

            <div className="relative space-y-12 pl-6 before:absolute before:left-[1.75rem] before:top-4 before:bottom-4 before:w-1.5 before:bg-brand-gc/10 before:rounded-full">
              {historyLog.length > 0 ? historyLog.map((log) => {
                const isResolved = log.status === 'respondido';
                return (
                  <div key={log.id} className="relative pl-12 animate-fadeIn">
                    <div className={`absolute left-[-1.25rem] top-1.5 w-8 h-8 rounded-full border-4 border-brand-cream z-10 shadow-lg flex items-center justify-center transition-all ${isResolved ? 'bg-green-500 scale-110' : 'bg-brand-gc'}`}>
                      {isResolved && <i className="fa-solid fa-check text-white text-[11px]"></i>}
                    </div>
                    <div className="bg-white rounded-[2.5rem] p-7 border border-brand-gc/5 shadow-xl shadow-brand-gc/5 space-y-4 relative overflow-hidden group hover:scale-[1.02] transition-transform">
                      {isResolved && <div className="absolute top-0 right-0 w-32 h-32 bg-green-500/5 rounded-full -mr-16 -mt-16 flex items-end justify-start pb-8 pl-8 text-green-500 opacity-30"><i className="fa-solid fa-award text-5xl"></i></div>}

                      <div className="flex justify-between items-start">
                         <span className={`text-[9px] font-black uppercase tracking-[0.2em] px-4 py-1.5 rounded-full ${isResolved ? 'bg-green-50 text-green-600 border border-green-100' : 'bg-brand-soft text-brand-gc'}`}>
                           {isResolved ? 'Vitória Alcançada' : 'Semente de Clamor'}
                         </span>
                         <span className="text-[10px] text-gray-400 font-black">{new Date(log.createdAt).toLocaleDateString('pt-BR')}</span>
                      </div>

                      <p className="text-base font-bold text-brand-dark leading-snug">{log.request}</p>
                      {log.verse && <p className="text-xs text-brand-primary/80 italic bg-brand-soft/40 p-4 rounded-[1.5rem]"><i className="fa-solid fa-book-bible mr-2"></i> "{log.verse}"</p>}

                      {isResolved && log.resolvedAt && (
                        <div className="pt-5 border-t border-dashed border-gray-100 flex items-center justify-between">
                          <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Respondido em:</span>
                          <span className="text-xs font-black text-green-600">{new Date(log.resolvedAt).toLocaleDateString('pt-BR')}</span>
                        </div>
                      )}
                    </div>
                  </div>
                );
              }) : (
                <div className="text-center py-24 opacity-40">
                  <div className="w-20 h-20 bg-brand-soft rounded-[2rem] flex items-center justify-center mx-auto mb-6">
                    <i className="fa-solid fa-seedling text-4xl text-brand-gc"></i>
                  </div>
                  <p className="text-sm font-black uppercase tracking-widest text-brand-dark">Plante a primeira semente de oração.</p>
                </div>
              )}
            </div>

            <div className="mt-16 p-8 bg-white/60 rounded-[3rem] border border-white shadow-inner text-center space-y-4">
              <i className="fa-solid fa-quote-left text-brand-gc/20 text-5xl"></i>
              <p className="text-[15px] text-brand-dark/80 font-medium italic leading-relaxed">"O Senhor está longe dos ímpios, mas ouve a oração dos justos."</p>
              <p className="text-[10px] font-black text-brand-gc uppercase tracking-[0.4em]">— Provérbios 15:29</p>
            </div>
          </div>
        </div>
      )}

      {/* Modal Adicionar Clamor */}
      {showAddRequestModal && (
        <div className="fixed inset-0 bg-black/85 z-[70] flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white w-full max-w-sm rounded-[3rem] p-10 space-y-8 animate-fadeIn shadow-2xl">
            <div className="text-center space-y-3">
              <div className="w-16 h-16 bg-brand-soft rounded-[1.5rem] flex items-center justify-center mx-auto text-brand-primary">
                <i className="fa-solid fa-hands-praying text-3xl"></i>
              </div>
              <h3 className="serif-font text-3xl font-black text-brand-dark">Novo Clamor</h3>
              <p className="text-[10px] text-gray-400 uppercase font-black tracking-[0.2em]">Coloque no Altar</p>
            </div>
            <div className="space-y-5">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-brand-primary uppercase ml-4 tracking-widest">Qual o motivo?</label>
                <textarea placeholder="Ex: Proteção, faculdade, novos caminhos..." value={newReqText} onChange={(e) => setNewReqText(e.target.value)} className="w-full p-6 bg-gray-50 rounded-[2.5rem] border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary h-36 resize-none shadow-inner font-medium" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-brand-primary uppercase ml-4 tracking-widest">Base Bíblica (Opcional)</label>
                <input type="text" placeholder="Ex: Salmos 121" value={newReqVerse} onChange={(e) => setNewReqVerse(e.target.value)} className="w-full p-6 bg-gray-50 rounded-full border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner font-medium" />
              </div>
            </div>
            <div className="flex gap-4 pt-4">
              <button onClick={() => { setShowAddRequestModal(false); resetRequestForm(); }} className="flex-1 py-5 bg-gray-100 text-gray-500 rounded-full text-xs font-black uppercase tracking-widest active:scale-95 transition-all">Cancelar</button>
              <button onClick={handleAddRequest} className="flex-1 py-5 gradient-brand text-white rounded-full text-xs font-black uppercase tracking-widest shadow-xl active:scale-95 transition-all">Salvar</button>
            </div>
          </div>
        </div>
      )}

      {/* Modal Cadastro/Edição de Filho */}
      {(showAddModal || showEditModal) && (
        <div className="fixed inset-0 bg-black/85 z-[70] flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white w-full max-w-md rounded-[3.5rem] p-10 space-y-10 animate-fadeIn overflow-y-auto max-h-[95vh] no-scrollbar shadow-2xl">
            <div className="text-center space-y-3">
              <h3 className="serif-font text-3xl font-black text-brand-dark leading-none">{showEditModal ? 'Editar Filho' : 'Novo Filho'}</h3>
              <div className="flex items-center justify-center gap-3">
                <p className="text-[10px] text-gray-400 uppercase font-black tracking-[0.2em]">Cobertura</p>
                <img src={IMAGENS.logoGC} className="h-4 w-auto object-contain opacity-80" alt="Logo GC" />
              </div>
            </div>

            <div className="space-y-8">
              <div className="flex flex-col items-center gap-4">
                <div onClick={() => (showEditModal ? editFileInputRef : fileInputRef).current?.click()} className="w-36 h-36 rounded-[3rem] bg-brand-soft border-2 border-dashed border-brand-primary/30 flex flex-col items-center justify-center cursor-pointer overflow-hidden relative group shadow-inner">
                  {newPhoto ? (
                    <img src={newPhoto} alt="Preview" className="w-full h-full object-cover" />
                  ) : (
                    <div className="text-center px-6">
                      <i className="fa-solid fa-camera text-brand-primary text-4xl opacity-20 group-hover:scale-110 transition-transform mb-3"></i>
                      <p className="text-[10px] font-black text-brand-primary/40 uppercase tracking-widest leading-tight">Adicionar Foto</p>
                    </div>
                  )}
                  <div className="absolute inset-0 bg-brand-primary/10 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                    <i className="fa-solid fa-camera text-white text-2xl"></i>
                  </div>
                </div>
                <input type="file" ref={showEditModal ? editFileInputRef : fileInputRef} onChange={handlePhotoUpload} accept="image/*" className="hidden" />
              </div>

              <div className="space-y-6">
                <div className="space-y-2">
                  <label className="text-[11px] font-black text-brand-primary uppercase ml-5 tracking-widest">Nome Completo</label>
                  <input type="text" placeholder="Como ele se chama?" value={newName} onChange={(e) => setNewName(e.target.value)} className="w-full p-6 bg-gray-50 rounded-full border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner font-bold" />
                </div>

                <div className="space-y-2">
                  <label className="text-[11px] font-black text-brand-primary uppercase ml-5 tracking-widest">WhatsApp</label>
                  <input type="tel" placeholder="(00) 00000-0000" value={newWhatsapp} onChange={handleWhatsappChange} className="w-full p-6 bg-gray-50 rounded-full border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner font-bold" />
                </div>

                <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[11px] font-black text-brand-primary uppercase ml-5 tracking-widest">Vínculo</label>
                    <select value={newType} onChange={(e) => setNewType(e.target.value as any)} className="w-full p-6 bg-gray-50 rounded-full border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner appearance-none font-bold">
                      <option value="biologico">Biológico</option>
                      <option value="espiritual">Espiritual</option>
                      <option value="adotivo">Adotivo</option>
                      <option value="geracao_compromisso">Geração Compromisso</option>
                    </select>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[11px] font-black text-brand-primary uppercase ml-5 tracking-widest">Nascimento</label>
                    <input type="date" value={newBirthDate} onChange={(e) => setNewBirthDate(e.target.value)} className="w-full p-6 bg-gray-50 rounded-full border border-gray-100 text-sm focus:outline-none focus:ring-2 focus:ring-brand-primary shadow-inner font-bold" />
                  </div>
                </div>
              </div>
            </div>

            <div className="flex gap-4 pt-6">
              <button onClick={() => { setShowAddModal(false); setShowEditModal(false); resetChildForm(); }} className="flex-1 py-6 bg-gray-100 text-gray-500 rounded-full text-[11px] font-black uppercase tracking-widest active:scale-95 transition-all">Cancelar</button>
              <button onClick={showEditModal ? handleUpdateChild : handleSaveChild} className="flex-1 py-6 gradient-brand text-white rounded-full text-[11px] font-black uppercase tracking-widest shadow-2xl active:scale-95 transition-all">
                {showEditModal ? 'Atualizar' : 'Salvar'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default FilhosView;

import React, { useState, useRef, useMemo } from 'react';
import { ChildOfPrayer, ChildPrayerRequest } from '../types';
import { INSTITUTIONAL, IMAGENS } from '../constants';

interface FilhosProps {
  children: ChildOfPrayer[];
  setChildren: React.Dispatch<React.SetStateAction<ChildOfPrayer[]>>;
  pendingChildren?: ChildOfPrayer[];
  setPendingChildren?: React.Dispatch<React.SetStateAction<ChildOfPrayer[]>>;
}

const FilhosView: React.FC<FilhosProps> = ({ children, setChildren, pendingChildren = [], setPendingChildren }) => {
  const [showAddModal, setShowAddModal] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [showAddRequestModal, setShowAddRequestModal] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [selectedChild, setSelectedChild] = useState<ChildOfPrayer | null>(null);
  const [viewMode, setViewMode] = useState<'list' | 'card'>('list');

  // Form State for Child
  const [newName, setNewName] = useState('');
  const [newType, setNewType] = useState<ChildOfPrayer['type']>('biologico');
  const [newBirthDate, setNewBirthDate] = useState('');
  const [newLocation, setNewLocation] = useState('');
  const [newPhoto, setNewPhoto] = useState<string | undefined>(undefined);
  const [newWhatsapp, setNewWhatsapp] = useState('');
  const [whatsappError, setWhatsappError] = useState(false);

  // Form State for Request
  const [newReqText, setNewReqText] = useState('');
  const [newReqVerse, setNewReqVerse] = useState('');
  const [newReqStatus, setNewReqStatus] = useState<'em_oracao' | 'respondido'>('em_oracao');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const editFileInputRef = useRef<HTMLInputElement>(null);

  const formatPhoneNumber = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 11) {
      return numbers
        .replace(/^(\d{2})(\d)/g, '($1) $2')
        .replace(/(\d{5})(\d)/, '$1-$2');
    }
    return numbers.slice(0, 11)
      .replace(/^(\d{2})(\d)/g, '($1) $2')
      .replace(/(\d{5})(\d)/, '$1-$2');
  };

  const validateWhatsapp = (value: string) => {
    if (!value) return true; // Opcional, então se vazio é válido
    const regex = /^\(\d{2}\) \d{5}-\d{4}$/;
    return regex.test(value);
  };

  const handleWhatsappChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const formatted = formatPhoneNumber(e.target.value);
    setNewWhatsapp(formatted);
    if (formatted && !validateWhatsapp(formatted)) {
      setWhatsappError(true);
    } else {
      setWhatsappError(false);
    }
  };

  const calculateAge = (birthDate: string) => {
    if (!birthDate) return 0;
    const today = new Date();
    const birth = new Date(birthDate);
    let age = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) age--;
    return age;
  };

  const isStale = (child: ChildOfPrayer) => {
    const now = new Date();
    return child.individualRequests.some(req => {
      if (req.status !== 'em_oracao') return false;
      const created = new Date(req.createdAt);
      const diffDays = (now.getTime() - created.getTime()) / (1000 * 3600 * 24);
      return diffDays >= 3;
    });
  };

  const getSeloStyles = (type: string) => {
    switch (type) {
      case 'geracao_compromisso': return 'bg-brand-gc border-brand-gc text-white';
      case 'biologico': return 'bg-brand-primary/10 text-brand-primary border-brand-primary/20';
      case 'espiritual': return 'bg-brand-secondary/10 text-brand-secondary border-brand-secondary/20';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  const getLabel = (type: string) => {
    if (type === 'geracao_compromisso') {
      return (
        <div className="flex items-center justify-center">
          <img src={IMAGENS.logoGC} className="h-3 w-auto object-contain brightness-0 invert" alt="Logo GC" />
        </div>
      );
    }
    switch (type) {
      case 'biologico': return 'Biológico';
      case 'espiritual': return 'Espiritual';
      case 'adotivo': return 'Adotivo';
      default: return type;
    }
  };

  const handleAcceptPending = (pending: ChildOfPrayer) => {
    setChildren(prev => [pending, ...prev]);
    if (setPendingChildren) setPendingChildren(prev => prev.filter(p => p.id !== pending.id));
  };

  const handleDeclinePending = (id: string) => {
    if (setPendingChildren) setPendingChildren(prev => prev.filter(p => p.id !== id));
  };

  const handlePhotoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setNewPhoto(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleSaveChild = () => {
    if (!newName || !newBirthDate) return alert("Preencha nome e nascimento.");
    if (newWhatsapp && !validateWhatsapp(newWhatsapp)) {
      setWhatsappError(true);
      return alert("Por favor, insira um WhatsApp válido no formato (XX) XXXXX-XXXX.");
    }
    const newChild: ChildOfPrayer = {
      id: Date.now().toString(),
      name: newName,
      type: newType,
      birthDate: newBirthDate,
      location: newLocation || 'Não informada',
      photo: newPhoto,
      whatsapp: newWhatsapp,
      notes: '',
      startDate: new Date().toISOString(),
      prayerMinutes: 0,
      individualRequests: []
    };
    setChildren(prev => [newChild, ...prev]);
    resetChildForm();
    setShowAddModal(false);
  };

  const handleOpenEdit = () => {
    if (!selectedChild) return;
    setNewName(selectedChild.name);
    setNewType(selectedChild.type);
    setNewBirthDate(selectedChild.birthDate);
    setNewLocation(selectedChild.location);
    setNewPhoto(selectedChild.photo);
    const formattedPhone = selectedChild.whatsapp ? formatPhoneNumber(selectedChild.whatsapp) : '';
    setNewWhatsapp(formattedPhone);
    setWhatsappError(false);
    setShowEditModal(true);
  };

  const handleUpdateChild = () => {
    if (!selectedChild || !newName || !newBirthDate) return;
    if (newWhatsapp && !validateWhatsapp(newWhatsapp)) {
      setWhatsappError(true);
      return alert("Por favor, insira um WhatsApp válido no formato (XX) XXXXX-XXXX.");
    }
    const updatedChild: ChildOfPrayer = {
      ...selectedChild,
      name: newName,
      type: newType,
      birthDate: newBirthDate,
      location: newLocation,
      photo: newPhoto,
      whatsapp: newWhatsapp,
    };
    setChildren(prev => prev.map(c => c.id === selectedChild.id ? updatedChild : c));
    setSelectedChild(updatedChild);
    resetChildForm();
    setShowEditModal(false);
  };

  const handleAddRequest = () => {
    if (!selectedChild || !newReqText) return alert("Informe o motivo.");
    const newReq: ChildPrayerRequest = {
      id: Date.now().toString(),
      request: newReqText,
      verse: newReqVerse,
      status: newReqStatus,
      createdAt: new Date().toISOString(),
    };
    setChildren(prev => {
      return prev.map(child => {
        if (child.id === selectedChild.id) {
          const updatedChild = { ...child, individualRequests: [...child.individualRequests, newReq] };
          setSelectedChild(updatedChild);
          return updatedChild;
        }
        return child;
      });
    });
    resetRequestForm();
    setShowAddRequestModal(false);
  };

  const toggleRequestStatus = (requestId: string) => {
    if (!selectedChild) return;
    setChildren(prev => {
      return prev.map(child => {
        if (child.id === selectedChild.id) {
          const updatedRequests = child.individualRequests.map(req => {
            if (req.id === requestId) {
              const newStatus = req.status === 'em_oracao' ? 'respondido' : 'em_oracao';
              return { 
                ...req, 
                status: newStatus as any,
                resolvedAt: newStatus === 'respondido' ? new Date().toISOString() : undefined
              };
            }
            return req;
          });
          const updatedChild = { ...child, individualRequests: updatedRequests };
          setSelectedChild(updatedChild);
          return updatedChild;
        }
        return child;
      });
    });
  };

  const handlePrayerAction = () => {
    if (!selectedChild) return;
    setChildren(prev => {
      return prev.map(child => {
        if (child.id === selectedChild.id) {
          const updatedChild = { 
            ...child, 
            prayerMinutes: child.prayerMinutes + 1 
          };
          setSelectedChild(updatedChild);
          return updatedChild;
        }
        return child;
      });
    });
    alert(`Intercessão por ${selectedChild.name.split(' ')[0]} registrada no céu!`);
  };

  const handleSendWhatsapp = (child: ChildOfPrayer) => {
    if (!child.whatsapp) return alert("WhatsApp não cadastrado.");
    const cleanNumber = child.whatsapp.replace(/\D/g, '');
    const message = encodeURIComponent(`Olá, estou intercedendo por você agora mesmo através do App Desperta Débora! Creio no que Deus fará.`);
    window.open(`https://wa.me/55${cleanNumber}?text=${message}`, '_blank');
  };

  const resetChildForm = () => {
    setNewName(''); setNewType('biologico'); setNewBirthDate(''); setNewLocation(''); setNewPhoto(undefined); setNewWhatsapp(''); setWhatsappError(false);
  };

  const resetRequestForm = () => {
    setNewReqText(''); setNewReqVerse(''); setNewReqStatus('em_oracao');
  };

  const historyLog = useMemo(() => {
    if (!selectedChild) return [];
    return [...selectedChild.individualRequests].sort((a, b) => 
      new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
    );
  }, [selectedChild]);

  return (
    <div className="space-y-6 pb-20">
      {/* Header com Logomarca Visível */}
      <div className="flex items-center justify-between">
        <div className="flex flex-col">
          <h2 className="serif-font text-2xl font-bold text-brand-dark leading-tight">Filhos de Oração</h2>
          <div className="mt-2 flex items-center gap-2 h-7">
            <span className="text-[10px] font-black uppercase text-gray-400 tracking-[0.2em]">Pela</span>
            <img src={IMAGENS.logoGC} alt="Logo Geração Compromisso" className="h-full w-auto object-contain" />
          </div>
        </div>
        <div className="flex items-center gap-3">
          <div className="bg-brand-soft p-1 rounded-xl flex items-center border border-brand-border">
            <button onClick={() => setViewMode('list')} className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all ${viewMode === 'list' ? 'bg-white text-brand-primary shadow-sm' : 'text-gray-400'}`}>
              <i className="fa-solid fa-list-ul text-xs"></i>
            </button>
            <button onClick={() => setViewMode('card')} className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all ${viewMode === 'card' ? 'bg-white text-brand-primary shadow-sm' : 'text-gray-400'}`}>
              <i className="fa-solid fa-grip text-xs"></i>
            </button>
          </div>
          <button onClick={() => setShowAddModal(true)} className="bg-brand-gc text-white w-10 h-10 rounded-full flex items-center justify-center shadow-lg active:scale-90 transition-transform">
            <i className="fa-solid fa-plus"></i>
          </button>
        </div>
      </div>

      {pendingChildren.length > 0 && (
        <section className="space-y-3 animate-fadeIn">
          <div className="flex items-center gap-2 px-1">
            <span className="relative flex h-2 w-2">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-brand-gc opacity-75"></span>
              <span className="relative inline-flex rounded-full h-2 w-2 bg-brand-gc"></span>
            </span>
            <h3 className="text-[10px] font-black uppercase text-brand-gc tracking-[0.2em]">Novas Solicitações</h3>
          </div>
          <div className="space-y-3">
            {pendingChildren.map(pending => (
              <div key={pending.id} className="bg-white rounded-3xl p-4 border-2 border-brand-gc/20 shadow-lg shadow-brand-gc/5 flex flex-col gap-4">
                <div className="flex gap-4">
                  <div className="w-16 h-16 rounded-2xl overflow-hidden border border-brand-gc/30">
                    <img src={pending.photo} className="w-full h-full object-cover" alt={pending.name} />
                  </div>
                  <div className="flex-1">
                    <div className="flex justify-between items-center h-6">
                      <h4 className="font-black text-brand-dark">{pending.name}</h4>
                      <div className="bg-brand-gc px-3 py-1 rounded-full flex items-center justify-center">
                        <img src={IMAGENS.logoGC} className="h-3 w-auto object-contain brightness-0 invert" alt="GC" />
                      </div>
                    </div>
                    <p className="text-[10px] text-gray-500 mt-1 line-clamp-2 italic">"{pending.notes}"</p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button onClick={() => handleAcceptPending(pending)} className="flex-1 bg-brand-gc text-white py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest active:scale-[0.98]">Aceitar Cobertura</button>
                  <button onClick={() => handleDeclinePending(pending.id)} className="px-4 bg-gray-100 text-gray-400 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest active:scale-[0.98]">Ignorar</button>
                </div>
              </div>
            ))}
          </div>
        </section>
      )}

      {/* Caixa de Introdução - Logomarca VISÍVEL */}
      <div className="bg-brand-gc text-white p-6 rounded-[2.5rem] border border-white/20 relative overflow-hidden shadow-xl shadow-brand-gc/20">
        <div className="relative z-10 flex gap-5 items-center">
           <div className="w-16 h-16 bg-white/20 rounded-2xl flex items-center justify-center backdrop-blur-md flex-shrink-0 border border-white/10">
             <img src={IMAGENS.logoGC} className="w-12 h-12 object-contain brightness-0 invert" alt="Logo GC" />
           </div>
           <div>
             <div className="flex items-center gap-2 mb-1.5">
                <p className="text-[10px] font-black uppercase tracking-[0.2em] opacity-80">Geração</p>
                <img src={IMAGENS.logoGC} className="h-4 w-auto object-contain brightness-0 invert" alt="Compromisso" />
             </div>
             <p className="text-[13px] font-semibold leading-snug opacity-95">
                Cubra nossos jovens com o escudo da oração. Mães de joelhos, filhos de pé!
             </p>
           </div>
        </div>
        <div className="absolute -right-8 -bottom-8 w-32 h-32 bg-white/5 rounded-full blur-3xl"></div>
      </div>

      {/* Grid de Filhos */}
      <div className={viewMode === 'list' ? "grid grid-cols-1 gap-4" : "grid grid-cols-2 gap-4"}>
        {children.length > 0 ? (
          children.map(child => {
            const stale = isStale(child);
            return (
              <div 
                key={child.id} 
                onClick={() => setSelectedChild(child)} 
                className={`bg-white rounded-3xl p-4 border shadow-sm flex ${viewMode === 'list' ? 'gap-4' : 'flex-col gap-3 items-center text-center'} cursor-pointer hover:shadow-md transition-all active:scale-[0.99] relative ${stale ? 'border-orange-300 ring-1 ring-orange-100' : 'border-brand-border'}`}
              >
                {stale && <div className="absolute -top-1 -left-1 bg-orange-500 text-white text-[8px] font-black px-2 py-0.5 rounded-full z-10 shadow-sm animate-pulse">URGENTE</div>}
                <div className={`${viewMode === 'list' ? 'w-20 h-20' : 'w-full aspect-square'} rounded-2xl overflow-hidden flex-shrink-0 bg-brand-soft border border-brand-border`}>
                  <img src={child.photo || `https://picsum.photos/seed/${child.id}/200`} alt={child.name} className="w-full h-full object-cover" />
                </div>
                <div className="flex-1 w-full space-y-2">
                  <div className="flex justify-between items-start">
                    <h3 className="font-bold text-brand-dark line-clamp-1">{child.name}</h3>
                    {viewMode === 'list' && (
                      <span className={`text-[8px] uppercase font-black px-3 py-1.5 rounded-full border tracking-tighter flex items-center justify-center min-w-[60px] ${getSeloStyles(child.type)}`}>
                        {getLabel(child.type)}
                      </span>
                    )}
                  </div>
                  <div className="flex items-center gap-3 text-[11px] text-gray-500 font-medium">
                    <p><i className="fa-solid fa-cake-candles mr-1 opacity-60"></i> {calculateAge(child.birthDate)} anos</p>
                    <p><i className="fa-solid fa-clock mr-1 opacity-60"></i> {child.prayerMinutes}m</p>
