import React, { useState, useEffect } from 'react';
import { UserProfile, UserStats } from '../types';
import { INSTITUTIONAL } from '../constants';

interface ProfileProps {
  profile: UserProfile;
  stats: UserStats;
  setProfile?: React.Dispatch<React.SetStateAction<UserProfile>>;
}

const ProfileView: React.FC<ProfileProps> = ({ profile, stats, setProfile }) => {
  const [notifEnabled, setNotifEnabled] = useState(false);
  const [cpfInput, setCpfInput] = useState('');
  const [errorMsg, setErrorMsg] = useState('');

  useEffect(() => {
    if ("Notification" in window) {
      setNotifEnabled(Notification.permission === "granted");
    }
  }, []);

  const formatCPF = (value: string) => {
    return value
      .replace(/\D/g, '')
      .replace(/(\d{3})(\d)/, '$1.$2')
      .replace(/(\d{3})(\d)/, '$1.$2')
      .replace(/(\d{3})(\d{1,2})/, '$1-$2')
      .replace(/(-\d{2})\d+?$/, '$1');
  };

  const handleCpfChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setCpfInput(formatCPF(e.target.value));
    setErrorMsg('');
  };

  const handleConsultarCpf = () => {
    if (cpfInput === '123.456.789-00') {
      if (setProfile) {
        setProfile({
          name: "Ricardo Oliveira",
          photo: "https://picsum.photos/seed/ricardo/400",
          birthDate: "1980-01-15",
          church: "Ministério de Finanças Cristãs",
          participationTime: "5 anos",
          groupName: "Homens de Fé - Finanças"
        });
        setErrorMsg('');
        alert("Olá Ricardo Oliveira! Bem-vindo de volta. Vimos que você gosta de Finanças.");
      }
    } else {
      setErrorMsg("Cadastro não encontrado. Por favor, cadastre-se em nosso site.");
    }
  };

  const handleToggleNotifications = async () => {
    if (!("Notification" in window)) {
      alert("Seu navegador não suporta notificações.");
      return;
    }

    if (Notification.permission === "default") {
      const permission = await Notification.requestPermission();
      setNotifEnabled(permission === "granted");
    } else if (Notification.permission === "denied") {
      alert("As notificações estão bloqueadas nas configurações do seu navegador.");
    } else {
      setNotifEnabled(!notifEnabled);
    }
  };

  return (
    <div className="space-y-8 animate-fadeIn pb-24">
      {/* CPF Identification Section */}
      <div className="bg-white p-6 rounded-[2.5rem] border border-brand-border shadow-sm space-y-4">
        <div className="flex flex-col gap-1">
          <label className="text-[10px] font-black text-brand-rose uppercase tracking-widest ml-4">Identificação por CPF</label>
          <div className="flex gap-2">
            <input 
              type="tel" 
              placeholder="000.000.000-00"
              value={cpfInput}
              onChange={handleCpfChange}
              className="flex-1 bg-brand-soft border border-brand-border rounded-full px-6 py-3 text-sm font-bold focus:outline-none focus:ring-2 focus:ring-brand-rose/20"
            />
            <button 
              onClick={handleConsultarCpf}
              className="bg-brand-rose text-white px-6 rounded-full text-[10px] font-black uppercase tracking-widest active:scale-95 transition-transform"
            >
              Consultar
            </button>
          </div>
        </div>
        {errorMsg && (
          <div className="px-4 py-2 bg-red-50 border border-red-100 rounded-2xl">
            <p className="text-[11px] text-red-600 font-medium">{errorMsg}</p>
            <a 
              href="https://www.despertadebora.com.br" 
              target="_blank" 
              rel="noopener noreferrer"
              className="text-[10px] text-red-700 font-black uppercase underline mt-1 block"
            >
              Cadastrar no Site
            </a>
          </div>
        )}
      </div>

      {/* Profile Header */}
      <div className="flex flex-col items-center text-center space-y-4">
        <div className="relative">
          <div className="w-28 h-28 rounded-full border-4 border-brand-primary p-1 shadow-lg shadow-brand-primary/10">
            <img src={profile.photo || "https://picsum.photos/seed/profile/400"} className="w-full h-full object-cover rounded-full" alt="User" />
          </div>
          <button className="absolute bottom-0 right-0 w-8 h-8 bg-brand-primary text-white rounded-full flex items-center justify-center border-2 border-white shadow-md active:scale-90 transition-transform">
            <i className="fa-solid fa-camera text-xs"></i>
          </button>
        </div>
        <div>
          <h2 className="serif-font text-2xl font-bold text-brand-dark">{profile.name}</h2>
          <div className="flex flex-col gap-1">
            <p className="text-xs text-gray-500 font-medium">{profile.church}</p>
            {profile.name === "Ricardo Oliveira" && (
              <span className="bg-brand-gc text-white text-[9px] font-black px-3 py-1 rounded-full uppercase tracking-widest mx-auto mt-2">
                <i className="fa-solid fa-coins mr-1"></i> Especialista em Finanças
              </span>
            )}
          </div>
        </div>
      </div>

      {/* Profile Info Cards */}
      <div className="grid grid-cols-1 gap-3">
        <InfoRow icon="fa-clock" label="No ministério há" value={profile.participationTime} />
        <InfoRow icon="fa-users" label="Meu grupo" value={profile.groupName} />
        <InfoRow icon="fa-calendar" label="Nascimento" value={new Date(profile.birthDate).toLocaleDateString('pt-BR')} />
      </div>

      {/* App Stats Section */}
      <div className="bg-brand-soft rounded-3xl p-6 border border-brand-border shadow-inner">
        <h3 className="text-[10px] font-black uppercase text-brand-primary tracking-[0.2em] mb-4 flex items-center gap-2">
          <i className="fa-solid fa-chart-line"></i>
          Minha Jornada de Oração
        </h3>
        <div className="space-y-4">
          <StatProgress label="Dias consecutivos" value={stats.streak} max={30} unit="dias" color="bg-orange-500" />
          <StatProgress label="Minutos orados" value={stats.totalMinutes} max={1000} unit="min" color="bg-brand-primary" />
          <StatProgress label="Dias totais" value={stats.totalDays} max={365} unit="dias" color="bg-brand-secondary" />
        </div>
      </div>

      {/* Settings Options */}
      <div className="space-y-2">
        <SettingsButton 
          icon="fa-bell" 
          label="Lembretes de Intercessão" 
          toggle 
          active={notifEnabled}
          onClick={handleToggleNotifications}
        />
        <SettingsButton icon="fa-shield-halved" label="Privacidade" />
        <SettingsButton 
          icon="fa-circle-info" 
          label={`Sobre o ${INSTITUTIONAL.ministryName}`} 
          onClick={() => alert(INSTITUTIONAL.mission)}
        />
        <SettingsButton icon="fa-right-from-bracket" label="Sair da conta" color="text-red-600" />
      </div>

      {/* Institutional Footer */}
      <div className="flex flex-col items-center space-y-4 pt-4 px-6 text-center">
        <div className="w-16 h-16 opacity-40 grayscale hover:grayscale-0 hover:opacity-100 transition-all duration-300 cursor-pointer">
           <img src={INSTITUTIONAL.logoUrl} alt="Logo Footer" className="w-full h-full object-contain" />
        </div>

        <p className="text-[10px] text-gray-400 font-medium uppercase tracking-tight italic leading-relaxed">
          {INSTITUTIONAL.mpcCredit}
        </p>

        <p className="text-[10px] font-black uppercase tracking-[0.2em] text-brand-primary opacity-40">
          v1.1.0 • {INSTITUTIONAL.ministryName}
        </p>
      </div>
    </div>
  );
};

const InfoRow = ({ icon, label, value }: any) => (
  <div className="bg-white p-4 rounded-2xl border border-brand-border flex items-center gap-4 transition-transform active:scale-[0.99]">
    <div className="w-10 h-10 rounded-xl bg-brand-soft flex items-center justify-center text-brand-primary">
      <i className={`fa-solid ${icon}`}></i>
    </div>
    <div>
      <p className="text-[10px] text-gray-400 uppercase font-bold">{label}</p>
      <p className="text-sm font-bold text-brand-dark">{value}</p>
    </div>
  </div>
);

const StatProgress = ({ label, value, max, unit, color }: any) => (
  <div className="space-y-1.5">
    <div className="flex justify-between text-[10px] font-bold uppercase text-gray-500">
      <span>{label}</span>
      <span className="text-brand-primary">{value} {unit}</span>
    </div>
    <div className="h-2 w-full bg-white rounded-full overflow-hidden border border-brand-border/30 shadow-sm">
      <div className={`h-full ${color} rounded-full transition-all duration-1000`} style={{ width: `${Math.min((value/max)*100, 100)}%` }}></div>
    </div>
  </div>
);

const SettingsButton = ({ icon, label, toggle, active, onClick, color = "text-gray-700" }: any) => (
  <button 
    onClick={onClick}
    className="w-full bg-white p-4 rounded-2xl border border-brand-border flex items-center justify-between active:bg-brand-soft transition-all"
  >
    <div className="flex items-center gap-3">
      <i className={`fa-solid ${icon} ${color} w-5`}></i>
      <span className={`text-sm font-semibold ${color}`}>{label}</span>
    </div>
    {toggle ? (
      <div className={`w-10 h-5 rounded-full relative shadow-inner transition-colors ${active ? 'bg-brand-primary' : 'bg-gray-200'}`}>
        <div className={`absolute top-1 w-3 h-3 bg-white rounded-full shadow-sm transition-all ${active ? 'right-1' : 'left-1'}`}></div>
      </div>
    ) : (
      <i className="fa-solid fa-chevron-right text-gray-300 text-xs"></i>
    )}
  </button>
);

export default ProfileView;

