// Responsabilidade: Lógica de formatação e cálculos matemáticos puros
// Inputs: Strings brutas ou Datas | Outputs: Strings formatadas ou Cálculos

export const formatPhone = (value: string) => {
  const numbers = value.replace(/\D/g, '');
  return numbers.length <= 11 
    ? numbers.replace(/^(\d{2})(\d)/g, '($1) $2').replace(/(\d{5})(\d)/, '$1-$2')
    : numbers.slice(0, 11).replace(/^(\d{2})(\d)/g, '($1) $2').replace(/(\d{5})(\d)/, '$1-$2');
};

export const formatCPF = (value: string) => {
  return value.replace(/\D/g, '').replace(/(\d{3})(\d)/, '$1.$2').replace(/(\d{3})(\d)/, '$1.$2').replace(/(\d{3})(\d{1,2})/, '$1-$2').replace(/(-\d{2})\d+?$/, '$1');
};

export const calculateAge = (birthDate: string) => {
  if (!birthDate) return 0;
  const today = new Date();
  const birth = new Date(birthDate);
  let age = today.getFullYear() - birth.getFullYear();
  const m = today.getMonth() - birth.getMonth();
  if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) age--;
  return age;
};

export const validateWhatsapp = (value: string) => {
  return /^\(\d{2}\) \d{5}-\d{4}$/.test(value);
};

