  const [prayers, setPrayers] = useState<PrayerRequest[]>(INITIAL_PRAYER_REQUESTS);
  const [profile, setProfile] = useState<UserProfile>({
    name: "Ana Cláudia",
    birthDate: "1985-05-20",
    church: "Igreja Batista Aliança",
    participationTime: "2 anos",
    groupName: "Déboras de Curitiba"
  });

  useEffect(() => {
    // Splash Screen temporizado para experiência de marca
    const timer = setTimeout(() => setIsLoading(false), 2000);
    return () => clearTimeout(timer);
  }, []);

  // Verifica se há pendências para notificar na aba
  const hasPendingChildren = children.some(c => c.status === 'pending_review');

  if (isLoading) return <SplashScreen />;

  const views: Record<string, React.ReactNode> = {
    home: <HomeView stats={stats} prayers={prayers} onNavigate={setActiveTab} />,
    prayers: <PrayersView prayers={prayers} setPrayers={setPrayers} />,
    filhos: <FilhosView children={children} setChildren={setChildren} />,
    community: <CommunityView />,
    timer: <TimerView stats={stats} setStats={setStats} onFinish={() => setActiveTab('home')} />,
    profile: <ProfileView profile={profile} stats={stats} setProfile={setProfile} />
  };

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab} hasPending={hasPendingChildren}>
      {views[activeTab]}
    </Layout>
  );
};

const SplashScreen = () => (
  <div className="fixed inset-0 bg-brand-lavender flex flex-col items-center justify-center z-[100] animate-fadeIn">
    <img src={INSTITUTIONAL.logoUrl} alt="Logo" className="w-48 mb-8 animate-pulse" />
    <p className="text-brand-rose text-[10px] font-black uppercase tracking-[0.4em]">Preparando o Altar...</p>
  </div>
);

export default App;

// Responsabilidade: Gestão da lista de filhos e clamores individuais.
// Inputs: children, setChildren | Outputs: UI de intercessão por filhos.

import React, { useState, useRef } from 'react';
import { ChildOfPrayer, ChildPrayerRequest } from '../types';
import { IMAGENS } from '../constants';
import { BaseModal, ActionButton, InstitutionalFooter } from '../components/UI';
import { calculateAge, formatPhone, validateWhatsapp, getStaleStatus } from '../utils/helpers';

interface FilhosProps {
  children: ChildOfPrayer[];
  setChildren: React.Dispatch<React.SetStateAction<ChildOfPrayer[]>>;
}

const FilhosView: React.FC<FilhosProps> = ({ children, setChildren }) => {
