      </header>

      <div className="grid grid-cols-1 gap-4">
        {children.map(child => {
          const isPending = child.status === 'pending_review';
          return (
            <div 
              key={child.id} 
              onClick={() => setSelectedChild(child)} 
              className={`bg-white rounded-3xl p-4 border shadow-sm flex gap-4 cursor-pointer relative transition-all ${isPending ? 'border-brand-accent bg-brand-cream ring-2 ring-brand-accent/20' : (getStaleStatus(child.individualRequests) ? 'border-orange-300' : 'border-brand-border')}`}
            >
              {isPending && (
                <div className="absolute -top-2 -right-2 bg-brand-accent text-white text-[8px] font-black uppercase px-3 py-1 rounded-full shadow-md animate-bounce">
                  Novo • Revisar
                </div>
              )}
              <img src={child.photo || `https://picsum.photos/seed/${child.id}/200`} className={`w-16 h-16 rounded-2xl object-cover border ${isPending ? 'grayscale' : ''}`} />
              <div className="flex-1">
                <div className="flex justify-between items-start">
                  <h3 className="font-bold text-brand-dark">{child.name}</h3>
                  <span className={`text-[8px] font-black uppercase px-3 py-1 rounded-full border ${getSeloStyles(child.type)}`}>{child.type}</span>
                </div>
                <p className="text-[11px] text-gray-500 mt-1">
                  {isPending ? 'Importado do Site • Aguardando aceite' : `${calculateAge(child.birthDate)} anos • ${child.prayerMinutes}m orados`}
                </p>
              </div>
            </div>
          );
        })}
      </div>

      <InstitutionalFooter />

      {/* Modal Adicionar Filho */}
      <BaseModal isOpen={modals.add} onClose={() => toggleModal('add', false)} title="Novo Filho" subtitle="Cadastrar para Intercessão">
        <div className="space-y-4">
          <input type="text" placeholder="Nome" className="w-full p-4 bg-gray-50 rounded-2xl border" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
          <div className="grid grid-cols-2 gap-3">
            <select className="p-4 bg-gray-50 rounded-2xl border text-sm" value={formData.type} onChange={e => setFormData({...formData, type: e.target.value as any})}>
              <option value="biologico">Biológico</option>
              <option value="espiritual">Espiritual</option>
              <option value="adotivo">Adotivo</option>
            </select>
            <input type="date" className="p-4 bg-gray-50 rounded-2xl border text-sm" value={formData.birthDate} onChange={e => setFormData({...formData, birthDate: e.target.value})} />
          </div>
          <ActionButton label="Salvar Cadastro" onClick={handleSaveChild} fullWidth />
        </div>
      </BaseModal>

      {/* Modal Detalhes Dinâmico */}
      {selectedChild && (
        <BaseModal isOpen={!!selectedChild} onClose={() => setSelectedChild(null)} title={selectedChild.name} subtitle={selectedChild.status === 'pending_review' ? 'Revisão Necessária' : selectedChild.type}>
          <div className="space-y-6 text-center">
            <img src={selectedChild.photo || `https://picsum.photos/seed/${selectedChild.id}/200`} className="w-24 h-24 rounded-3xl mx-auto object-cover border-4 border-brand-soft" />

            {selectedChild.status === 'pending_review' ? (
              <div className="space-y-4 animate-fadeIn">
                <div className="bg-brand-cream p-4 rounded-2xl border border-brand-accent/50 text-xs text-left">
                  <p className="font-bold text-brand-dark mb-1"><i className="fa-solid fa-circle-info text-brand-accent mr-2"></i>Origem: Site Desperta Débora</p>
                  <p className="text-gray-600">Este cadastro foi importado automaticamente. Por favor, verifique os dados antes de iniciar a intercessão.</p>
                </div>
                <ActionButton label="Aceitar Cadastro" onClick={handleAcceptChild} variant="primary" icon="fa-check" fullWidth className="bg-green-600 border-none shadow-green-200" />
                <button onClick={() => setSelectedChild(null)} className="text-[10px] text-gray-400 font-bold uppercase tracking-widest hover:text-red-400">Rejeitar/Excluir</button>
              </div>
            ) : (
              <>
                <div className="grid grid-cols-2 gap-3">
                  <ActionButton label="Clamores" onClick={() => {}} variant="outline" icon="fa-hands-praying" />
                  <ActionButton label="WhatsApp" onClick={() => window.open(`https://wa.me/${selectedChild.whatsapp?.replace(/\D/g,'')}`)} variant="outline" icon="fa-whatsapp" />
                </div>
                <ActionButton label="Registrar 1m de Oração" onClick={() => {
                  setChildren(prev => prev.map(c => c.id === selectedChild.id ? {...c, prayerMinutes: c.prayerMinutes + 1} : c));
                  setSelectedChild(prev => prev ? {...prev, prayerMinutes: prev.prayerMinutes + 1} : null);
                }} fullWidth />
              </>
            )}
          </div>
        </BaseModal>
      )}
    </div>
  );
};

export default FilhosView;

// Responsabilidade: Gestão da lista de filhos e clamores individuais.
// Inputs: children, setChildren | Outputs: UI de intercessão por filhos.

import React, { useState } from 'react';
import { ChildOfPrayer, ChildPrayerRequest } from '../types';
import { BaseModal, ActionButton, InstitutionalFooter } from '../components/UI';
import { calculateAge, getStaleStatus } from '../utils/helpers';

interface FilhosProps {
  children: ChildOfPrayer[];
  setChildren: React.Dispatch<React.SetStateAction<ChildOfPrayer[]>>;
}

const FilhosView: React.FC<FilhosProps> = ({ children, setChildren }) => {
  const [modals, setModals] = useState({ add: false });
  const [selectedChild, setSelectedChild] = useState<ChildOfPrayer | null>(null);
  const [viewMode, setViewMode] = useState<'details' | 'requests'>('details');
  const [formData, setFormData] = useState({ name: '', type: 'biologico' as any, birthDate: '', photo: undefined as any, whatsapp: '' });

  // State for Requests
  const [reqData, setReqData] = useState({ text: '', verse: '', notes: '' });
  const [isAddingRequest, setIsAddingRequest] = useState(false);

  const toggleModal = (key: keyof typeof modals, val: boolean) => setModals(prev => ({ ...prev, [key]: val }));

  const handleSaveChild = () => {
    if (!formData.name || !formData.birthDate) return alert("Nome e nascimento obrigatórios.");
    const newChild: ChildOfPrayer = {
      id: Date.now().toString(),
      ...formData,
      location: 'Não informada',
      notes: '',
      startDate: new Date().toISOString(),
      prayerMinutes: 0,
      individualRequests: [],
      status: 'active'
    };
    setChildren(prev => [newChild, ...prev]);
    toggleModal('add', false);
    setFormData({ name: '', type: 'biologico', birthDate: '', photo: undefined, whatsapp: '' });
  };

  const handleAcceptChild = () => {
    if (!selectedChild) return;
    setChildren(prev => prev.map(c => c.id === selectedChild.id ? { ...c, status: 'active' } : c));
    setSelectedChild(prev => prev ? { ...prev, status: 'active' } : null);
    alert("Cadastro confirmado! Agora você pode adicionar pedidos de oração.");
  };

  const handleSaveRequest = () => {
    if (!selectedChild || !reqData.text.trim()) return alert("Por favor, descreva o pedido.");

    const newRequest: ChildPrayerRequest = {
      id: Date.now().toString(),
      request: reqData.text,
      verse: reqData.verse,
      status: 'em_oracao',
      createdAt: new Date().toISOString(),
      notes: reqData.notes
    };

    const updateFn = (child: ChildOfPrayer) => ({
      ...child,
      individualRequests: [newRequest, ...child.individualRequests]
    });

    setChildren(prev => prev.map(c => c.id === selectedChild.id ? updateFn(c) : c));
    setSelectedChild(prev => prev ? updateFn(prev) : null);

    setReqData({ text: '', verse: '', notes: '' });
    setIsAddingRequest(false);
  };

  const handleToggleStatus = (reqId: string) => {
    if (!selectedChild) return;

    const toggleFn = (reqs: ChildPrayerRequest[]) => reqs.map(r => {
      if (r.id === reqId) {
        const newStatus = r.status === 'em_oracao' ? 'respondido' : 'em_oracao';
        return { 
          ...r, 
          status: newStatus, 
          resolvedAt: newStatus === 'respondido' ? new Date().toISOString() : undefined 
        } as ChildPrayerRequest;
      }
      return r;
    });

    const updateChild = (child: ChildOfPrayer) => ({
      ...child,
      individualRequests: toggleFn(child.individualRequests)
    });

    setChildren(prev => prev.map(c => c.id === selectedChild.id ? updateChild(c) : c));
    setSelectedChild(prev => prev ? updateChild(prev) : null);
  };

  const getSeloStyles = (type: string) => {
    if (type === 'geracao_compromisso') return 'bg-brand-gc text-white border-brand-gc';
    const mapping: any = { biologico: 'bg-brand-soft text-brand-primary', espiritual: 'bg-brand-lavender text-brand-gc', adotivo: 'bg-brand-pink text-brand-rose' };
    return `${mapping[type] || 'bg-gray-100'} border-transparent`;
  };

  const openChildDetails = (child: ChildOfPrayer) => {
    setSelectedChild(child);
    setViewMode('details');
    setIsAddingRequest(false);
  };

  return (
    <div className="space-y-6 pb-20 animate-fadeIn">
      <header className="flex items-center justify-between">
        <div>
          <h2 className="serif-font text-2xl font-bold text-brand-dark">Filhos de Oração</h2>
          <p className="text-[10px] font-black uppercase text-brand-gc tracking-[0.2em] mt-1">Cobertura Geração Compromisso</p>
        </div>
        <button onClick={() => toggleModal('add', true)} className="bg-brand-gc text-white w-10 h-10 rounded-full shadow-lg active:scale-90"><i className="fa-solid fa-plus"></i></button>
      </header>

      <div className="grid grid-cols-1 gap-4">
        {children.map(child => {
          const isPending = child.status === 'pending_review';
          return (
            <div 
              key={child.id} 
              onClick={() => openChildDetails(child)} 
              className={`bg-white rounded-3xl p-4 border shadow-sm flex gap-4 cursor-pointer relative transition-all ${isPending ? 'border-brand-accent bg-brand-cream ring-2 ring-brand-accent/20' : (getStaleStatus(child.individualRequests) ? 'border-orange-300' : 'border-brand-border')}`}
            >
              {isPending && (
                <div className="absolute -top-2 -right-2 bg-brand-accent text-white text-[8px] font-black uppercase px-3 py-1 rounded-full shadow-md animate-bounce">
                  Novo • Revisar
                </div>
              )}
              <img src={child.photo || `https://picsum.photos/seed/${child.id}/200`} className={`w-16 h-16 rounded-2xl object-cover border ${isPending ? 'grayscale' : ''}`} alt={child.name} />
              <div className="flex-1">
                <div className="flex justify-between items-start">
                  <h3 className="font-bold text-brand-dark">{child.name}</h3>
                  <span className={`text-[8px] font-black uppercase px-3 py-1 rounded-full border ${getSeloStyles(child.type)}`}>{child.type}</span>
                </div>
                <p className="text-[11px] text-gray-500 mt-1">
                  {isPending ? 'Importado do Site • Aguardando aceite' : `${calculateAge(child.birthDate)} anos • ${child.prayerMinutes}m orados`}
                </p>
              </div>
            </div>
          );
        })}
      </div>

      <InstitutionalFooter />

      {/* Modal Adicionar Filho */}
      <BaseModal isOpen={modals.add} onClose={() => toggleModal('add', false)} title="Novo Filho" subtitle="Cadastrar para Intercessão">
        <div className="space-y-4">
          <input type="text" placeholder="Nome" className="w-full p-4 bg-gray-50 rounded-2xl border" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
          <div className="grid grid-cols-2 gap-3">
            <select className="p-4 bg-gray-50 rounded-2xl border text-sm" value={formData.type} onChange={e => setFormData({...formData, type: e.target.value as any})}>
              <option value="biologico">Biológico</option>
              <option value="espiritual">Espiritual</option>
              <option value="adotivo">Adotivo</option>
            </select>
            <input type="date" className="p-4 bg-gray-50 rounded-2xl border text-sm" value={formData.birthDate} onChange={e => setFormData({...formData, birthDate: e.target.value})} />
          </div>
          <ActionButton label="Salvar Cadastro" onClick={handleSaveChild} fullWidth />
        </div>
      </BaseModal>

      {/* Modal Detalhes / Pedidos */}
      {selectedChild && (
        <BaseModal 
          isOpen={!!selectedChild} 
          onClose={() => setSelectedChild(null)} 
          title={viewMode === 'requests' ? 'Pedidos de Oração' : selectedChild.name} 
          subtitle={viewMode === 'requests' ? `Intercedendo por ${selectedChild.name}` : (selectedChild.status === 'pending_review' ? 'Revisão Necessária' : selectedChild.type)}
        >
          {viewMode === 'details' ? (
            // VIEW: DETALHES DO FILHO
            <div className="space-y-6 text-center animate-fadeIn">
              <img src={selectedChild.photo || `https://picsum.photos/seed/${selectedChild.id}/200`} className="w-24 h-24 rounded-3xl mx-auto object-cover border-4 border-brand-soft" alt="Child" />

              {selectedChild.status === 'pending_review' ? (
                <div className="space-y-4">
                  <div className="bg-brand-cream p-4 rounded-2xl border border-brand-accent/50 text-xs text-left">
                    <p className="font-bold text-brand-dark mb-1"><i className="fa-solid fa-circle-info text-brand-accent mr-2"></i>Origem: Site Desperta Débora</p>
                    <p className="text-gray-600">Este cadastro foi importado automaticamente. Por favor, verifique os dados antes de iniciar a intercessão.</p>
                  </div>
                  <ActionButton label="Aceitar Cadastro" onClick={handleAcceptChild} variant="primary" icon="fa-check" fullWidth className="bg-green-600 border-none shadow-green-200" />
                  <button onClick={() => setSelectedChild(null)} className="text-[10px] text-gray-400 font-bold uppercase tracking-widest hover:text-red-400">Rejeitar/Excluir</button>
                </div>
              ) : (
                <>
                  <div className="grid grid-cols-2 gap-3">
                    <ActionButton label="Clamores" onClick={() => setViewMode('requests')} variant="outline" icon="fa-hands-praying" />
                    <ActionButton label="WhatsApp" onClick={() => window.open(`https://wa.me/${selectedChild.whatsapp?.replace(/\D/g,'')}`)} variant="outline" icon="fa-whatsapp" />
                  </div>
                  <ActionButton label="Registrar 1m de Oração" onClick={() => {
                    setChildren(prev => prev.map(c => c.id === selectedChild.id ? {...c, prayerMinutes: c.prayerMinutes + 1} : c));
                    setSelectedChild(prev => prev ? {...prev, prayerMinutes: prev.prayerMinutes + 1} : null);
                  }} fullWidth />
                </>
              )}
            </div>
          ) : (
            // VIEW: PEDIDOS DE ORAÇÃO
            <div className="space-y-4 animate-fadeIn h-[50vh] flex flex-col">
              {!isAddingRequest ? (
                <>
                  <div className="flex-1 overflow-y-auto no-scrollbar space-y-3">
                    {selectedChild.individualRequests.length === 0 ? (
                      <div className="text-center py-10 opacity-50">
                        <i className="fa-solid fa-scroll text-3xl mb-2 text-brand-border"></i>
                        <p className="text-xs font-bold text-gray-400">Nenhum pedido registrado.</p>
                      </div>
                    ) : (
                      selectedChild.individualRequests.map(req => (
                        <div key={req.id} className={`p-4 rounded-2xl border transition-all ${req.status === 'respondido' ? 'bg-green-50 border-green-200' : 'bg-white border-brand-border'}`}>
                          <div className="flex justify-between items-start mb-2">
                            <span 
                              onClick={() => handleToggleStatus(req.id)}
                              className={`text-[9px] font-black uppercase px-2 py-1 rounded-full cursor-pointer select-none ${req.status === 'respondido' ? 'bg-green-200 text-green-700' : 'bg-brand-soft text-brand-primary'}`}
                            >
                              {req.status === 'respondido' ? 'Respondido' : 'Em Oração'}
                            </span>
                            <span className="text-[9px] text-gray-400">{new Date(req.createdAt).toLocaleDateString()}</span>
                          </div>
                          <p className={`text-sm font-bold text-brand-dark mb-1 ${req.status === 'respondido' ? 'line-through opacity-60' : ''}`}>{req.request}</p>
                          {req.verse && <p className="text-[10px] text-gray-500 italic">"{req.verse}"</p>}
                        </div>
                      ))
                    )}
                  </div>
                  <div className="pt-2 flex flex-col gap-2">
                    <ActionButton label="Novo Pedido" onClick={() => setIsAddingRequest(true)} fullWidth icon="fa-plus" />
                    <button onClick={() => setViewMode('details')} className="w-full py-3 text-[10px] font-black text-gray-400 uppercase tracking-widest">Voltar</button>
                  </div>
                </>
              ) : (
                // FORMULÁRIO DE NOVO PEDIDO
                <div className="space-y-4 flex flex-col h-full">
                  <div className="flex-1 space-y-3">
                    <textarea 
                      placeholder="Descreva o motivo de oração..." 
                      className="w-full p-4 bg-gray-50 rounded-2xl border text-sm h-32 resize-none focus:ring-2 focus:ring-brand-primary/20 outline-none"
                      value={reqData.text}
                      onChange={e => setReqData({...reqData, text: e.target.value})}
                    />
                    <input 
                      type="text" 
                      placeholder="Versículo chave (opcional)" 
                      className="w-full p-4 bg-gray-50 rounded-2xl border text-sm outline-none"
                      value={reqData.verse}
                      onChange={e => setReqData({...reqData, verse: e.target.value})}
                    />
                  </div>
                  <div className="flex gap-2">
                     <button onClick={() => setIsAddingRequest(false)} className="flex-1 py-4 bg-gray-100 rounded-full text-[10px] font-black text-gray-500 uppercase">Cancelar</button>
                     <ActionButton label="Salvar" onClick={handleSaveRequest} className="flex-[2]" />
                  </div>
                </div>
              )}
            </div>
          )}
        </BaseModal>
      )}
    </div>
  );
};

export default FilhosView;

